#[derive(Debug, Clone, Copy, PartialEq)]
struct DesktopMenuChromeLayout {
    is_mobile: bool,
    left_gutter: Option<RenderRect>,
    right_gutter: Option<RenderRect>,
    bottom_gutter: Option<RenderRect>,
    discord_rect: RenderRect,
    terminal_rect: Option<RenderRect>,
    info_rect: Option<RenderRect>,
    becheck_rect: Option<RenderRect>,
}

impl DesktopMenuChromeLayout {
    fn for_viewport(viewport: RenderViewport) -> Self {
        let width = viewport.width.max(1.0);
        let height = viewport.height.max(1.0);
        let is_mobile = width <= 720.0 || height > width * 1.2;
        let right_margin = 10.0;
        let bottom_margin = 9.0;

        let left_gutter =
            is_mobile.then_some(RenderRect::new(viewport.x, viewport.y, 14.0, height));
        let right_gutter = is_mobile.then_some(RenderRect::new(
            viewport.x + width - 14.0,
            viewport.y,
            14.0,
            height,
        ));
        let bottom_gutter = is_mobile.then_some(RenderRect::new(
            viewport.x + 14.0,
            viewport.y + height - 12.0,
            (width - 28.0).max(1.0),
            12.0,
        ));

        let discord_rect = RenderRect::new(
            viewport.x + width - right_margin - 84.0,
            viewport.y + height - bottom_margin - 45.0,
            84.0,
            45.0,
        );
        let terminal_rect = is_mobile.then_some(RenderRect::new(
            viewport.x + 6.0,
            viewport.y + height - bottom_margin - 60.0,
            60.0,
            60.0,
        ));
        let info_rect = terminal_rect.map(|terminal_rect| {
            RenderRect::new(
                terminal_rect.x + terminal_rect.width + 8.0,
                viewport.y + height - bottom_margin - 45.0,
                84.0,
                45.0,
            )
        });
        let becheck_rect = if is_mobile {
            None
        } else {
            Some(RenderRect::new(
                viewport.x + width - right_margin - 200.0,
                discord_rect.y - 8.0 - 60.0,
                200.0,
                60.0,
            ))
        };

        Self {
            is_mobile,
            left_gutter,
            right_gutter,
            bottom_gutter,
            discord_rect,
            terminal_rect,
            info_rect,
            becheck_rect,
        }
    }

    fn action_at_point(self, point: RenderPoint) -> Option<DesktopMenuChromeAction> {
        if self.discord_rect.contains_point(point) {
            return Some(DesktopMenuChromeAction::Discord);
        }
        if let Some(rect) = self.terminal_rect {
            if rect.contains_point(point) {
                return Some(DesktopMenuChromeAction::MobileTerminalToggle);
            }
        }
        if let Some(rect) = self.info_rect {
            if rect.contains_point(point) {
                return Some(DesktopMenuChromeAction::InfoOpenAbout);
            }
        }
        if let Some(rect) = self.becheck_rect {
            if rect.contains_point(point) {
                return Some(DesktopMenuChromeAction::Becheck);
            }
        }
        None
    }
}

#[derive(Debug, Clone, PartialEq)]
pub struct DesktopStandardEffectRenderFrame {
    pub draw_plans: Vec<StandardEffectDrawPlan>,
    pub circle_primitives: Vec<StandardEffectCircleRenderPrimitive>,
    pub square_primitives: Vec<StandardEffectSquareRenderPrimitive>,
    pub rect_primitives: Vec<StandardEffectRectRenderPrimitive>,
    pub line_primitives: Vec<StandardEffectLineRenderPrimitive>,
    pub triangle_primitives: Vec<StandardEffectTriangleRenderPrimitive>,
    pub light_primitives: Vec<StandardEffectLightRenderPrimitive>,
    pub block_full_icon_regions: BTreeMap<ContentId, String>,
}

fn desktop_effect_render_color(color: Option<DecalColor>, alpha: f32) -> [f32; 4] {
    let color = color.unwrap_or(DecalColor::WHITE);
    [color.r, color.g, color.b, color.a * alpha]
}

fn desktop_light_render_color(light: LightPrimitive) -> [f32; 4] {
    [
        light.color.r,
        light.color.g,
        light.color.b,
        light.color.a * light.opacity,
    ]
}

fn desktop_resolve_color_symbol(name: &str) -> Option<DecalColor> {
    if name.is_empty() {
        return None;
    }

    if let Some((base, alpha)) = name.rsplit_once('@') {
        if let Ok(alpha) = alpha.parse::<f32>() {
            let mut color = desktop_resolve_color_symbol(base)?;
            color.a *= alpha.clamp(0.0, 1.0);
            return Some(color);
        }
    }

    if let Some((base, scale)) = name.rsplit_once('*') {
        if let Ok(scale) = scale.parse::<f32>() {
            let mut color = desktop_resolve_color_symbol(base)?;
            color.r = (color.r * scale).clamp(0.0, 1.0);
            color.g = (color.g * scale).clamp(0.0, 1.0);
            color.b = (color.b * scale).clamp(0.0, 1.0);
            color.a = (color.a * scale).clamp(0.0, 1.0);
            return Some(color);
        }
    }

    let hex = name.strip_prefix('#').unwrap_or(name);
    if hex.len() == 6 || hex.len() == 8 {
        if let Ok(mut rgba) = u32::from_str_radix(hex, 16) {
            if hex.len() == 6 {
                rgba = (rgba << 8) | 0xff;
            }
            return Some(DecalColor::from_rgba(rgba));
        }
    }

    standard_effect_color_symbol(name)
        .or_else(|| Pal::by_name(name))
        .or_else(|| standard_effect_color_symbol(&format!("Pal.{name}")))
        .or_else(|| standard_effect_color_symbol(&format!("Color.{name}")))
}

fn desktop_bullet_render_color(name: &str, fallback: DecalColor) -> [f32; 4] {
    let color = desktop_resolve_color_symbol(name).unwrap_or(fallback);
    desktop_effect_render_color(Some(color), 1.0)
}

fn desktop_curve(value: f32, from: f32, to: f32) -> f32 {
    if (to - from).abs() <= f32::EPSILON {
        return if value >= to { 1.0 } else { 0.0 };
    }
    ((value - from) / (to - from)).clamp(0.0, 1.0)
}

fn desktop_bullet_fin_fout(bullet: &BulletComp) -> (f32, f32) {
    let fin = if bullet.lifetime > f32::EPSILON {
        (bullet.time / bullet.lifetime).clamp(0.0, 1.0)
    } else {
        0.0
    };
    (fin, 1.0 - fin)
}

fn desktop_laser_bullet_colors(spec: &BulletSpec) -> Vec<String> {
    if !spec.colors.is_empty() {
        spec.colors.clone()
    } else if !spec.front_color.is_empty() {
        vec![spec.front_color.clone()]
    } else {
        vec![
            "lancerLaser@0.4".into(),
            "lancerLaser".into(),
            "white".into(),
        ]
    }
}

fn laser_bullet_base_length(bullet: &BulletComp) -> (f32, f32, f32) {
    let (fin, fout) = desktop_bullet_fin_fout(bullet);
    let base_length = bullet.fdata.max(0.0) * desktop_curve(fin, 0.0, 0.2);
    (base_length, fin, fout)
}

fn laser_bullet_snapshot_render_commands(
    bullet: &BulletComp,
    spec: &BulletSpec,
    layer: f32,
) -> Vec<RenderCommand> {
    if bullet.removed || spec.kind != BulletKind::Laser {
        return Vec::new();
    }

    let (base_length, _, fout) = laser_bullet_base_length(bullet);
    if base_length <= f32::EPSILON || fout <= f32::EPSILON || spec.width <= f32::EPSILON {
        return Vec::new();
    }

    let origin = RenderPoint::new(bullet.x, bullet.y);
    let end = desktop_line_angle_points(origin, bullet.rotation(), base_length).1;
    let mut cwidth = spec.width;
    let mut compound = 1.0;
    let mut commands = Vec::new();

    for color_name in desktop_laser_bullet_colors(spec) {
        cwidth *= 0.5;
        let stroke = cwidth * fout;
        let color = desktop_bullet_render_color(&color_name, Pal::LANCER_LASER);

        commands.push(RenderCommand::draw_line(origin, end, stroke, color, layer));
        commands.push(RenderCommand::draw_triangle(
            end,
            stroke,
            cwidth * 2.0 + spec.width / 2.0,
            bullet.rotation(),
            color,
            layer,
        ));
        commands.push(RenderCommand::draw_circle(
            origin,
            cwidth * fout,
            color,
            true,
            layer,
        ));

        for sign in [-1.0_f32, 1.0] {
            commands.push(RenderCommand::draw_triangle(
                origin,
                spec.side_width * fout * cwidth,
                spec.side_length * compound,
                bullet.rotation() + spec.side_angle * sign,
                color,
                layer,
            ));
        }

        compound *= 0.5;
    }

    commands
}

fn laser_bullet_snapshot_light_commands(
    bullet: &BulletComp,
    spec: &BulletSpec,
) -> Vec<LightCommand> {
    if bullet.removed || spec.kind != BulletKind::Laser {
        return Vec::new();
    }

    let (base_length, _, fout) = laser_bullet_base_length(bullet);
    let stroke = spec.width * 1.4 * fout;
    if base_length <= f32::EPSILON || stroke <= f32::EPSILON {
        return Vec::new();
    }

    let origin = RenderPoint::new(bullet.x, bullet.y);
    let (_, light_end) = desktop_line_angle_points(origin, bullet.rotation(), base_length * 1.1);
    let color_name = desktop_laser_bullet_colors(spec)
        .into_iter()
        .next()
        .unwrap_or_else(|| "lancerLaser@0.4".into());
    let color = desktop_resolve_color_symbol(&color_name).unwrap_or(Pal::LANCER_LASER);

    vec![LightCommand::Line {
        x: origin.x,
        y: origin.y,
        x2: light_end.x,
        y2: light_end.y,
        stroke,
        tint: LightPrimitive {
            center: (origin.x, origin.y),
            radius: stroke,
            color,
            opacity: 0.6,
        },
    }]
}

fn desktop_lerp_decal_color(from: DecalColor, to: DecalColor, progress: f32) -> DecalColor {
    DecalColor {
        r: desktop_lerp(from.r, to.r, progress),
        g: desktop_lerp(from.g, to.g, progress),
        b: desktop_lerp(from.b, to.b, progress),
        a: desktop_lerp(from.a, to.a, progress),
    }
}

fn desktop_shrapnel_bullet_render_color(spec: &BulletSpec, fin: f32) -> [f32; 4] {
    let from = desktop_resolve_color_symbol(&spec.from_color).unwrap_or(DecalColor::WHITE);
    let to = desktop_resolve_color_symbol(&spec.to_color).unwrap_or(Pal::LANCER_LASER);
    desktop_effect_render_color(Some(desktop_lerp_decal_color(from, to, fin)), 1.0)
}

fn shrapnel_bullet_snapshot_render_commands(
    bullet: &BulletComp,
    spec: &BulletSpec,
    layer: f32,
) -> Vec<RenderCommand> {
    if bullet.removed || spec.kind != BulletKind::Shrapnel {
        return Vec::new();
    }

    let (fin, fout) = desktop_bullet_fin_fout(bullet);
    if fout <= f32::EPSILON || spec.width <= f32::EPSILON {
        return Vec::new();
    }

    let real_length = bullet.fdata.max(0.0);
    let rotation = bullet.rotation();
    let origin = RenderPoint::new(bullet.x, bullet.y);
    let color = desktop_shrapnel_bullet_render_color(spec, fin);
    let mut commands = Vec::new();

    let serration_count = if spec.length.abs() <= f32::EPSILON {
        0
    } else {
        (spec.serrations as f32 * real_length / spec.length).max(0.0) as i32
    };
    let serration_alpha = (fout - spec.serration_fade_offset).clamp(0.0, 1.0);
    for i in 0..serration_count {
        let distance = i as f32 * spec.serration_spacing;
        let (offset_x, offset_y) = desktop_rotate_offset(rotation, distance, 0.0);
        let center = RenderPoint::new(origin.x + offset_x, origin.y + offset_y);
        let length =
            serration_alpha * (spec.serration_space_offset - i as f32 * spec.serration_len_scl);
        commands.push(RenderCommand::draw_triangle(
            center,
            spec.serration_width,
            length,
            rotation + 90.0,
            color,
            layer,
        ));
        commands.push(RenderCommand::draw_triangle(
            center,
            spec.serration_width,
            length,
            rotation - 90.0,
            color,
            layer,
        ));
    }

    commands.push(RenderCommand::draw_triangle(
        origin,
        spec.width * fout,
        real_length + 4.0,
        rotation,
        color,
        layer,
    ));
    commands.push(RenderCommand::draw_triangle(
        origin,
        spec.width * fout,
        10.0,
        rotation + 180.0,
        color,
        layer,
    ));

    commands
}

fn shrapnel_bullet_snapshot_light_commands(
    bullet: &BulletComp,
    spec: &BulletSpec,
) -> Vec<LightCommand> {
    if bullet.removed || spec.kind != BulletKind::Shrapnel {
        return Vec::new();
    }

    let (_, fout) = desktop_bullet_fin_fout(bullet);
    let stroke = spec.width * 2.5 * fout;
    let real_length = bullet.fdata.max(0.0);
    if stroke <= f32::EPSILON || real_length <= f32::EPSILON {
        return Vec::new();
    }

    let origin = RenderPoint::new(bullet.x, bullet.y);
    let (_, light_end) = desktop_line_angle_points(origin, bullet.rotation(), real_length);
    let color = desktop_resolve_color_symbol(&spec.to_color).unwrap_or(Pal::LANCER_LASER);

    vec![LightCommand::Line {
        x: origin.x,
        y: origin.y,
        x2: light_end.x,
        y2: light_end.y,
        stroke,
        tint: LightPrimitive {
            center: (origin.x, origin.y),
            radius: stroke,
            color,
            opacity: spec.light_opacity,
        },
    }]
}

const DESKTOP_DRAWF_LASER_CAP_BASE_SIZE: f32 = 16.0;

fn desktop_bullet_laser_line_symbol(spec: &BulletSpec) -> &str {
    if spec.sprite.is_empty() {
        "laser"
    } else {
        spec.sprite.as_str()
    }
}

fn desktop_bullet_laser_end_symbol(line_symbol: &str) -> String {
    format!("{line_symbol}-end")
}

fn drawf_laser_sprite_commands(
    line_symbol: &str,
    start_symbol: &str,
    end_symbol: &str,
    origin: RenderPoint,
    end: RenderPoint,
    scale: f32,
    color: [f32; 4],
    layer: f32,
) -> Vec<RenderCommand> {
    let Some(plan) = Drawf::laser(origin.x, origin.y, end.x, end.y, scale, true) else {
        return Vec::new();
    };

    let cap_size = (DESKTOP_DRAWF_LASER_CAP_BASE_SIZE * scale).max(0.5);
    let mut commands = Vec::with_capacity(3);
    commands.push(RenderCommand::draw_sprite(
        start_symbol,
        RenderRect::from_center(origin, cap_size, cap_size),
        color,
        plan.rotation + 180.0,
        layer,
    ));
    commands.push(RenderCommand::draw_sprite(
        end_symbol,
        RenderRect::from_center(end, cap_size, cap_size),
        color,
        plan.rotation,
        layer,
    ));

    let body_length = plan.body_length();
    if body_length > f32::EPSILON {
        let (center_x, center_y) = plan.body_center();
        commands.push(RenderCommand::draw_sprite(
            line_symbol,
            RenderRect::from_center(
                RenderPoint::new(center_x, center_y),
                body_length,
                plan.stroke.max(0.5),
            ),
            color,
            plan.rotation,
            layer,
        ));
    }

    commands
}

fn sap_bullet_snapshot_render_commands(
    bullet: &BulletComp,
    spec: &BulletSpec,
    data_position: RenderPoint,
    layer: f32,
) -> Vec<RenderCommand> {
    if bullet.removed || spec.kind != BulletKind::Sap {
        return Vec::new();
    }

    let (fin, fout) = desktop_bullet_fin_fout(bullet);
    let scale = spec.width * fout;
    if scale <= f32::EPSILON {
        return Vec::new();
    }

    let origin = RenderPoint::new(bullet.x, bullet.y);
    let end = RenderPoint::new(
        data_position.x + (origin.x - data_position.x) * fin,
        data_position.y + (origin.y - data_position.y) * fin,
    );
    let color = desktop_bullet_render_color(&spec.color, DecalColor::WHITE);
    let line_symbol = desktop_bullet_laser_line_symbol(spec);
    let end_symbol = desktop_bullet_laser_end_symbol(line_symbol);

    drawf_laser_sprite_commands(
        line_symbol,
        &end_symbol,
        &end_symbol,
        origin,
        end,
        scale,
        color,
        layer,
    )
}

fn sap_bullet_snapshot_light_commands(
    bullet: &BulletComp,
    spec: &BulletSpec,
    data_position: RenderPoint,
) -> Vec<LightCommand> {
    if bullet.removed || spec.kind != BulletKind::Sap {
        return Vec::new();
    }

    let (fin, fout) = desktop_bullet_fin_fout(bullet);
    let stroke = 15.0 * fout;
    if stroke <= f32::EPSILON {
        return Vec::new();
    }

    let origin = RenderPoint::new(bullet.x, bullet.y);
    let end = RenderPoint::new(
        data_position.x + (origin.x - data_position.x) * fin,
        data_position.y + (origin.y - data_position.y) * fin,
    );
    let color = desktop_resolve_color_symbol(&spec.light_color).unwrap_or(Pal::SAP);

    vec![LightCommand::Line {
        x: origin.x,
        y: origin.y,
        x2: end.x,
        y2: end.y,
        stroke,
        tint: LightPrimitive {
            center: (origin.x, origin.y),
            radius: stroke,
            color,
            opacity: spec.light_opacity,
        },
    }]
}

fn continuous_laser_bullet_colors(spec: &BulletSpec) -> Vec<String> {
    if !spec.colors.is_empty() {
        spec.colors.clone()
    } else {
        vec![
            "ec745855".into(),
            "ec7458aa".into(),
            "ff9c5a".into(),
            "white".into(),
        ]
    }
}

fn continuous_laser_bullet_fout(bullet: &BulletComp, spec: &BulletSpec) -> f32 {
    let lifetime = if bullet.lifetime > f32::EPSILON {
        bullet.lifetime
    } else {
        spec.lifetime
    };
    if lifetime <= f32::EPSILON {
        return 1.0;
    }
    let fade_time = 16.0_f32.min(lifetime);
    if bullet.time > lifetime - fade_time {
        (1.0 - (bullet.time - (lifetime - fade_time)) / fade_time).clamp(0.0, 1.0)
    } else {
        1.0
    }
}

fn continuous_laser_bullet_real_length(bullet: &BulletComp, spec: &BulletSpec, fout: f32) -> f32 {
    let faded_length = spec.length.max(0.0) * fout;
    if bullet.fdata > f32::EPSILON {
        bullet.fdata.min(faded_length)
    } else {
        faded_length
    }
}

fn continuous_laser_bullet_snapshot_render_commands(
    bullet: &BulletComp,
    spec: &BulletSpec,
    layer: f32,
    render_time: f32,
) -> Vec<RenderCommand> {
    if bullet.removed || spec.kind != BulletKind::ContinuousLaser {
        return Vec::new();
    }

    let fout = continuous_laser_bullet_fout(bullet, spec);
    let real_length = continuous_laser_bullet_real_length(bullet, spec, fout);
    if fout <= f32::EPSILON || real_length <= f32::EPSILON || spec.width <= f32::EPSILON {
        return Vec::new();
    }

    let colors = continuous_laser_bullet_colors(spec);
    let color_count = colors.len().max(1) as f32;
    let origin = RenderPoint::new(bullet.x, bullet.y);
    let line_length = (real_length - 35.0).max(0.0);
    let line_end = desktop_line_angle_points(origin, bullet.rotation(), line_length).1;
    let absin = desktop_absin(render_time, 0.8, 1.5);
    let mut commands = Vec::with_capacity(colors.len() * 3);

    for (index, color_name) in colors.iter().enumerate() {
        let color_fin = if colors.len() > 1 {
            index as f32 / (colors.len() - 1) as f32
        } else {
            0.0
        };
        let base_stroke = desktop_lerp(2.0, 0.5, color_fin);
        let stroke = (spec.width + absin) * fout * base_stroke;
        let color = desktop_bullet_render_color(color_name, Pal::LIGHT_FLAME);
        let ellipse_len_scl = desktop_lerp(1.0 - index as f32 / color_count, 1.0, 0.75);

        commands.push(RenderCommand::draw_line(
            origin, line_end, stroke, color, layer,
        ));
        commands.push(RenderCommand::draw_circle(
            origin,
            (7.0 * ellipse_len_scl).max(stroke / 2.0),
            color,
            true,
            layer,
        ));
        commands.push(RenderCommand::draw_circle(
            line_end,
            (35.0 * ellipse_len_scl).max(stroke / 2.0),
            color,
            true,
            layer,
        ));
    }

    commands
}

fn continuous_laser_bullet_snapshot_light_commands(
    bullet: &BulletComp,
    spec: &BulletSpec,
) -> Vec<LightCommand> {
    if bullet.removed || spec.kind != BulletKind::ContinuousLaser {
        return Vec::new();
    }

    let fout = continuous_laser_bullet_fout(bullet, spec);
    let real_length = continuous_laser_bullet_real_length(bullet, spec, fout);
    if real_length <= f32::EPSILON {
        return Vec::new();
    }

    let origin = RenderPoint::new(bullet.x, bullet.y);
    let (_, light_end) = desktop_line_angle_points(origin, bullet.rotation(), real_length * 1.1);
    let color = desktop_resolve_color_symbol(&spec.light_color).unwrap_or(Pal::LIGHT_FLAME);

    vec![LightCommand::Line {
        x: origin.x,
        y: origin.y,
        x2: light_end.x,
        y2: light_end.y,
        stroke: 40.0,
        tint: LightPrimitive {
            center: (origin.x, origin.y),
            radius: 40.0,
            color,
            opacity: spec.light_opacity,
        },
    }]
}

fn continuous_flame_bullet_colors(spec: &BulletSpec) -> Vec<String> {
    if !spec.colors.is_empty() {
        spec.colors.clone()
    } else {
        vec![
            "eb7abe88".into(),
            "e189f5b2".into(),
            "907ef7cc".into(),
            "91a4ff".into(),
            "white".into(),
        ]
    }
}

fn desktop_slope_interp(value: f32) -> f32 {
    let value = value.clamp(0.0, 1.0);
    if value < 0.5 {
        value * 2.0
    } else {
        (1.0 - value) * 2.0
    }
}

fn desktop_circle_out_interp(value: f32) -> f32 {
    let value = value.clamp(0.0, 1.0);
    (1.0 - (value - 1.0).powi(2)).max(0.0).sqrt()
}

fn desktop_sin(time: f32, scl: f32, mag: f32) -> f32 {
    if !time.is_finite() || scl.abs() <= f32::EPSILON || !mag.is_finite() {
        return 0.0;
    }
    (time / scl).sin() * mag
}

fn desktop_scale_render_color(mut color: [f32; 4], scale: f32) -> [f32; 4] {
    for channel in &mut color {
        *channel = (*channel * scale).clamp(0.0, 1.0);
    }
    color
}

fn continuous_flame_bullet_real_length(bullet: &BulletComp, spec: &BulletSpec, mult: f32) -> f32 {
    let faded_length = spec.length.max(0.0) * mult.max(0.0);
    if bullet.fdata > f32::EPSILON {
        bullet.fdata.min(faded_length)
    } else {
        faded_length
    }
}

fn continuous_flame_bullet_snapshot_render_commands(
    bullet: &BulletComp,
    spec: &BulletSpec,
    layer: f32,
    render_time: f32,
) -> Vec<RenderCommand> {
    if bullet.removed || spec.kind != BulletKind::ContinuousFlame {
        return Vec::new();
    }

    let (fin, _) = desktop_bullet_fin_fout(bullet);
    let mult = desktop_slope_interp(fin);
    let real_length = continuous_flame_bullet_real_length(bullet, spec, mult);
    let width = if spec.width > f32::EPSILON {
        spec.width
    } else {
        3.7
    };
    if mult <= f32::EPSILON || real_length <= f32::EPSILON || width <= f32::EPSILON {
        return Vec::new();
    }

    let origin = RenderPoint::new(bullet.x, bullet.y);
    let rotation = bullet.rotation();
    let osc_scl = if spec.osc_scl > f32::EPSILON {
        spec.osc_scl
    } else {
        1.2
    };
    let osc_mag = if spec.osc_mag.abs() > f32::EPSILON {
        spec.osc_mag
    } else {
        0.02
    };
    let sin = desktop_sin(render_time, osc_scl, osc_mag);
    let pulse = 0.9 * (1.0 + desktop_absin(render_time, 1.0, 0.1));
    let divisions = 25;
    let length_width_pans = [
        (1.12_f32, 1.3_f32, 0.32_f32),
        (1.0, 1.0, 0.3),
        (0.8, 0.9, 0.2),
        (0.5, 0.8, 0.15),
        (0.25, 0.7, 0.1),
    ];

    let colors = continuous_flame_bullet_colors(spec);
    let mut commands = Vec::new();
    for (index, color_name) in colors.iter().enumerate() {
        let (length_scl, width_scl, pan) = length_width_pans
            .get(index)
            .copied()
            .unwrap_or_else(|| *length_width_pans.last().unwrap());
        let flame_length = real_length * length_scl * (1.0 - sin);
        let flame_width = width * width_scl * mult * (1.0 + sin);
        if flame_length <= f32::EPSILON || flame_width <= f32::EPSILON {
            continue;
        }

        let color = desktop_scale_render_color(
            desktop_bullet_render_color(color_name, Pal::LIGHT_FLAME),
            pulse,
        );
        let (_, flame_end) = desktop_line_angle_points(origin, rotation, flame_length);
        commands.push(RenderCommand::draw_line(
            origin,
            flame_end,
            (flame_width * 2.0).max(0.5),
            color,
            layer,
        ));

        let flame = Drawf::flame(
            origin.x,
            origin.y,
            divisions,
            rotation,
            flame_length,
            flame_width,
            pan,
        );
        let stroke = (flame_width * 0.45).max(0.35);
        for points in flame.points.windows(2) {
            let from = RenderPoint::new(points[0].0, points[0].1);
            let to = RenderPoint::new(points[1].0, points[1].1);
            commands.push(RenderCommand::draw_line(from, to, stroke, color, layer));
        }
        if let (Some(first), Some(last)) = (flame.points.first(), flame.points.last()) {
            commands.push(RenderCommand::draw_line(
                RenderPoint::new(last.0, last.1),
                RenderPoint::new(first.0, first.1),
                stroke,
                color,
                layer,
            ));
        }
    }

    let flare_color = desktop_bullet_render_color(&spec.flare_color, Pal::LIGHT_FLAME);
    let flare_angle = render_time * 1.2;
    let flare_length = 40.0 * (mult + sin).max(0.0);
    if flare_length > f32::EPSILON {
        for i in 0..4 {
            commands.push(RenderCommand::draw_triangle(
                origin,
                3.0,
                flare_length,
                i as f32 * 90.0 + 45.0 + flare_angle,
                flare_color,
                layer - 0.0001,
            ));
        }
        for i in 0..4 {
            commands.push(RenderCommand::draw_triangle(
                origin,
                1.5,
                flare_length * 0.5,
                i as f32 * 90.0 + 45.0 + flare_angle,
                desktop_bullet_render_color("white", DecalColor::WHITE),
                layer - 0.0001,
            ));
        }
    }

    commands
}

fn continuous_flame_bullet_snapshot_light_commands(
    bullet: &BulletComp,
    spec: &BulletSpec,
) -> Vec<LightCommand> {
    if bullet.removed || spec.kind != BulletKind::ContinuousFlame {
        return Vec::new();
    }

    let (fin, _) = desktop_bullet_fin_fout(bullet);
    let mult = desktop_slope_interp(fin);
    let real_length = continuous_flame_bullet_real_length(bullet, spec, mult);
    if real_length <= f32::EPSILON {
        return Vec::new();
    }

    let origin = RenderPoint::new(bullet.x, bullet.y);
    let (_, light_end) = desktop_line_angle_points(origin, bullet.rotation(), real_length * 1.1);
    let light_color_name = if spec.light_color.is_empty() {
        &spec.hit_color
    } else {
        &spec.light_color
    };
    let color = desktop_resolve_color_symbol(light_color_name).unwrap_or(Pal::LIGHT_FLAME);
    let opacity = if spec.light_opacity > f32::EPSILON {
        spec.light_opacity
    } else {
        0.7
    };

    vec![LightCommand::Line {
        x: origin.x,
        y: origin.y,
        x2: light_end.x,
        y2: light_end.y,
        stroke: 40.0,
        tint: LightPrimitive {
            center: (origin.x, origin.y),
            radius: 40.0,
            color,
            opacity,
        },
    }]
}

fn point_laser_bullet_aim_endpoint(bullet: &BulletComp) -> Option<RenderPoint> {
    if bullet.aim_x < 0.0
        || bullet.aim_y < 0.0
        || !bullet.aim_x.is_finite()
        || !bullet.aim_y.is_finite()
    {
        return None;
    }
    Some(RenderPoint::new(bullet.aim_x, bullet.aim_y))
}

fn point_laser_bullet_width_scale(bullet: &BulletComp, spec: &BulletSpec, render_time: f32) -> f32 {
    let (fin, _) = desktop_bullet_fin_fout(bullet);
    let fslope = desktop_slope_interp(fin);
    let osc_scl = if spec.osc_scl > f32::EPSILON {
        spec.osc_scl
    } else {
        2.0
    };
    let osc_mag = if spec.osc_mag.abs() > f32::EPSILON {
        spec.osc_mag
    } else {
        0.3
    };
    fslope * (1.0 - osc_mag + desktop_absin(render_time, osc_scl, osc_mag))
}

fn point_laser_bullet_snapshot_render_commands(
    bullet: &BulletComp,
    spec: &BulletSpec,
    layer: f32,
    render_time: f32,
) -> Vec<RenderCommand> {
    if bullet.removed || spec.kind != BulletKind::PointLaser {
        return Vec::new();
    }

    let Some(end) = point_laser_bullet_aim_endpoint(bullet) else {
        return Vec::new();
    };
    let origin = RenderPoint::new(bullet.x, bullet.y);
    let dx = end.x - origin.x;
    let dy = end.y - origin.y;
    if (dx * dx + dy * dy).sqrt() <= f32::EPSILON {
        return Vec::new();
    }

    let scale = point_laser_bullet_width_scale(bullet, spec, render_time);
    if scale <= f32::EPSILON {
        return Vec::new();
    }
    let color = desktop_bullet_render_color(&spec.color, DecalColor::WHITE);
    let line_symbol = desktop_bullet_laser_line_symbol(spec);
    let end_symbol = desktop_bullet_laser_end_symbol(line_symbol);

    drawf_laser_sprite_commands(
        line_symbol,
        &end_symbol,
        &end_symbol,
        origin,
        end,
        scale,
        color,
        layer,
    )
}

fn rail_bullet_snapshot_render_color(spec: &BulletSpec) -> [f32; 4] {
    let color_name = [&spec.hit_color, &spec.light_color, &spec.color]
        .into_iter()
        .find(|name| !name.is_empty() && name.as_str() != "none")
        .map(String::as_str)
        .unwrap_or("white");
    desktop_bullet_render_color(color_name, Pal::LANCER_LASER)
}

fn rail_bullet_snapshot_render_commands(
    bullet: &BulletComp,
    spec: &BulletSpec,
    layer: f32,
) -> Vec<RenderCommand> {
    if bullet.removed || spec.kind != BulletKind::Rail {
        return Vec::new();
    }

    let result_length = if bullet.fdata > f32::EPSILON {
        bullet.fdata.min(spec.length.max(0.0))
    } else {
        spec.length.max(0.0)
    };
    if result_length <= f32::EPSILON {
        return Vec::new();
    }

    let origin = RenderPoint::new(bullet.x, bullet.y);
    let (_, end) = desktop_line_angle_points(origin, bullet.rotation(), result_length);
    let color = rail_bullet_snapshot_render_color(spec);
    let mut commands = Vec::new();

    if spec.line_effect != "none" {
        commands.push(RenderCommand::draw_line(origin, end, 2.0, color, layer));
    }

    if spec.point_effect != "none" && spec.point_effect_space > f32::EPSILON {
        let mut distance = 0.0;
        while distance <= result_length + f32::EPSILON {
            let (_, point) = desktop_line_angle_points(origin, bullet.rotation(), distance);
            commands.push(RenderCommand::draw_circle(point, 2.0, color, true, layer));
            distance += spec.point_effect_space;
        }
    }

    if spec.end_effect != "none" && bullet.collided_ids.is_empty() {
        commands.push(RenderCommand::draw_circle(end, 3.0, color, false, layer));
    }

    commands
}

fn laser_bolt_bullet_snapshot_render_commands(
    bullet: &BulletComp,
    spec: &BulletSpec,
    layer: f32,
) -> Vec<RenderCommand> {
    let line_width = spec.width.max(0.0);
    let back_length = spec.height.max(0.0);
    if line_width <= f32::EPSILON || back_length <= f32::EPSILON {
        return Vec::new();
    }

    let center = RenderPoint::new(bullet.x, bullet.y);
    let (back_from, back_to) =
        desktop_line_angle_center_points(center, bullet.rotation(), back_length);
    let (front_from, front_to) =
        desktop_line_angle_center_points(center, bullet.rotation(), back_length / 2.0);

    vec![
        RenderCommand::draw_line(
            back_from,
            back_to,
            line_width,
            desktop_bullet_render_color(&spec.back_color, Pal::BULLET_YELLOW_BACK),
            layer,
        ),
        RenderCommand::draw_line(
            front_from,
            front_to,
            line_width,
            desktop_bullet_render_color(&spec.front_color, Pal::BULLET_YELLOW),
            layer,
        ),
    ]
}

fn desktop_bullet_front_sprite(spec: &BulletSpec) -> String {
    if spec.sprite.is_empty() {
        "bullet".into()
    } else {
        spec.sprite.clone()
    }
}

fn desktop_bullet_back_sprite(spec: &BulletSpec, front_sprite: &str) -> String {
    if spec.back_sprite.is_empty() {
        format!("{front_sprite}-back")
    } else {
        spec.back_sprite.clone()
    }
}

fn desktop_bullet_sprite_virtual_source_paths(spec: &BulletSpec) -> Vec<String> {
    let front = desktop_bullet_front_sprite(spec);
    let back = desktop_bullet_back_sprite(spec, &front);
    let mut paths = vec![format!("sprites/{front}.png")];
    if back != front {
        paths.push(format!("sprites/{back}.png"));
    }
    paths
}

fn desktop_basic_bullet_kind_renderable(kind: BulletKind) -> bool {
    matches!(
        kind,
        BulletKind::Basic
            | BulletKind::Bomb
            | BulletKind::Missile
            | BulletKind::Flak
            | BulletKind::Artillery
            | BulletKind::LaserBolt
    )
}

fn desktop_bullet_layer(spec: &BulletSpec) -> f32 {
    let layer = spec.layer.strip_prefix("Layer.").unwrap_or(&spec.layer);
    Layer::by_name(layer).unwrap_or(Layer::BULLET)
}

fn desktop_unit_body_sprite_virtual_source_paths(content_loader: &ContentLoader) -> Vec<String> {
    content_loader
        .units()
        .iter()
        .flat_map(|unit| {
            let mut paths = vec![
                format!("sprites/{}.png", unit.name()),
                format!("sprites/{}-outline.png", unit.name()),
                format!("sprites/{}-cell.png", unit.name()),
            ];
            for region in [
                &unit.leg_region,
                &unit.leg_base_region,
                &unit.foot_region,
                &unit.joint_region,
                &unit.base_joint_region,
                &unit.base_region,
            ] {
                if !region.name.is_empty() {
                    paths.push(format!("sprites/{}.png", region.name));
                }
            }
            paths
        })
        .chain([
            "sprites/particle.png".to_string(),
            "sprites/circle-shadow.png".to_string(),
            "sprites/square-shadow.png".to_string(),
            "sprites/ring-item.png".to_string(),
            "sprites/payload-unit.png".to_string(),
            "sprites/payload-build.png".to_string(),
            "sprites/power-cell.png".to_string(),
        ])
        .chain(desktop_unit_weapon_sprite_virtual_source_paths(
            content_loader,
        ))
        .collect()
}

fn desktop_unit_weapon_sprite_virtual_source_paths(content_loader: &ContentLoader) -> Vec<String> {
    content_loader
        .units()
        .iter()
        .flat_map(|unit| unit.weapons.iter())
        .flat_map(|weapon| {
            [
                desktop_weapon_region_symbol(weapon),
                desktop_weapon_outline_symbol(weapon),
                desktop_weapon_cell_symbol(weapon),
                desktop_weapon_heat_symbol(weapon),
            ]
        })
        .filter(|symbol| !symbol.is_empty())
        .map(|symbol| format!("sprites/{symbol}.png"))
        .collect()
}

fn desktop_weapon_region_symbol(weapon: &Weapon) -> String {
    weapon
        .region
        .as_ref()
        .filter(|region| !region.is_empty())
        .cloned()
        .unwrap_or_else(|| weapon.name.clone())
}

fn desktop_weapon_outline_symbol(weapon: &Weapon) -> String {
    weapon
        .outline_region
        .as_ref()
        .filter(|region| !region.is_empty())
        .cloned()
        .unwrap_or_else(|| format!("{}-outline", weapon.name))
}

fn desktop_weapon_cell_symbol(weapon: &Weapon) -> String {
    weapon
        .cell_region
        .as_ref()
        .filter(|region| !region.is_empty())
        .cloned()
        .unwrap_or_else(|| format!("{}-cell", weapon.name))
}

fn desktop_weapon_heat_symbol(weapon: &Weapon) -> String {
    weapon
        .heat_region
        .as_ref()
        .filter(|region| !region.is_empty())
        .cloned()
        .unwrap_or_else(|| format!("{}-heat", weapon.name))
}

fn desktop_unit_body_layer(unit: &UnitComp) -> f32 {
    if unit.is_grounded() {
        if unit.type_info.ground_layer >= 0.0 {
            unit.type_info.ground_layer
        } else {
            Layer::GROUND_UNIT
        }
    } else if unit.type_info.flying_layer >= 0.0 {
        unit.type_info.flying_layer
    } else if unit.type_info.low_altitude {
        Layer::FLYING_UNIT_LOW
    } else {
        Layer::FLYING_UNIT
    }
}

fn desktop_unit_leg_layer(unit: &UnitComp) -> f32 {
    desktop_unit_body_layer(unit) - 0.02
}

fn desktop_texture_region_symbol(region: &TextureRegionRef) -> Option<&str> {
    let name = region.name.trim();
    (!name.is_empty()).then_some(name)
}

fn desktop_texture_region_width(region: &TextureRegionRef, fallback: u32) -> f32 {
    if region.width > 0 {
        region.width as f32
    } else {
        fallback.max(1) as f32
    }
}

fn desktop_texture_region_height(region: &TextureRegionRef, fallback: u32) -> f32 {
    if region.height > 0 {
        region.height as f32
    } else {
        fallback.max(1) as f32
    }
}

fn desktop_angle_between(from: RenderPoint, to: RenderPoint) -> f32 {
    (to.y - from.y).atan2(to.x - from.x).to_degrees()
}

fn desktop_set_vector_length(x: f32, y: f32, target: f32) -> (f32, f32) {
    let length = (x * x + y * y).sqrt();
    if length <= f32::EPSILON || target.abs() <= f32::EPSILON {
        (0.0, 0.0)
    } else {
        (x / length * target, y / length * target)
    }
}

fn desktop_textured_line_sprite_command(
    symbol: impl Into<String>,
    from: RenderPoint,
    to: RenderPoint,
    stroke: f32,
    tint: [f32; 4],
    layer: f32,
) -> Option<RenderCommand> {
    let dx = to.x - from.x;
    let dy = to.y - from.y;
    let length = (dx * dx + dy * dy).sqrt();
    if length <= f32::EPSILON || stroke.abs() <= f32::EPSILON {
        return None;
    }
    Some(RenderCommand::draw_sprite(
        symbol,
        RenderRect::from_center(
            RenderPoint::new((from.x + to.x) * 0.5, (from.y + to.y) * 0.5),
            length,
            stroke,
        ),
        tint,
        dy.atan2(dx).to_degrees(),
        layer,
    ))
}

