pub enum DesktopGraphicsOpenGlBackendTextureResourceKind {
    AtlasPage,
    RuntimeTexture,
    FramebufferAttachment,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct DesktopGraphicsOpenGlBackendTextureResourceIdentity {
    pub key: String,
    pub resource_kind: DesktopGraphicsOpenGlBackendTextureResourceKind,
    pub page_type: PageType,
    pub page_source_path: String,
    pub generation: u64,
    pub gl_handle: Option<u32>,
}

impl DesktopGraphicsOpenGlBackendTextureResourceIdentity {
    pub fn from_atlas_page(page_type: PageType, page_source_path: impl Into<String>) -> Self {
        let page_source_path = page_source_path.into();
        Self {
            key: format!("atlas:{page_type:?}:{page_source_path}"),
            resource_kind: DesktopGraphicsOpenGlBackendTextureResourceKind::AtlasPage,
            page_type,
            page_source_path,
            generation: 0,
            gl_handle: None,
        }
    }

    pub fn from_runtime_texture(name: impl Into<String>) -> Self {
        let name = name.into();
        let page_source_path = format!("runtime:{name}");
        Self {
            key: format!("runtime-texture:{name}"),
            resource_kind: DesktopGraphicsOpenGlBackendTextureResourceKind::RuntimeTexture,
            page_type: PageType::Ui,
            page_source_path,
            generation: 0,
            gl_handle: None,
        }
    }

    pub fn from_framebuffer_color_attachment(name: impl Into<String>) -> Self {
        let name = name.into();
        let page_source_path = format!("framebuffer:{name}:color0");
        Self {
            key: format!("framebuffer-attachment:{name}:color0"),
            resource_kind: DesktopGraphicsOpenGlBackendTextureResourceKind::FramebufferAttachment,
            page_type: PageType::Ui,
            page_source_path,
            generation: 0,
            gl_handle: None,
        }
    }

    pub fn from_effect_buffer_attachment() -> Self {
        Self::from_framebuffer_color_attachment("renderer.effectBuffer")
    }

    pub fn from_shader_texture_binding(texture: &TextureBinding) -> Self {
        match texture {
            TextureBinding::Asset(source_path) => Self::from_atlas_page(
                opengl_backend_texture_page_type_from_source_path(source_path),
                source_path.clone(),
            ),
            TextureBinding::EffectBuffer => Self::from_effect_buffer_attachment(),
        }
    }

    pub fn with_gl_handle(mut self, gl_handle: u32, generation: u64) -> Self {
        self.generation = generation;
        self.gl_handle = Some(gl_handle);
        self.key = format!("gl-texture:{gl_handle}:generation:{generation}");
        self
    }

    pub fn with_uploaded_gl_handle(mut self, gl_handle: u32, generation: u64) -> Self {
        self.generation = generation;
        self.gl_handle = Some(gl_handle);
        self
    }
}

fn opengl_backend_texture_page_type_from_source_path(source_path: &str) -> PageType {
    let path = source_path.trim().replace('\\', "/").to_ascii_lowercase();
    if path.contains("sprites/blocks/environment")
        || path.contains("sprites-override/blocks/environment")
    {
        PageType::Environment
    } else if path.contains("sprites/rubble") || path.contains("sprites-override/rubble") {
        PageType::Rubble
    } else if path.contains("sprites/ui") || path.contains("sprites-override/ui") {
        PageType::Ui
    } else {
        PageType::Main
    }
}

