#[derive(Debug, Clone, PartialEq, Eq)]
pub enum DesktopGraphicsOpenGlBackendTextureUploadPixelSource {
    AtlasPage {
        page_type: PageType,
        page_source_path: String,
        width: u32,
        height: u32,
    },
    GeneratedRgba8888 {
        source_tag: String,
        width: u32,
        height: u32,
        pixels: Vec<u8>,
    },
    RuntimeTexture {
        texture_key: String,
        page_source_path: String,
        width: u32,
        height: u32,
    },
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct DesktopGraphicsOpenGlBackendTextureUploadPixelBytes {
    pub width: u32,
    pub height: u32,
    pub pixels: Vec<u8>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum DesktopGraphicsOpenGlBackendTextureUploadPixelLoadError {
    PngDecode {
        source_path: String,
        error: PngRgba8888DecodeError,
    },
    SizeMismatch {
        source_path: String,
        expected_width: u32,
        expected_height: u32,
        actual_width: u32,
        actual_height: u32,
    },
    RuntimeTexturePixelsUnavailable {
        texture_key: String,
    },
}

impl DesktopGraphicsOpenGlBackendTextureUploadPixelSource {
    pub fn load_rgba8888_pixels(
        &self,
    ) -> Result<
        DesktopGraphicsOpenGlBackendTextureUploadPixelBytes,
        DesktopGraphicsOpenGlBackendTextureUploadPixelLoadError,
    > {
        match self {
            Self::GeneratedRgba8888 {
                source_tag,
                width,
                height,
                pixels,
            } => {
                let expected_len = width.saturating_mul(*height).saturating_mul(4) as usize;
                if pixels.len() != expected_len {
                    let actual_pixels = (pixels.len() / 4).min(u32::MAX as usize) as u32;
                    return Err(
                        DesktopGraphicsOpenGlBackendTextureUploadPixelLoadError::SizeMismatch {
                            source_path: source_tag.clone(),
                            expected_width: *width,
                            expected_height: *height,
                            actual_width: (*width).max(1),
                            actual_height: actual_pixels / (*width).max(1),
                        },
                    );
                }
                Ok(DesktopGraphicsOpenGlBackendTextureUploadPixelBytes {
                    width: *width,
                    height: *height,
                    pixels: pixels.clone(),
                })
            }
            Self::AtlasPage {
                page_source_path,
                width,
                height,
                ..
            } => {
                let image = png_rgba8888_from_path(page_source_path).map_err(|error| {
                    DesktopGraphicsOpenGlBackendTextureUploadPixelLoadError::PngDecode {
                        source_path: page_source_path.clone(),
                        error,
                    }
                })?;
                if image.width != *width || image.height != *height {
                    return Err(
                        DesktopGraphicsOpenGlBackendTextureUploadPixelLoadError::SizeMismatch {
                            source_path: page_source_path.clone(),
                            expected_width: *width,
                            expected_height: *height,
                            actual_width: image.width,
                            actual_height: image.height,
                        },
                    );
                }
                Ok(DesktopGraphicsOpenGlBackendTextureUploadPixelBytes {
                    width: image.width,
                    height: image.height,
                    pixels: image.pixels,
                })
            }
            Self::RuntimeTexture {
                texture_key,
                width,
                height,
                ..
            } if texture_key == DESKTOP_GRAPHICS_OPENGL_PRIMITIVE_TEXTURE_KEY
                && *width == 1
                && *height == 1 =>
            {
                Ok(DesktopGraphicsOpenGlBackendTextureUploadPixelBytes {
                    width: *width,
                    height: *height,
                    pixels: vec![255, 255, 255, 255],
                })
            }
            Self::RuntimeTexture {
                texture_key,
                width,
                height,
                ..
            } if texture_key == DESKTOP_FONT_GLYPH_ATLAS_TEXTURE_KEY
                && *width > 0
                && *height > 0 =>
            {
                Ok(DesktopGraphicsOpenGlBackendTextureUploadPixelBytes {
                    width: *width,
                    height: *height,
                    pixels: opengl_backend_font_glyph_atlas_placeholder_pixels(*width, *height),
                })
            }
            Self::RuntimeTexture { texture_key, .. } => Err(
                DesktopGraphicsOpenGlBackendTextureUploadPixelLoadError::RuntimeTexturePixelsUnavailable {
                    texture_key: texture_key.clone(),
                },
            ),
        }
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum DesktopGraphicsOpenGlBackendTextureUploadCommand {
    DeleteTexture {
        texture_handle: u32,
    },
    BindTexture {
        target: u32,
        texture_handle: u32,
    },
    SetTextureParameter {
        target: u32,
        pname: u32,
        param: i32,
    },
    TexImage2D {
        target: u32,
        level: i32,
        internal_format: i32,
        width: i32,
        height: i32,
        border: i32,
        format: u32,
        pixel_type: u32,
        pixel_source: DesktopGraphicsOpenGlBackendTextureUploadPixelSource,
    },
    TexSubImage2DFromSource {
        target: u32,
        level: i32,
        xoffset: i32,
        yoffset: i32,
        width: i32,
        height: i32,
        format: u32,
        pixel_type: u32,
        pixel_source: DesktopGraphicsOpenGlBackendTextureUploadPixelSource,
    },
    TexSubImage2D {
        target: u32,
        level: i32,
        xoffset: i32,
        yoffset: i32,
        width: i32,
        height: i32,
        format: u32,
        pixel_type: u32,
        pixels: Vec<u8>,
    },
}

pub trait DesktopGraphicsOpenGlBackendTextureUploadCommandSink {
    fn consume_opengl_texture_upload_command(
        &mut self,
        command: DesktopGraphicsOpenGlBackendTextureUploadCommand,
    );
}

#[derive(Debug, Clone, Default, PartialEq, Eq)]
pub struct DesktopGraphicsRecordingOpenGlBackendTextureUploadCommandSink {
    pub commands: Vec<DesktopGraphicsOpenGlBackendTextureUploadCommand>,
}

impl DesktopGraphicsOpenGlBackendTextureUploadCommandSink
    for DesktopGraphicsRecordingOpenGlBackendTextureUploadCommandSink
{
    fn consume_opengl_texture_upload_command(
        &mut self,
        command: DesktopGraphicsOpenGlBackendTextureUploadCommand,
    ) {
        self.commands.push(command);
    }
}

fn opengl_backend_texture_upload_dimension(value: u32) -> i32 {
    value.min(i32::MAX as u32) as i32
}

fn opengl_backend_rgba8888_upload_bytes(rgba: u32) -> [u8; 4] {
    [
        ((rgba >> 24) & 0xff) as u8,
        ((rgba >> 16) & 0xff) as u8,
        ((rgba >> 8) & 0xff) as u8,
        (rgba & 0xff) as u8,
    ]
}

fn opengl_backend_font_glyph_atlas_placeholder_pixels(width: u32, height: u32) -> Vec<u8> {
    let pixel_count = width.saturating_mul(height) as usize;
    let mut pixels = vec![0; pixel_count.saturating_mul(4)];
    if pixel_count == 0 {
        return pixels;
    }

    for y in 0..height {
        for x in 0..width {
            if x == y || x + y + 1 == width.max(height) {
                let index = (y.saturating_mul(width).saturating_add(x) as usize) * 4;
                if index + 3 < pixels.len() {
                    pixels[index] = 255;
                    pixels[index + 1] = 255;
                    pixels[index + 2] = 255;
                    pixels[index + 3] = 255;
                }
            }
        }
    }
    pixels
}

impl DesktopGraphicsOpenGlBackendResolvedTextureUpload {
    fn full_upload_pixel_source(&self) -> DesktopGraphicsOpenGlBackendTextureUploadPixelSource {
        match self.resource_kind {
            DesktopGraphicsOpenGlBackendTextureResourceKind::AtlasPage => {
                DesktopGraphicsOpenGlBackendTextureUploadPixelSource::AtlasPage {
                    page_type: self.page_type,
                    page_source_path: self.page_source_path.clone(),
                    width: self.page_width,
                    height: self.page_height,
                }
            }
            DesktopGraphicsOpenGlBackendTextureResourceKind::RuntimeTexture => {
                DesktopGraphicsOpenGlBackendTextureUploadPixelSource::RuntimeTexture {
                    texture_key: self.texture_key.clone(),
                    page_source_path: self.page_source_path.clone(),
                    width: self.page_width,
                    height: self.page_height,
                }
            }
            DesktopGraphicsOpenGlBackendTextureResourceKind::FramebufferAttachment => {
                DesktopGraphicsOpenGlBackendTextureUploadPixelSource::RuntimeTexture {
                    texture_key: self.texture_key.clone(),
                    page_source_path: self.page_source_path.clone(),
                    width: self.page_width,
                    height: self.page_height,
                }
            }
        }
    }

    pub fn to_opengl_texture_upload_commands(
        &self,
    ) -> Vec<DesktopGraphicsOpenGlBackendTextureUploadCommand> {
        let mut commands = Vec::new();
        if let Some(texture_handle) = self.previous_texture_handle {
            commands.push(
                DesktopGraphicsOpenGlBackendTextureUploadCommand::DeleteTexture { texture_handle },
            );
        }
        commands.push(
            DesktopGraphicsOpenGlBackendTextureUploadCommand::BindTexture {
                target: DESKTOP_GRAPHICS_OPENGL_TEXTURE_2D,
                texture_handle: self.texture_handle,
            },
        );

        match self.kind {
            DesktopGraphicsOpenGlBackendTextureUploadKind::FullPage => {
                if self.recreate_texture || self.texture_was_allocated {
                    let filter = self.sampler.to_opengl_filter();
                    commands.push(
                        DesktopGraphicsOpenGlBackendTextureUploadCommand::SetTextureParameter {
                            target: DESKTOP_GRAPHICS_OPENGL_TEXTURE_2D,
                            pname: DESKTOP_GRAPHICS_OPENGL_TEXTURE_MIN_FILTER,
                            param: filter,
                        },
                    );
                    commands.push(
                        DesktopGraphicsOpenGlBackendTextureUploadCommand::SetTextureParameter {
                            target: DESKTOP_GRAPHICS_OPENGL_TEXTURE_2D,
                            pname: DESKTOP_GRAPHICS_OPENGL_TEXTURE_MAG_FILTER,
                            param: filter,
                        },
                    );
                    commands.push(
                        DesktopGraphicsOpenGlBackendTextureUploadCommand::SetTextureParameter {
                            target: DESKTOP_GRAPHICS_OPENGL_TEXTURE_2D,
                            pname: DESKTOP_GRAPHICS_OPENGL_TEXTURE_WRAP_S,
                            param: DESKTOP_GRAPHICS_OPENGL_CLAMP_TO_EDGE as i32,
                        },
                    );
                    commands.push(
                        DesktopGraphicsOpenGlBackendTextureUploadCommand::SetTextureParameter {
                            target: DESKTOP_GRAPHICS_OPENGL_TEXTURE_2D,
                            pname: DESKTOP_GRAPHICS_OPENGL_TEXTURE_WRAP_T,
                            param: DESKTOP_GRAPHICS_OPENGL_CLAMP_TO_EDGE as i32,
                        },
                    );
                    commands.push(
                        DesktopGraphicsOpenGlBackendTextureUploadCommand::TexImage2D {
                            target: DESKTOP_GRAPHICS_OPENGL_TEXTURE_2D,
                            level: 0,
                            internal_format: DESKTOP_GRAPHICS_OPENGL_RGBA as i32,
                            width: opengl_backend_texture_upload_dimension(self.page_width),
                            height: opengl_backend_texture_upload_dimension(self.page_height),
                            border: 0,
                            format: DESKTOP_GRAPHICS_OPENGL_RGBA,
                            pixel_type: DESKTOP_GRAPHICS_OPENGL_UNSIGNED_BYTE,
                            pixel_source: self.full_upload_pixel_source(),
                        },
                    );
                } else {
                    commands.push(
                        DesktopGraphicsOpenGlBackendTextureUploadCommand::TexSubImage2DFromSource {
                            target: DESKTOP_GRAPHICS_OPENGL_TEXTURE_2D,
                            level: 0,
                            xoffset: 0,
                            yoffset: 0,
                            width: opengl_backend_texture_upload_dimension(self.page_width),
                            height: opengl_backend_texture_upload_dimension(self.page_height),
                            format: DESKTOP_GRAPHICS_OPENGL_RGBA,
                            pixel_type: DESKTOP_GRAPHICS_OPENGL_UNSIGNED_BYTE,
                            pixel_source: self.full_upload_pixel_source(),
                        },
                    );
                }
            }
            DesktopGraphicsOpenGlBackendTextureUploadKind::DirtyPixels => {
                for pixel in &self.dirty_pixels {
                    commands.push(
                        DesktopGraphicsOpenGlBackendTextureUploadCommand::TexSubImage2D {
                            target: DESKTOP_GRAPHICS_OPENGL_TEXTURE_2D,
                            level: 0,
                            xoffset: pixel.x,
                            yoffset: pixel.y,
                            width: 1,
                            height: 1,
                            format: DESKTOP_GRAPHICS_OPENGL_RGBA,
                            pixel_type: DESKTOP_GRAPHICS_OPENGL_UNSIGNED_BYTE,
                            pixels: opengl_backend_rgba8888_upload_bytes(pixel.rgba).to_vec(),
                        },
                    );
                }
            }
        }

        commands
    }
}

#[derive(Debug, Clone, Default, PartialEq, Eq)]
pub struct DesktopGraphicsOpenGlBackendTextureUploadSinkExecutionState {
    pub texture_uploads_emitted: usize,
    pub last_texture_upload: Option<DesktopGraphicsOpenGlBackendTextureUploadPlan>,
}

#[derive(Debug, Clone, Default, PartialEq, Eq)]
pub struct DesktopGraphicsOpenGlBackendFramebufferAttachmentSinkExecutionState {
    pub framebuffer_attachments_emitted: usize,
    pub last_framebuffer_attachment: Option<DesktopGraphicsOpenGlBackendFramebufferAttachmentPlan>,
}

impl DesktopGraphicsOpenGlBackendTextureResource {
    pub fn from_binding(binding: &DesktopGraphicsOpenGlBackendTextureBinding) -> Self {
        Self {
            key: binding.texture_identity.key.clone(),
            identity: binding.texture_identity.clone(),
            resource_kind: binding.texture_identity.resource_kind.clone(),
            page_type: binding.page_type,
            page_source_path: binding.page_source_path.clone(),
            page_width: binding.page_width,
            page_height: binding.page_height,
            sampler: binding.sampler,
            bind_count: 0,
        }
    }

    pub fn needs_full_upload(&self) -> bool {
        self.identity.gl_handle.is_none()
    }

    pub fn to_full_upload_plan(&self) -> DesktopGraphicsOpenGlBackendTextureUploadPlan {
        DesktopGraphicsOpenGlBackendTextureUploadPlan {
            texture_key: self.key.clone(),
            texture_identity: self.identity.clone(),
            resource_kind: self.resource_kind.clone(),
            page_type: self.page_type,
            page_source_path: self.page_source_path.clone(),
            page_width: self.page_width,
            page_height: self.page_height,
            sampler: self.sampler,
            generation: self.identity.generation.saturating_add(1),
            bind_count: self.bind_count,
            recreate_texture: false,
            dirty_pixels: Vec::new(),
            kind: DesktopGraphicsOpenGlBackendTextureUploadKind::FullPage,
        }
    }

    pub fn apply_resolved_upload(
        &mut self,
        upload: &DesktopGraphicsOpenGlBackendResolvedTextureUpload,
    ) {
        self.identity = self
            .identity
            .clone()
            .with_uploaded_gl_handle(upload.texture_handle, upload.generation);
    }
}

impl DesktopGraphicsOpenGlBackendTextureResourceTable {
    pub fn register_binding(&mut self, binding: &DesktopGraphicsOpenGlBackendTextureBinding) {
        let key = binding.texture_identity.key.clone();
        let resource = self
            .resources
            .entry(key)
            .or_insert_with(|| DesktopGraphicsOpenGlBackendTextureResource::from_binding(binding));
        resource.identity = binding.texture_identity.clone();
        resource.resource_kind = binding.texture_identity.resource_kind.clone();
        resource.page_type = binding.page_type;
        resource.page_source_path = binding.page_source_path.clone();
        resource.page_width = binding.page_width;
        resource.page_height = binding.page_height;
        resource.sampler = binding.sampler;
        resource.bind_count += 1;
    }

    pub fn get(&self, key: &str) -> Option<&DesktopGraphicsOpenGlBackendTextureResource> {
        self.resources.get(key)
    }

    pub fn full_upload_plans(&self) -> Vec<DesktopGraphicsOpenGlBackendTextureUploadPlan> {
        self.resources
            .values()
            .filter(|resource| resource.needs_full_upload())
            .map(DesktopGraphicsOpenGlBackendTextureResource::to_full_upload_plan)
            .collect()
    }

    pub fn apply_resolved_upload(
        &mut self,
        upload: &DesktopGraphicsOpenGlBackendResolvedTextureUpload,
    ) {
        if let Some(resource) = self.resources.get_mut(&upload.texture_key) {
            resource.apply_resolved_upload(upload);
        }
    }

    pub fn apply_resolved_uploads<I>(&mut self, uploads: I)
    where
        I: IntoIterator<Item = DesktopGraphicsOpenGlBackendResolvedTextureUpload>,
    {
        for upload in uploads {
            self.apply_resolved_upload(&upload);
        }
    }
}

fn desktop_candidate_asset_raw_root_from_asset_root(
    asset_root: &std::path::Path,
) -> Option<PathBuf> {
    asset_root.parent().map(|parent| parent.join("assets-raw"))
}

fn desktop_sprite_source_path_cache() -> &'static Mutex<BTreeMap<String, Option<PathBuf>>> {
    static CACHE: OnceLock<Mutex<BTreeMap<String, Option<PathBuf>>>> = OnceLock::new();
    CACHE.get_or_init(|| Mutex::new(BTreeMap::new()))
}

fn desktop_normalized_path_string(path: &Path) -> String {
    path.to_string_lossy().replace('\\', "/")
}

fn desktop_path_components_for_sprite_lookup(path: &str) -> Vec<String> {
    path.split('/')
        .filter(|component| !component.is_empty() && *component != "." && *component != "..")
        .map(|component| component.to_ascii_lowercase())
        .collect()
}

fn desktop_sprite_source_lookup_score(
    raw_root: &Path,
    candidate: &Path,
    normalized_source_path: &str,
) -> usize {
    let Ok(relative) = candidate.strip_prefix(raw_root) else {
        return 0;
    };
    let candidate_components =
        desktop_path_components_for_sprite_lookup(&desktop_normalized_path_string(relative));
    let source_components = desktop_path_components_for_sprite_lookup(normalized_source_path);
    if source_components.is_empty() || candidate_components.is_empty() {
        return 0;
    }

    let source_parent_len = source_components.len().saturating_sub(1);
    let shared_prefix_len = candidate_components
        .iter()
        .zip(source_components.iter())
        .take(source_parent_len)
        .take_while(|(candidate, source)| candidate == source)
        .count();
    let exact_suffix_bonus = if candidate_components.ends_with(&source_components) {
        1000
    } else {
        0
    };

    exact_suffix_bonus + shared_prefix_len
}

fn desktop_find_sprite_source_path_by_filename(
    raw_root: &Path,
    normalized_source_path: &str,
) -> Option<PathBuf> {
    let source_file_name = Path::new(normalized_source_path).file_name()?.to_owned();
    let mut pending = vec![raw_root.to_path_buf()];
    let mut best: Option<(usize, String, PathBuf)> = None;

    while let Some(directory) = pending.pop() {
        let Ok(entries) = std::fs::read_dir(&directory) else {
            continue;
        };
        for entry in entries.flatten() {
            let path = entry.path();
            let Ok(file_type) = entry.file_type() else {
                continue;
            };
            if file_type.is_dir() {
                pending.push(path);
                continue;
            }
            if !file_type.is_file() || path.file_name() != Some(source_file_name.as_os_str()) {
                continue;
            }

            let score = desktop_sprite_source_lookup_score(raw_root, &path, normalized_source_path);
            let normalized_candidate = desktop_normalized_path_string(&path);
            let replace_best = best
                .as_ref()
                .map(|(best_score, best_path, _)| {
                    score > *best_score
                        || (score == *best_score && normalized_candidate < *best_path)
                })
                .unwrap_or(true);
            if replace_best {
                best = Some((score, normalized_candidate, path));
            }
        }
    }

    best.map(|(_, _, path)| path)
}

fn desktop_existing_sprite_source_path_from_raw_root(
    raw_root: &Path,
    normalized_source_path: &str,
) -> Option<PathBuf> {
    let raw_path = raw_root.join(normalized_source_path);
    if raw_path.exists() {
        return Some(raw_path);
    }

    let cache_key = format!(
        "{}::{}",
        desktop_normalized_path_string(raw_root),
        normalized_source_path
    );
    if let Ok(cache) = desktop_sprite_source_path_cache().lock() {
        if let Some(cached) = cache.get(&cache_key) {
            return cached.clone();
        }
    }

    let found = desktop_find_sprite_source_path_by_filename(raw_root, normalized_source_path);
    if let Ok(mut cache) = desktop_sprite_source_path_cache().lock() {
        cache.insert(cache_key, found.clone());
    }
    found
}

fn desktop_sprite_source_path_is_nine_patch(source_path: &str) -> bool {
    source_path
        .trim()
        .replace('\\', "/")
        .to_ascii_lowercase()
        .ends_with(".9.png")
}

fn desktop_png_rgba8888_pixel(image: &PngRgba8888Image, x: u32, y: u32) -> Option<[u8; 4]> {
    if x >= image.width || y >= image.height {
        return None;
    }
    let offset = usize::try_from((y * image.width + x) * 4).ok()?;
    Some([
        *image.pixels.get(offset)?,
        *image.pixels.get(offset + 1)?,
        *image.pixels.get(offset + 2)?,
        *image.pixels.get(offset + 3)?,
    ])
}

fn desktop_nine_patch_marker_pixel(image: &PngRgba8888Image, x: u32, y: u32) -> bool {
    desktop_png_rgba8888_pixel(image, x, y)
        .map(|[r, g, b, a]| a > 0 && r < 16 && g < 16 && b < 16)
        .unwrap_or(false)
}

fn desktop_nine_patch_horizontal_marker_run(
    image: &PngRgba8888Image,
    y: u32,
) -> Option<(u32, u32)> {
    if image.width <= 2 || y >= image.height {
        return None;
    }
    let mut run = None;
    for x in 1..image.width - 1 {
        if desktop_nine_patch_marker_pixel(image, x, y) {
            run = Some(match run {
                Some((start, _)) => (start, x),
                None => (x, x),
            });
        }
    }
    run
}

fn desktop_nine_patch_vertical_marker_run(image: &PngRgba8888Image, x: u32) -> Option<(u32, u32)> {
    if image.height <= 2 || x >= image.width {
        return None;
    }
    let mut run = None;
    for y in 1..image.height - 1 {
        if desktop_nine_patch_marker_pixel(image, x, y) {
            run = Some(match run {
                Some((start, _)) => (start, y),
                None => (y, y),
            });
        }
    }
    run
}

fn desktop_nine_patch_from_path(path: &Path) -> Option<DesktopGraphicsOpenGlBackendNinePatch> {
    let image = png_rgba8888_from_path(path).ok()?;
    if image.width <= 2 || image.height <= 2 {
        return None;
    }
    let inner_width = image.width - 2;
    let inner_height = image.height - 2;
    let (left, right) = desktop_nine_patch_horizontal_marker_run(&image, 0)
        .map(|(start, end)| {
            (
                start.saturating_sub(1).min(inner_width),
                inner_width.saturating_sub(end).min(inner_width),
            )
        })
        .unwrap_or((1.min(inner_width), 1.min(inner_width)));
    let (top, bottom) = desktop_nine_patch_vertical_marker_run(&image, 0)
        .map(|(start, end)| {
            (
                start.saturating_sub(1).min(inner_height),
                inner_height.saturating_sub(end).min(inner_height),
            )
        })
        .unwrap_or((1.min(inner_height), 1.min(inner_height)));

    Some(DesktopGraphicsOpenGlBackendNinePatch {
        left,
        right,
        top,
        bottom,
    })
}

fn desktop_existing_sprite_source_path(source_path: &str) -> Option<PathBuf> {
    let normalized = source_path.trim().replace('\\', "/");
    if normalized.is_empty() {
        return None;
    }

    let direct = PathBuf::from(&normalized);
    if direct.exists() {
        return Some(direct);
    }

    if let Ok(asset_root) = std::env::var("MINDUSTRY_ASSET_ROOT") {
        let asset_root = PathBuf::from(asset_root);
        let asset_path = asset_root.join(&normalized);
        if asset_path.exists() {
            return Some(asset_path);
        }

        if let Some(asset_raw_root) = desktop_candidate_asset_raw_root_from_asset_root(&asset_root)
        {
            if let Some(raw_path) =
                desktop_existing_sprite_source_path_from_raw_root(&asset_raw_root, &normalized)
            {
                return Some(raw_path);
            }
        }
    }

    if let Ok(asset_raw_root) = std::env::var("MINDUSTRY_ASSET_RAW_ROOT") {
        if let Some(raw_path) = desktop_existing_sprite_source_path_from_raw_root(
            &PathBuf::from(asset_raw_root),
            &normalized,
        ) {
            return Some(raw_path);
        }
    }

    None
}

fn desktop_existing_asset_source_path(source_path: &str) -> Option<PathBuf> {
    let normalized = source_path.trim().replace('\\', "/");
    if normalized.is_empty() {
        return None;
    }

    let direct = PathBuf::from(&normalized);
    if direct.exists() {
        return Some(direct);
    }

    if let Ok(asset_root) = std::env::var("MINDUSTRY_ASSET_ROOT") {
        let asset_path = PathBuf::from(asset_root).join(&normalized);
        if asset_path.exists() {
            return Some(asset_path);
        }
    }

    None
}

fn default_desktop_font_asset_source_traces() -> Vec<DesktopFontAssetSourceTrace> {
    upstream_font_source_paths()
        .map(|source_path| DesktopFontAssetSourceTrace {
            source_path: source_path.to_string(),
            file_path: desktop_existing_asset_source_path(source_path)
                .map(|path| path.to_string_lossy().replace('\\', "/")),
        })
        .collect()
}

fn desktop_read_utf8_lossy_text_file(path: &Path) -> io::Result<String> {
    let bytes = std::fs::read(path)?;
    Ok(match String::from_utf8(bytes) {
        Ok(contents) => contents,
        Err(error) => String::from_utf8_lossy(error.as_bytes()).into_owned(),
    })
}

fn default_desktop_content_icon_glyph_registry() -> DesktopContentIconGlyphRegistry {
    let source_path = UPSTREAM_ICONS_PROPERTIES_SOURCE_PATH.to_string();
    let file_path = desktop_existing_asset_source_path(UPSTREAM_ICONS_PROPERTIES_SOURCE_PATH)
        .map(|path| path.to_string_lossy().replace('\\', "/"));

    let Some(file_path_ref) = file_path.as_ref() else {
        return DesktopContentIconGlyphRegistry::new(source_path, file_path, Vec::new(), None);
    };

    let path = PathBuf::from(file_path_ref);
    match desktop_read_utf8_lossy_text_file(&path) {
        Ok(contents) => match parse_upstream_icon_properties(&contents) {
            Ok(icons) => DesktopContentIconGlyphRegistry::new(source_path, file_path, icons, None),
            Err(error) => DesktopContentIconGlyphRegistry::new(
                source_path,
                file_path,
                Vec::new(),
                Some(error.to_string()),
            ),
        },
        Err(error) => DesktopContentIconGlyphRegistry::new(
            source_path,
            file_path,
            Vec::new(),
            Some(error.to_string()),
        ),
    }
}

fn desktop_font_rasterization_plan(
    font_asset_sources: &[DesktopFontAssetSourceTrace],
    content_icon_glyph_registry: &DesktopContentIconGlyphRegistry,
    texture_atlas: &TextureAtlasPlan<bool>,
) -> DesktopFontRasterizationPlan {
    let mut source_paths = BTreeMap::new();
    for source in font_asset_sources {
        source_paths
            .entry(source.source_path.as_str())
            .or_insert_with(|| source.file_path.clone());
    }

    let font_assets = upstream_font_assets()
        .iter()
        .map(|asset| {
            let file_path = source_paths
                .get(asset.source_path)
                .and_then(|file_path| file_path.clone());
            DesktopFontRasterizationAssetPlan {
                role: asset.role,
                java_static_name: asset.role.java_static_name(),
                asset_name: asset.asset_name,
                source_path: asset.source_path,
                resolved: file_path.is_some(),
                file_path,
                render_font_id: asset.render_font_id(),
                size: asset.size,
                incremental: asset.incremental,
                scaled: asset.scaled,
                border_width: asset.border_width,
                shadow_offset_y: asset.shadow_offset_y,
                character_seed_count: asset
                    .characters
                    .map(|characters| characters.chars().count())
                    .unwrap_or(0),
            }
        })
        .collect::<Vec<_>>();

    let content_icons = content_icon_glyph_registry
        .icons()
        .iter()
        .map(|icon| DesktopContentIconGlyphPlan {
            unicode: icon.unicode,
            name: icon.name.clone(),
            atlas_symbol: icon.atlas_symbol.clone(),
            emoji: icon.emoji_string(),
            atlas_region_resolved: texture_atlas.has(&icon.atlas_symbol),
        })
        .collect::<Vec<_>>();

    DesktopFontRasterizationPlan {
        font_assets,
        content_icons,
        content_icon_load_error: content_icon_glyph_registry.load_error.clone(),
        fallback_placeholder_enabled: true,
    }
}

fn desktop_validate_font_asset_sources(
    sources: &[DesktopFontAssetSourceTrace],
) -> DesktopFontAssetValidationReport {
    let mut resolved_by_source_path = BTreeMap::new();
    for source in sources {
        resolved_by_source_path
            .entry(source.source_path.clone())
            .and_modify(|resolved| *resolved |= source.resolved())
            .or_insert_with(|| source.resolved());
    }

    DesktopFontAssetValidationReport {
        total_count: resolved_by_source_path.len(),
        resolved_count: resolved_by_source_path
            .values()
            .filter(|resolved| **resolved)
            .count(),
        missing_source_paths: resolved_by_source_path
            .into_iter()
            .filter_map(|(source_path, resolved)| (!resolved).then_some(source_path))
            .collect(),
    }
}

impl DesktopGraphicsOpenGlBackendTextureBinding {
    pub fn from_resolved_sprite(sprite: &DesktopGraphicsResolvedSpriteTrace) -> Option<Self> {
        if sprite.missing {
            return None;
        }
        let page_type = sprite.page_type?;
        let page_source_path = sprite.page_source_path.clone()?;
        if let Some(region_source_path) = sprite.region_source_path.as_deref() {
            if let Some(existing_source_path) =
                desktop_existing_sprite_source_path(region_source_path)
            {
                if let Some((page_width, page_height)) =
                    png_dimensions_from_path(&existing_source_path)
                {
                    let direct_page_source_path =
                        existing_source_path.to_string_lossy().replace('\\', "/");
                    let nine_patch = desktop_sprite_source_path_is_nine_patch(region_source_path)
                        .then(|| desktop_nine_patch_from_path(&existing_source_path))
                        .flatten();
                    let (uv, region_width, region_height) =
                        if nine_patch.is_some() && page_width > 2 && page_height > 2 {
                            (
                                [
                                    1.0 / page_width as f32,
                                    1.0 / page_height as f32,
                                    (page_width - 1) as f32 / page_width as f32,
                                    (page_height - 1) as f32 / page_height as f32,
                                ],
                                page_width - 2,
                                page_height - 2,
                            )
                        } else {
                            ([0.0, 0.0, 1.0, 1.0], page_width, page_height)
                        };
                    return Some(Self {
                        command_index: sprite.command_index,
                        symbol: sprite.symbol.clone(),
                        texture_identity:
                            DesktopGraphicsOpenGlBackendTextureResourceIdentity::from_atlas_page(
                                page_type,
                                direct_page_source_path.clone(),
                            ),
                        page_type,
                        page_source_path: direct_page_source_path,
                        page_width,
                        page_height,
                        sampler: sprite.sampler,
                        uv,
                        region_width,
                        region_height,
                        nine_patch,
                    });
                }
            }
        }
        Some(Self {
            command_index: sprite.command_index,
            symbol: sprite.symbol.clone(),
            texture_identity: DesktopGraphicsOpenGlBackendTextureResourceIdentity::from_atlas_page(
                page_type,
                page_source_path.clone(),
            ),
            page_type,
            page_source_path,
            page_width: sprite.page_width?,
            page_height: sprite.page_height?,
            sampler: sprite.sampler,
            uv: [sprite.u?, sprite.v?, sprite.u2?, sprite.v2?],
            region_width: sprite.region_width?,
            region_height: sprite.region_height?,
            nine_patch: None,
        })
    }
}

