#[derive(Debug, Clone, Default, PartialEq)]
pub struct DesktopGraphicsResolvingOpenGlBackendCommandExecutor {
    pub allocator: DesktopGraphicsOpenGlBackendHandleAllocator,
    pub cache: DesktopGraphicsOpenGlBackendHandleCache,
    pub location_cache: DesktopGraphicsOpenGlBackendLocationCache,
    pub framebuffer_attachment_plans: Vec<DesktopGraphicsOpenGlBackendFramebufferAttachmentPlan>,
    pub resolved_framebuffer_attachments:
        Vec<DesktopGraphicsOpenGlBackendResolvedFramebufferAttachment>,
    pub resolved_texture_uploads: Vec<DesktopGraphicsOpenGlBackendResolvedTextureUpload>,
    pub texture_upload_commands: Vec<DesktopGraphicsOpenGlBackendTextureUploadCommand>,
    pub resolved_sprite_mesh_uploads: Vec<DesktopGraphicsOpenGlBackendResolvedSpriteMeshUpload>,
    pub sprite_mesh_upload_commands: Vec<DesktopGraphicsOpenGlBackendSpriteMeshUploadCommand>,
    pub resolved_resolve_mesh_uploads: Vec<DesktopGraphicsOpenGlBackendResolvedResolveMeshUpload>,
    pub resolve_mesh_upload_commands: Vec<DesktopGraphicsOpenGlBackendResolveMeshUploadCommand>,
    pub resolved_shader_commands: Vec<DesktopGraphicsOpenGlBackendResolvedShaderCommand>,
    pub resolved_draw_actions: Vec<DesktopGraphicsOpenGlBackendResolvedDrawCallAction>,
    pub draw_commands: Vec<DesktopGraphicsOpenGlBackendDrawCommand>,
    pub resolve_commands: Vec<DesktopGraphicsOpenGlBackendResolveCommand>,
    pub resolve_sample_quads: Vec<DesktopGraphicsOpenGlBackendResolveQuad>,
    pub resolve_draw_commands: Vec<DesktopGraphicsOpenGlBackendDrawCommand>,
}

impl DesktopGraphicsResolvingOpenGlBackendCommandExecutor {
    pub const SHADER_BLIT_PROGRAM_KEY: &'static str = "shader:resolve:ShaderBlit";
    pub const DRAW_RECT_SAMPLE_PROGRAM_KEY: &'static str = "shader:resolve:DrawRectSample";
    pub const DRAW_FBO_SAMPLE_PROGRAM_KEY: &'static str = "shader:resolve:DrawFboSample";
    pub const FULLSCREEN_QUAD_VERTEX_ARRAY_KEY: &'static str = "mesh:resolve:fullscreen-quad";
    pub const SAMPLE_QUAD_VERTEX_ARRAY_KEY_PREFIX: &'static str = "mesh:resolve:sample-quad";

    pub const fn resolve_draw_program_key(resolve_kind: RenderResolveKind) -> Option<&'static str> {
        match resolve_kind {
            RenderResolveKind::ShaderBlit => Some(Self::SHADER_BLIT_PROGRAM_KEY),
            RenderResolveKind::DrawRectSample => Some(Self::DRAW_RECT_SAMPLE_PROGRAM_KEY),
            RenderResolveKind::DrawFboSample => Some(Self::DRAW_FBO_SAMPLE_PROGRAM_KEY),
            RenderResolveKind::Blit => None,
        }
    }

    pub fn resolve_sample_quad_vertex_array_key(
        resolve_index: usize,
        command: &DesktopGraphicsOpenGlBackendResolveCommand,
    ) -> String {
        format!(
            "{}:{}:{:?}:{:?}",
            Self::SAMPLE_QUAD_VERTEX_ARRAY_KEY_PREFIX,
            resolve_index,
            command.source_target,
            command.resolve_kind
        )
    }

    pub fn consume_opengl_framebuffer_attachment(
        &mut self,
        plan: DesktopGraphicsOpenGlBackendFramebufferAttachmentPlan,
    ) {
        let resolved = self
            .cache
            .resolve_framebuffer_attachment(&plan, &mut self.allocator);
        self.framebuffer_attachment_plans.push(plan);
        self.resolved_framebuffer_attachments.push(resolved);
    }

    pub fn consume_opengl_resolve_event(
        &mut self,
        event: DesktopGraphicsOpenGlBackendResolveEvent,
    ) {
        let resolve_index = self.resolve_commands.len();
        let source_attachment = opengl_backend_framebuffer_attachment_plan_for_render_target(
            &event.source_target,
        )
        .map(|plan| {
            self.cache
                .resolve_framebuffer_attachment(&plan, &mut self.allocator)
        });
        let command = DesktopGraphicsOpenGlBackendResolveCommand {
            source_target: event.source_target,
            resolve_target: event.resolve_target,
            resolve_kind: event.resolve_kind,
            resolve_sample: event.resolve_sample,
            resolve_sample_trace: event.resolve_sample.map(Into::into),
            resolve_sample_quad: event.resolve_sample.map(Into::into),
            source_attachment,
        };
        if let Some(program_key) = Self::resolve_draw_program_key(command.resolve_kind) {
            let shader_program_handle = self
                .cache
                .program_handle(program_key.to_string(), &mut self.allocator);
            let uses_sample_quad_mesh =
                command.uses_sample_quad_mesh() && command.source_attachment.is_some();
            let vertex_array_key = if uses_sample_quad_mesh {
                let vertex_array_key =
                    Self::resolve_sample_quad_vertex_array_key(resolve_index, &command);
                let quad = command
                    .resolve_sample_quad
                    .expect("sample quad mesh resolve should retain generated quad");
                let upload = DesktopGraphicsOpenGlBackendResolveMeshUploadPlan::from_quad(
                    resolve_index,
                    command.resolve_kind,
                    vertex_array_key.clone(),
                    quad,
                    program_key,
                    &mut self.location_cache,
                );
                self.consume_opengl_resolve_mesh_upload(upload);
                self.resolve_sample_quads.push(quad);
                vertex_array_key
            } else {
                Self::FULLSCREEN_QUAD_VERTEX_ARRAY_KEY.to_string()
            };
            let fullscreen_quad_vertex_array_handle = self
                .cache
                .vertex_array_handle(vertex_array_key, &mut self.allocator);
            self.resolve_draw_commands.extend(
                command.source_texture_sample_to_opengl_draw_commands(
                    shader_program_handle,
                    fullscreen_quad_vertex_array_handle,
                ),
            );
        }
        self.resolve_commands.push(command);
    }

    pub fn consume_opengl_texture_upload(
        &mut self,
        upload: DesktopGraphicsOpenGlBackendTextureUploadPlan,
    ) {
        let texture_identity_key = upload.texture_identity.key.clone();
        let texture_existed = upload.texture_identity.gl_handle.is_some()
            || self.cache.textures.contains_key(&texture_identity_key);
        let (previous_texture_handle, texture_handle) = if upload.recreate_texture {
            self.cache
                .replace_texture_handle(texture_identity_key, &mut self.allocator)
        } else {
            (
                None,
                self.cache
                    .texture_handle_for_identity(&upload.texture_identity, &mut self.allocator),
            )
        };
        let previous_texture_handle = previous_texture_handle
            .or(upload.texture_identity.gl_handle)
            .filter(|previous| *previous != texture_handle);
        let resolved_upload = DesktopGraphicsOpenGlBackendResolvedTextureUpload {
            texture_key: upload.texture_key,
            texture_handle,
            previous_texture_handle,
            texture_was_allocated: upload.recreate_texture || !texture_existed,
            resource_kind: upload.resource_kind,
            page_type: upload.page_type,
            page_source_path: upload.page_source_path,
            page_width: upload.page_width,
            page_height: upload.page_height,
            sampler: upload.sampler,
            generation: upload.generation,
            recreate_texture: upload.recreate_texture,
            dirty_pixels: upload.dirty_pixels,
            kind: upload.kind,
        };
        self.texture_upload_commands
            .extend(resolved_upload.to_opengl_texture_upload_commands());
        self.resolved_texture_uploads.push(resolved_upload);
    }

    pub fn consume_opengl_sprite_mesh_upload(
        &mut self,
        upload: DesktopGraphicsOpenGlBackendSpriteMeshUploadPlan,
    ) {
        let vertex_array_handle = self
            .cache
            .vertex_array_handle(upload.vertex_array_key.clone(), &mut self.allocator);
        let vertex_buffer_handle = self
            .cache
            .buffer_handle(upload.vertex_buffer_key.clone(), &mut self.allocator);
        let index_buffer_handle = self
            .cache
            .buffer_handle(upload.index_buffer_key.clone(), &mut self.allocator);
        let resolved_upload = DesktopGraphicsOpenGlBackendResolvedSpriteMeshUpload {
            batch_index: upload.batch_index,
            vertex_array_key: upload.vertex_array_key,
            vertex_array_handle,
            vertex_buffer_key: upload.vertex_buffer_key,
            vertex_buffer_handle,
            index_buffer_key: upload.index_buffer_key,
            index_buffer_handle,
            vertex_count: upload.vertex_count,
            index_count: upload.index_count,
            vertex_stride_bytes: upload.vertex_stride_bytes,
            vertex_attributes: upload.vertex_attributes,
            vertex_bytes: upload.vertex_bytes,
            index_bytes: upload.index_bytes,
        };
        self.sprite_mesh_upload_commands
            .extend(resolved_upload.to_opengl_sprite_mesh_upload_commands());
        self.resolved_sprite_mesh_uploads.push(resolved_upload);
    }

    pub fn consume_opengl_resolve_mesh_upload(
        &mut self,
        upload: DesktopGraphicsOpenGlBackendResolveMeshUploadPlan,
    ) {
        let vertex_array_handle = self
            .cache
            .vertex_array_handle(upload.vertex_array_key.clone(), &mut self.allocator);
        let vertex_buffer_handle = self
            .cache
            .buffer_handle(upload.vertex_buffer_key.clone(), &mut self.allocator);
        let index_buffer_handle = self
            .cache
            .buffer_handle(upload.index_buffer_key.clone(), &mut self.allocator);
        let resolved_upload = DesktopGraphicsOpenGlBackendResolvedResolveMeshUpload {
            resolve_index: upload.resolve_index,
            resolve_kind: upload.resolve_kind,
            vertex_array_key: upload.vertex_array_key,
            vertex_array_handle,
            vertex_buffer_key: upload.vertex_buffer_key,
            vertex_buffer_handle,
            index_buffer_key: upload.index_buffer_key,
            index_buffer_handle,
            vertex_count: upload.vertex_count,
            index_count: upload.index_count,
            vertex_stride_bytes: upload.vertex_stride_bytes,
            vertex_attributes: upload.vertex_attributes,
            vertex_bytes: upload.vertex_bytes,
            index_bytes: upload.index_bytes,
        };
        self.resolve_mesh_upload_commands
            .extend(resolved_upload.to_opengl_resolve_mesh_upload_commands());
        self.resolved_resolve_mesh_uploads.push(resolved_upload);
    }

    pub fn consume_opengl_shader_command(
        &mut self,
        command: DesktopGraphicsOpenGlBackendShaderCommand,
    ) {
        let resolved = self
            .cache
            .resolve_shader_command(command, &mut self.allocator);
        self.resolved_shader_commands.push(resolved);
    }

    pub fn consume_opengl_draw_command(
        &mut self,
        command: DesktopGraphicsOpenGlBackendDrawCommand,
    ) {
        self.draw_commands.push(command);
    }

    pub fn consume_opengl_sprite_draw_call(
        &mut self,
        draw_call: DesktopGraphicsOpenGlBackendSpriteDrawCallPlan,
    ) {
        let target = draw_call.target.clone();
        let blend_state = draw_call.blend_state;
        let clip = draw_call.clip;
        let mut recording = DesktopGraphicsRecordingOpenGlBackendDrawCallExecutor::default();
        recording.consume_opengl_sprite_draw_call(draw_call);
        for action in recording.actions {
            let resolved_action = self.cache.resolve_action(action, &mut self.allocator);
            self.draw_commands
                .extend(resolved_action.to_opengl_draw_commands());
            if matches!(
                resolved_action,
                DesktopGraphicsOpenGlBackendResolvedDrawCallAction::BindFramebuffer { .. }
            ) {
                self.draw_commands.extend(
                    opengl_backend_state_after_framebuffer_bind_to_draw_commands(
                        target.clone(),
                        blend_state,
                        clip,
                    ),
                );
            }
            self.resolved_draw_actions.push(resolved_action);
        }
    }

    pub fn drive_resolved_shader_command_sink<
        S: DesktopGraphicsOpenGlBackendResolvedShaderCommandSink,
    >(
        &self,
        sink: &mut S,
    ) -> usize {
        for command in &self.resolved_shader_commands {
            sink.consume_opengl_resolved_shader_command(command.clone());
        }
        self.resolved_shader_commands.len()
    }

    pub fn drive_framebuffer_attachment_sink<
        S: DesktopGraphicsOpenGlBackendFramebufferAttachmentSink,
    >(
        &self,
        sink: &mut S,
    ) -> usize {
        for plan in &self.framebuffer_attachment_plans {
            sink.consume_opengl_framebuffer_attachment(plan.clone());
        }
        self.framebuffer_attachment_plans.len()
    }

    pub fn drive_texture_upload_command_sink<
        S: DesktopGraphicsOpenGlBackendTextureUploadCommandSink,
    >(
        &self,
        sink: &mut S,
    ) -> usize {
        for command in &self.texture_upload_commands {
            sink.consume_opengl_texture_upload_command(command.clone());
        }
        self.texture_upload_commands.len()
    }

    pub fn drive_sprite_mesh_upload_command_sink<
        S: DesktopGraphicsOpenGlBackendSpriteMeshUploadCommandSink,
    >(
        &self,
        sink: &mut S,
    ) -> usize {
        for command in &self.sprite_mesh_upload_commands {
            sink.consume_opengl_sprite_mesh_upload_command(command.clone());
        }
        self.sprite_mesh_upload_commands.len()
    }

    pub fn drive_resolve_mesh_upload_command_sink<
        S: DesktopGraphicsOpenGlBackendResolveMeshUploadCommandSink,
    >(
        &self,
        sink: &mut S,
    ) -> usize {
        for command in &self.resolve_mesh_upload_commands {
            sink.consume_opengl_resolve_mesh_upload_command(command.clone());
        }
        self.resolve_mesh_upload_commands.len()
    }

    pub fn drive_draw_command_sink<S: DesktopGraphicsOpenGlBackendDrawCommandSink>(
        &self,
        sink: &mut S,
    ) -> usize {
        for command in &self.draw_commands {
            sink.consume_opengl_draw_command(command.clone());
        }
        self.draw_commands.len()
    }

    pub fn drive_resolve_command_sink<S: DesktopGraphicsOpenGlBackendResolveCommandSink>(
        &self,
        sink: &mut S,
    ) -> usize {
        for command in &self.resolve_commands {
            sink.consume_opengl_resolve_command(command.clone());
        }
        self.resolve_commands.len()
    }

    pub fn drive_resolve_draw_command_sink<S: DesktopGraphicsOpenGlBackendDrawCommandSink>(
        &self,
        sink: &mut S,
    ) -> usize {
        for command in &self.resolve_draw_commands {
            sink.consume_opengl_draw_command(command.clone());
        }
        self.resolve_draw_commands.len()
    }

    pub fn drive_driver<D: DesktopGraphicsOpenGlBackendDriver>(
        &self,
        driver: &mut D,
    ) -> DesktopGraphicsOpenGlBackendDriverExecutionState {
        let mut state = DesktopGraphicsOpenGlBackendDriverExecutionState::default();
        state.framebuffer_attachment_plans = self.drive_framebuffer_attachment_sink(driver);
        state.texture_upload_commands = self.drive_texture_upload_command_sink(driver);
        state.sprite_mesh_upload_commands = self.drive_sprite_mesh_upload_command_sink(driver);
        state.resolve_mesh_upload_commands = self.drive_resolve_mesh_upload_command_sink(driver);
        state.shader_commands = self.drive_resolved_shader_command_sink(driver);
        state.draw_commands = self.drive_draw_command_sink(driver);
        state.resolve_draw_commands = self.drive_resolve_draw_command_sink(driver);
        state.resolve_commands = self.drive_resolve_command_sink(driver);
        state
    }
}

