    pub fn background_render_pass(&self, camera: RenderCamera) -> Option<RenderPass> {
        if self.game_state.rules.background_texture.is_none()
            && self.game_state.rules.custom_background_callback.is_none()
        {
            return None;
        }

        let mut pass = RenderPass::new(RenderPassKind::Background)
            .with_target(RenderTarget::Buffer("background-buffer".into()))
            .with_resolve(RenderTarget::Screen, RenderResolveKind::DrawRectSample)
            .with_resolve_sample(RenderTextureSamplePlan::background_buffer_geometry_flip(
                camera,
            ));
        pass.push(RenderCommand::custom(
            "background-buffer-render",
            vec![
                RenderProperty::new(
                    "texture",
                    self.game_state
                        .rules
                        .background_texture
                        .as_deref()
                        .unwrap_or(""),
                ),
                RenderProperty::new(
                    "callback",
                    self.game_state
                        .rules
                        .custom_background_callback
                        .as_deref()
                        .unwrap_or(""),
                ),
                RenderProperty::new("speed", self.game_state.rules.background_speed.to_string()),
                RenderProperty::new("scale", self.game_state.rules.background_scl.to_string()),
                RenderProperty::new(
                    "offset_x",
                    self.game_state.rules.background_offset_x.to_string(),
                ),
                RenderProperty::new(
                    "offset_y",
                    self.game_state.rules.background_offset_y.to_string(),
                ),
            ],
        ));
        Some(pass)
    }

    fn desktop_ui_status_bar_model(&self) -> Option<(String, f32, u32)> {
        let connect_error = self.connect_error.as_deref();
        let connected = {
            let state = self.net_client.state();
            let state = state.lock().unwrap();
            state.connected
        };
        if !connected && connect_error.is_none() && self.connect_target.is_none() {
            return None;
        }

        if let Some(error) = connect_error {
            return Some((format!("connect error: {error}"), 0.0, 0xff55_55ff));
        }

        if !connected {
            return Some(("connecting".to_string(), 0.1, 0xffd3_7fff));
        }

        let status = self.playable_smoke_status();
        let checks = [
            status.client_ready,
            status.connected,
            status.world_loaded,
            status.confirmed,
            status.game_playing,
            status.runtime_client,
            status.world_width > 0 && status.world_height > 0,
            status.buildings > 0,
            status.player_on_default_team,
        ];
        let ready = checks.iter().filter(|ready| **ready).count();
        let total = checks.len();
        let fraction = ready as f32 / total as f32;
        let label = if status.ready() {
            "client ready".to_string()
        } else {
            format!("client sync {ready}/{total}")
        };
        let color = if status.ready() {
            0x84f4_91ff
        } else {
            0xffd3_7fff
        };
        Some((label, fraction, color))
    }

    pub fn desktop_ui_render_pass(&mut self, viewport: RenderViewport) -> Option<RenderPass> {
        let (label, fraction, color) = self.desktop_ui_status_bar_model()?;
        self.ui_status_bar.set_name(label);
        self.ui_status_bar.set_fraction(fraction);
        self.ui_status_bar.set_color(color);
        self.ui_status_bar.set_blink_color(0xffff_ffff);
        self.ui_status_bar.outline(0x0000_00ff, 1.0);

        let width = viewport.width.min(260.0).max(96.0);
        let layout = BarLayout {
            x: viewport.x + 12.0,
            y: viewport.y + viewport.height - 28.0,
            width,
            height: 16.0,
            parent_alpha: 1.0,
            label_width: width,
            label_height: 12.0,
            top_min_width: 1.0,
        };
        let plan = self.ui_status_bar.draw_plan(layout)?;
        let mut pass = RenderPass::new(RenderPassKind::Ui);
        push_bar_draw_plan_as_ui_commands(&mut pass, &plan, Layer::END);
        Some(pass)
    }

    pub fn minimap_overlay_plan(
        &mut self,
        camera: MinimapCamera,
        input: MinimapOverlayInput,
    ) -> MinimapOverlayPlan {
        let world = self.current_minimap_world_size();
        if world.width <= 0 || world.height <= 0 {
            return MinimapOverlayPlan {
                world_rect: MinimapRect::new(0.0, 0.0, 0.0, 0.0),
                scale_factor: 0.0,
                commands: Vec::new(),
            };
        }

        if self.minimap_renderer_state.world != world {
            self.minimap_renderer_state.reset(world);
        }

        self.minimap_renderer_state.overlay_plan(camera, input)
    }

    pub fn minimap_texture_frame_plan(&mut self) -> Option<MinimapTextureFramePlan> {
        let world = self.current_minimap_world_size();
        if world.width <= 0 || world.height <= 0 {
            return None;
        }
        if self.minimap_renderer_state.world != world {
            return Some(
                self.minimap_renderer_state
                    .reset(world)
                    .texture_frame_plan(),
            );
        }

        self.minimap_renderer_state.texture_frame_plan()
    }

