    fn push_settings_route_controls(&self, pass: &mut RenderPass, panel: RenderRect) {
        let (DesktopSettingsPage::Game
        | DesktopSettingsPage::Graphics
        | DesktopSettingsPage::Sound) = self.settings_dialog_state.page
        else {
            return;
        };
        let table = self.settings_dialog_state.page.key();
        let pane_symbol = Self::settings_drawable_symbol("pane");
        let track_symbol = Self::settings_slider_track_symbol();
        let scroll_track_symbol = Self::settings_scroll_track_symbol();
        let scroll_knob_symbol = Self::settings_scroll_knob_symbol();
        let specs = Self::settings_pref_widget_specs(table);
        let clip = Self::settings_pref_widget_clip_rect_for_panel(panel);
        let scroll_offset = self.settings_scroll_offset_pixels(table, clip);

        pass.push(RenderCommand::set_clip(clip));
        for (index, spec) in specs.iter().copied().enumerate() {
            let control_id = DesktopSettingsControlId::new(spec.table, spec.key);
            let hovered = self.last_settings_hovered_control == Some(control_id);
            let pressed = self.last_settings_pressed_control == Some(control_id);
            let row = Self::settings_pref_widget_row_rect_for_clip_with_scroll(
                clip,
                index,
                scroll_offset,
            );
            pass.push(RenderCommand::draw_sprite(
                pane_symbol.clone(),
                row,
                if pressed {
                    [0.88, 0.94, 1.0, 0.95]
                } else if hovered {
                    [1.0, 1.0, 1.0, 0.92]
                } else {
                    [1.0, 1.0, 1.0, 0.82]
                },
                0.0,
                Layer::END_PIXELED + 0.025,
            ));
            pass.push(RenderCommand::stroke_rect(
                row,
                [0.25, 0.42, 0.52, 0.72],
                1.0,
                Layer::END_PIXELED + 0.026,
            ));
            match spec.kind {
                DesktopSettingsPrefKind::Check => {
                    let checked = self.setting_bool_effective_value(spec);
                    let control = Self::settings_pref_widget_check_box_rect(row);
                    let label_point = Self::settings_pref_widget_check_label_point(row);
                    pass.push(RenderCommand::draw_text_styled(
                        Self::settings_pref_label(spec.key),
                        label_point,
                        [0.82, 0.9, 0.96, 1.0],
                        12.0,
                        0.0,
                        RenderTextStyle::new(RenderTextAlign::Start)
                            .with_vertical_align(RenderTextVerticalAlign::Center)
                            .with_integer_position(true),
                        Layer::END_PIXELED + 0.03,
                    ));
                    pass.push(RenderCommand::draw_sprite(
                        Self::settings_check_box_symbol(checked, hovered, pressed),
                        control,
                        [1.0, 1.0, 1.0, 1.0],
                        0.0,
                        Layer::END_PIXELED + 0.032,
                    ));
                }
                DesktopSettingsPrefKind::Slider => {
                    let Some(range) = spec.range_step else {
                        continue;
                    };
                    let value = self
                        .setting_slider_effective_value(spec)
                        .unwrap_or(range.min)
                        .clamp(range.min, range.max);
                    let track = Self::settings_pref_widget_slider_track_rect(row);
                    let t = if range.max > range.min {
                        (value - range.min) as f32 / (range.max - range.min) as f32
                    } else {
                        0.0
                    }
                    .clamp(0.0, 1.0);
                    let stack = Self::settings_pref_widget_slider_stack_rect(row);
                    let content = Self::settings_pref_widget_slider_content_rect(stack);
                    let knob_size = 24.0;
                    let knob = RenderRect::new(
                        track.x + t * track.width - knob_size * 0.5,
                        row.y + row.height * 0.5 - knob_size * 0.5,
                        knob_size,
                        knob_size,
                    );
                    pass.push(RenderCommand::draw_sprite(
                        track_symbol.clone(),
                        track,
                        [1.0, 1.0, 1.0, 1.0],
                        0.0,
                        Layer::END_PIXELED + 0.032,
                    ));
                    pass.push(RenderCommand::draw_sprite(
                        Self::settings_slider_knob_symbol(hovered, pressed),
                        knob,
                        [1.0, 1.0, 1.0, 1.0],
                        0.0,
                        Layer::END_PIXELED + 0.033,
                    ));
                    pass.push(RenderCommand::draw_text_styled(
                        Self::settings_pref_label(spec.key),
                        RenderPoint::new(content.x, row.y + row.height * 0.5),
                        [0.82, 0.9, 0.96, 1.0],
                        12.0,
                        0.0,
                        RenderTextStyle::new(RenderTextAlign::Start)
                            .with_vertical_align(RenderTextVerticalAlign::Center)
                            .with_integer_position(true),
                        Layer::END_PIXELED + 0.034,
                    ));
                    pass.push(RenderCommand::draw_text_styled(
                        format!("value: {value}"),
                        RenderPoint::new(content.right(), row.y + row.height * 0.5),
                        [0.72, 0.84, 0.9, 1.0],
                        11.0,
                        0.0,
                        RenderTextStyle::new(RenderTextAlign::End)
                            .with_vertical_align(RenderTextVerticalAlign::Center)
                            .with_integer_position(true),
                        Layer::END_PIXELED + 0.035,
                    ));
                }
            }
        }
        pass.push(RenderCommand::clear_clip());
        Self::push_settings_scrollbar(
            pass,
            clip,
            specs.len(),
            scroll_offset,
            scroll_track_symbol,
            scroll_knob_symbol,
        );
    }

    fn settings_route_control_action_at_point(
        &self,
        panel: RenderRect,
        point: RenderPoint,
    ) -> Option<DesktopSettingsAction> {
        let (DesktopSettingsPage::Game
        | DesktopSettingsPage::Graphics
        | DesktopSettingsPage::Sound) = self.settings_dialog_state.page
        else {
            return None;
        };
        let table = self.settings_dialog_state.page.key();
        let clip = Self::settings_pref_widget_clip_rect_for_panel(panel);
        let scroll_offset = self.settings_scroll_offset_pixels(table, clip);
        if !clip.contains_point(point) {
            return None;
        }
        for (index, spec) in Self::settings_pref_widget_specs(table)
            .iter()
            .copied()
            .enumerate()
        {
            let row = Self::settings_pref_widget_row_rect_for_clip_with_scroll(
                clip,
                index,
                scroll_offset,
            );
            if !row.contains_point(point) {
                continue;
            }
            match spec.kind {
                DesktopSettingsPrefKind::Check => {
                    let hit = Self::settings_pref_widget_check_hit_rect(row);
                    if !hit.contains_point(point) {
                        continue;
                    }
                    return Some(DesktopSettingsAction::ToggleSetting(spec.table, spec.key));
                }
                DesktopSettingsPrefKind::Slider => {
                    let stack = Self::settings_pref_widget_slider_stack_rect(row);
                    if !stack.contains_point(point) {
                        continue;
                    }
                    let range = spec.range_step?;
                    let track = Self::settings_pref_widget_slider_track_rect(row);
                    let value = Self::settings_slider_value_from_track_x(range, track, point.x);
                    return Some(DesktopSettingsAction::SetSliderValue(
                        spec.table, spec.key, value,
                    ));
                }
            };
        }
        None
    }

    fn settings_control_id_from_action(
        action: DesktopSettingsAction,
    ) -> Option<DesktopSettingsControlId> {
        match action {
            DesktopSettingsAction::ToggleSetting(table, key)
            | DesktopSettingsAction::SetSliderValue(table, key, _) => {
                Some(DesktopSettingsControlId::new(table, key))
            }
            _ => None,
        }
    }

    fn settings_control_id_at_surface_point(
        &self,
        surface_size: DesktopSurfaceSize,
        x: f32,
        y: f32,
    ) -> Option<DesktopSettingsControlId> {
        if self.active_menu_route != Some(DesktopMenuRoute::Settings) {
            return None;
        }
        let viewport = self.default_render_viewport_for_surface(surface_size);
        let panel =
            Self::active_menu_route_shell_panel_for_route(viewport, DesktopMenuRoute::Settings);
        let point = RenderPoint::new(x, y);
        self.settings_route_control_action_at_point(panel, point)
            .and_then(Self::settings_control_id_from_action)
    }

    fn settings_drag_action_at_surface_point(
        &self,
        surface_size: DesktopSurfaceSize,
        x: f32,
        _y: f32,
    ) -> Option<DesktopSettingsAction> {
        if self.active_menu_route != Some(DesktopMenuRoute::Settings) {
            return None;
        }
        let pressed = self.last_settings_pressed_control?;
        let (DesktopSettingsPage::Game
        | DesktopSettingsPage::Graphics
        | DesktopSettingsPage::Sound) = self.settings_dialog_state.page
        else {
            return None;
        };
        let table = self.settings_dialog_state.page.key();
        if pressed.table != table {
            return None;
        }
        let spec = settings_pref_spec(pressed.table, pressed.key)?;
        if spec.kind != DesktopSettingsPrefKind::Slider {
            return None;
        }
        let range = spec.range_step?;
        let viewport = self.default_render_viewport_for_surface(surface_size);
        let panel =
            Self::active_menu_route_shell_panel_for_route(viewport, DesktopMenuRoute::Settings);
        let clip = Self::settings_pref_widget_clip_rect_for_panel(panel);
        let scroll_offset = self.settings_scroll_offset_pixels(table, clip);
        let index = Self::settings_pref_widget_specs(table)
            .iter()
            .position(|candidate| candidate.table == spec.table && candidate.key == spec.key)?;
        let row =
            Self::settings_pref_widget_row_rect_for_clip_with_scroll(clip, index, scroll_offset);
        let track = Self::settings_pref_widget_slider_track_rect(row);
        let value = Self::settings_slider_value_from_track_x(range, track, x);
        Some(DesktopSettingsAction::SetSliderValue(
            spec.table, spec.key, value,
        ))
    }

    fn settings_scrollbar_drag_state_at_surface_point(
        &self,
        surface_size: DesktopSurfaceSize,
        x: f32,
        y: f32,
    ) -> Option<DesktopSettingsScrollDragState> {
        if self.active_menu_route != Some(DesktopMenuRoute::Settings) {
            return None;
        }
        let (DesktopSettingsPage::Game
        | DesktopSettingsPage::Graphics
        | DesktopSettingsPage::Sound) = self.settings_dialog_state.page
        else {
            return None;
        };
        let table = self.settings_dialog_state.page.key();
        let viewport = self.default_render_viewport_for_surface(surface_size);
        let panel =
            Self::active_menu_route_shell_panel_for_route(viewport, DesktopMenuRoute::Settings);
        let clip = Self::settings_pref_widget_clip_rect_for_panel(panel);
        let row_count = Self::settings_pref_widget_specs(table).len();
        let scroll_offset = self.settings_scroll_offset_pixels(table, clip);
        let knob = Self::settings_scrollbar_knob_rect_for_clip(clip, row_count, scroll_offset)?;
        let point = RenderPoint::new(x, y);
        if knob.contains_point(point) {
            Some(DesktopSettingsScrollDragState::new(table, y - knob.y))
        } else {
            None
        }
    }

    fn apply_settings_scrollbar_drag(&mut self, surface_size: DesktopSurfaceSize, y: f32) -> bool {
        let Some(drag_state) = self.settings_scroll_drag_state else {
            return false;
        };
        if self.active_menu_route != Some(DesktopMenuRoute::Settings) {
            return false;
        }
        let (DesktopSettingsPage::Game
        | DesktopSettingsPage::Graphics
        | DesktopSettingsPage::Sound) = self.settings_dialog_state.page
        else {
            return false;
        };
        let table = self.settings_dialog_state.page.key();
        if drag_state.table != table {
            return false;
        }
        let viewport = self.default_render_viewport_for_surface(surface_size);
        let panel =
            Self::active_menu_route_shell_panel_for_route(viewport, DesktopMenuRoute::Settings);
        let clip = Self::settings_pref_widget_clip_rect_for_panel(panel);
        let row_count = Self::settings_pref_widget_specs(table).len();
        let max = Self::settings_max_scroll_offset_for_clip(clip, row_count);
        if max <= 0 {
            return false;
        }
        let Some(knob) = Self::settings_scrollbar_knob_rect_for_clip(
            clip,
            row_count,
            self.settings_scroll_offset_pixels(table, clip),
        ) else {
            return false;
        };
        let travel = (clip.height - knob.height).max(0.0);
        if travel <= f32::EPSILON {
            return false;
        }
        let knob_y =
            (y - drag_state.grab_offset_y).clamp(clip.y, clip.y + clip.height - knob.height);
        let raw_scroll = ((clip.y + clip.height - knob.height - knob_y) / travel) * max as f32;
        let next = raw_scroll.round().clamp(0.0, max as f32) as i32;
        self.settings_scroll_offsets.insert(table, next);
        true
    }

    fn apply_settings_scroll_delta(
        &mut self,
        surface_size: DesktopSurfaceSize,
        delta_y: f32,
    ) -> bool {
        let (DesktopSettingsPage::Game
        | DesktopSettingsPage::Graphics
        | DesktopSettingsPage::Sound) = self.settings_dialog_state.page
        else {
            return false;
        };
        if self.active_menu_route != Some(DesktopMenuRoute::Settings) {
            return false;
        }
        let Some(cursor) = self.last_menu_cursor else {
            return false;
        };
        let viewport = self.default_render_viewport_for_surface(surface_size);
        let panel =
            Self::active_menu_route_shell_panel_for_route(viewport, DesktopMenuRoute::Settings);
        let clip = Self::settings_pref_widget_clip_rect_for_panel(panel);
        if !clip.contains_point(cursor) {
            return false;
        }
        let table = self.settings_dialog_state.page.key();
        let row_count = Self::settings_pref_widget_specs(table).len();
        let max = Self::settings_max_scroll_offset_for_clip(clip, row_count);
        if max <= 0 {
            return false;
        }
        let current = self
            .settings_scroll_offsets
            .get(table)
            .copied()
            .unwrap_or(0);
        let delta = (-delta_y * 40.0).round() as i32;
        let next = (current + delta).clamp(0, max);
        self.settings_scroll_offsets.insert(table, next);
        true
    }

    fn settings_route_lines(&self) -> Vec<String> {
        let state = &self.settings_dialog_state;
        let mut lines = vec![
            format!("settings page: {}", state.page.key()),
            "style: Tex.button / Styles.flatt".into(),
        ];

        match state.page {
            DesktopSettingsPage::Main => {
                lines.push(format!("categories: {}", SETTINGS_MENU_ENTRIES.len()));
                for entry in SETTINGS_MENU_ENTRIES {
                    lines.push(format!(
                        "category: {} {} target:{}",
                        entry.label,
                        Self::settings_icon_line(entry.icon),
                        entry.target
                    ));
                }
                for table in ["game", "graphics", "sound"] {
                    if let Some(highlights) = settings_pref_highlight_summary_line(table) {
                        lines.push(format!(
                            "pref table: {table} settings: {} critical: {highlights}",
                            settings_pref_count(table)
                        ));
                    }
                }
                lines.push(format!("data actions: {}", SETTINGS_DATA_ACTIONS.len()));
            }
            DesktopSettingsPage::Game
            | DesktopSettingsPage::Graphics
            | DesktopSettingsPage::Sound => {
                let table = state.page.key();
                lines.push(format!(
                    "table: {table} settings: {}",
                    settings_pref_count(table)
                ));
                if let Some(highlights) = settings_pref_highlight_summary_line(table) {
                    for highlight in highlights.split(" | ") {
                        lines.push(format!("critical: {highlight}"));
                    }
                }
                lines.push("button: reset-to-defaults".into());
                lines.push("button: back".into());
            }
            DesktopSettingsPage::Data => {
                lines.push(format!("planet: {}", state.selected_planet));
                for action in SETTINGS_DATA_ACTIONS {
                    lines.push(format!(
                        "data action: {} {}",
                        action.label,
                        Self::settings_icon_line(action.icon)
                    ));
                }
                lines.push("button: back".into());
            }
        }

        lines
    }

    fn settings_route_line_rect_for_panel(panel: RenderRect, line_index: usize) -> RenderRect {
        let center_y = panel.y + panel.height - 118.0 - line_index as f32 * 20.0;
        RenderRect::new(panel.x + 22.0, center_y - 9.0, panel.width - 44.0, 18.0)
    }

    fn settings_main_menu_button_rect_for_panel(panel: RenderRect, index: usize) -> RenderRect {
        let x = panel.x + 36.0 + SETTINGS_MENU_BUTTON_MARGIN_LEFT;
        let top = panel.y + panel.height - 124.0 - index as f32 * SETTINGS_MENU_BUTTON_HEIGHT;
        RenderRect::new(
            x,
            top - SETTINGS_MENU_BUTTON_HEIGHT,
            SETTINGS_MENU_BUTTON_WIDTH,
            SETTINGS_MENU_BUTTON_HEIGHT,
        )
    }

    fn settings_main_menu_entry_index_at_point(
        panel: RenderRect,
        point: RenderPoint,
    ) -> Option<usize> {
        SETTINGS_MENU_ENTRIES
            .iter()
            .enumerate()
            .find(|(index, _)| {
                Self::settings_main_menu_button_rect_for_panel(panel, *index).contains_point(point)
            })
            .map(|(index, _)| index)
    }

    fn settings_reset_button_rect_for_panel(panel: RenderRect) -> RenderRect {
        RenderRect::new(
            panel.x + (panel.width - SETTINGS_RESET_BUTTON_WIDTH) * 0.5,
            panel.y + SETTINGS_BACK_BUTTON_HEIGHT + 30.0,
            SETTINGS_RESET_BUTTON_WIDTH,
            SETTINGS_RESET_BUTTON_HEIGHT,
        )
    }

    fn settings_back_button_rect_for_panel(panel: RenderRect) -> RenderRect {
        RenderRect::new(
            panel.x + (panel.width - SETTINGS_BACK_BUTTON_WIDTH) * 0.5,
            panel.y + 18.0,
            SETTINGS_BACK_BUTTON_WIDTH,
            SETTINGS_BACK_BUTTON_HEIGHT,
        )
    }

    fn settings_action_for_main_entry(index: usize) -> Option<DesktopSettingsAction> {
        match index {
            0 => Some(DesktopSettingsAction::OpenPage(DesktopSettingsPage::Game)),
            1 => Some(DesktopSettingsAction::OpenPage(
                DesktopSettingsPage::Graphics,
            )),
            2 => Some(DesktopSettingsAction::OpenPage(DesktopSettingsPage::Sound)),
            3 => Some(DesktopSettingsAction::OpenLanguageDialog),
            4 => Some(DesktopSettingsAction::OpenControlsDialog),
            5 => Some(DesktopSettingsAction::OpenPage(DesktopSettingsPage::Data)),
            _ => None,
        }
    }

    fn settings_route_action_for_line(&self, line_index: usize) -> Option<DesktopSettingsAction> {
        match self.settings_dialog_state.page {
            DesktopSettingsPage::Main => line_index
                .checked_sub(3)
                .and_then(Self::settings_action_for_main_entry),
            DesktopSettingsPage::Data => {
                if let Some(action_index) = line_index.checked_sub(3) {
                    if let Some(action) = SETTINGS_DATA_ACTIONS.get(action_index) {
                        return Some(action.action);
                    }
                    if action_index == SETTINGS_DATA_ACTIONS.len() {
                        return Some(DesktopSettingsAction::BackToMain);
                    }
                }
                None
            }
            DesktopSettingsPage::Game
            | DesktopSettingsPage::Graphics
            | DesktopSettingsPage::Sound => {
                let table = self.settings_dialog_state.page.key();
                let reset_line = 3 + settings_pref_highlight_keys(table).len();
                let back_line = reset_line + 1;
                if line_index == reset_line {
                    Some(DesktopSettingsAction::ResetCurrentPage)
                } else if line_index == back_line {
                    Some(DesktopSettingsAction::BackToMain)
                } else {
                    None
                }
            }
        }
    }

    fn settings_child_dialog_rect_for_panel(panel: RenderRect) -> RenderRect {
        Self::schematic_info_dialog_rect_for_panel(panel)
    }

    fn settings_child_dialog_title(dialog: DesktopSettingsChildDialog) -> &'static str {
        match dialog {
            DesktopSettingsChildDialog::Language => "@settings.language",
            DesktopSettingsChildDialog::Controls => "@settings.controls",
        }
    }

    fn settings_child_dialog_summary(dialog: DesktopSettingsChildDialog) -> &'static str {
        match dialog {
            DesktopSettingsChildDialog::Language => {
                "LanguageDialog placeholder: locale list and bundle reload later"
            }
            DesktopSettingsChildDialog::Controls => {
                "ControlsDialog placeholder: keybind rows and reset later"
            }
        }
    }

    fn settings_child_dialog_action_at_point(
        &self,
        panel: RenderRect,
        point: RenderPoint,
    ) -> Option<DesktopMenuRouteShellAction> {
        self.settings_child_dialog?;
        let dialog = Self::settings_child_dialog_rect_for_panel(panel);
        if Self::schematic_info_button_rect(dialog, 0).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::Settings(
                DesktopSettingsAction::CloseChildDialog,
            ));
        }
        None
    }

    fn settings_route_shell_action_at_surface_point(
        &self,
        surface_size: DesktopSurfaceSize,
        x: f32,
        y: f32,
    ) -> Option<DesktopMenuRouteShellAction> {
        if self.active_menu_route != Some(DesktopMenuRoute::Settings) {
            return None;
        }
        let viewport = self.default_render_viewport_for_surface(surface_size);
        let panel =
            Self::active_menu_route_shell_panel_for_route(viewport, DesktopMenuRoute::Settings);
        let point = RenderPoint::new(x, y);
        if self.settings_child_dialog.is_some() {
            return self.settings_child_dialog_action_at_point(panel, point);
        }
        if self.settings_dialog_state.page == DesktopSettingsPage::Main {
            if let Some(index) = Self::settings_main_menu_entry_index_at_point(panel, point) {
                return Self::settings_action_for_main_entry(index)
                    .map(DesktopMenuRouteShellAction::Settings);
            }
        }
        if matches!(
            self.settings_dialog_state.page,
            DesktopSettingsPage::Game | DesktopSettingsPage::Graphics | DesktopSettingsPage::Sound
        ) && Self::settings_reset_button_rect_for_panel(panel).contains_point(point)
        {
            return Some(DesktopMenuRouteShellAction::Settings(
                DesktopSettingsAction::ResetCurrentPage,
            ));
        }
        if self.settings_dialog_state.page != DesktopSettingsPage::Main
            && Self::settings_back_button_rect_for_panel(panel).contains_point(point)
        {
            return Some(DesktopMenuRouteShellAction::Settings(
                DesktopSettingsAction::BackToMain,
            ));
        }
        if let Some(action) = self.settings_route_control_action_at_point(panel, point) {
            return Some(DesktopMenuRouteShellAction::Settings(action));
        }
        self.settings_route_lines()
            .iter()
            .enumerate()
            .find(|(line_index, _)| {
                Self::settings_route_line_rect_for_panel(panel, *line_index).contains_point(point)
            })
            .and_then(|(line_index, _)| self.settings_route_action_for_line(line_index))
            .map(DesktopMenuRouteShellAction::Settings)
    }

    fn load_game_slot_line_rect_for_viewport(
        viewport: RenderViewport,
        slot_index: usize,
    ) -> RenderRect {
        let panel =
            Self::active_menu_route_shell_panel_for_route(viewport, DesktopMenuRoute::LoadGame);
        Self::load_game_slot_card_rect_for_panel(panel, slot_index)
    }

    fn load_game_search_rect_for_panel(panel: RenderRect) -> RenderRect {
        RenderRect::new(
            panel.x + 28.0,
            panel.y + panel.height - 128.0,
            panel.width - 56.0,
            LOAD_SEARCH_BAR_HEIGHT,
        )
    }

    fn load_game_slot_card_rect_for_panel(panel: RenderRect, slot_index: usize) -> RenderRect {
        let search = Self::load_game_search_rect_for_panel(panel);
        let top =
            search.y - 16.0 - slot_index as f32 * (LOAD_SLOT_CARD_HEIGHT + LOAD_SLOT_CARD_GAP);
        RenderRect::new(
            panel.x + 28.0,
            top - LOAD_SLOT_CARD_HEIGHT,
            panel.width - 56.0,
            LOAD_SLOT_CARD_HEIGHT,
        )
    }

    fn load_game_slot_at_surface_point(
        &self,
        surface_size: DesktopSurfaceSize,
        x: f32,
        y: f32,
    ) -> Option<usize> {
        if self.active_menu_route != Some(DesktopMenuRoute::LoadGame) {
            return None;
        }
        let viewport = self.default_render_viewport_for_surface(surface_size);
        let point = RenderPoint::new(x, y);
        self.load_game_slots
            .iter()
            .take(4)
            .enumerate()
            .find(|(index, _)| {
                Self::load_game_slot_line_rect_for_viewport(viewport, *index).contains_point(point)
            })
            .map(|(index, _)| index)
    }

    fn dispatch_load_game_slot_action(
        &mut self,
        slot_index: usize,
    ) -> Option<DesktopLoadGameAction> {
        let slot = self.load_game_slots.get(slot_index)?;
        let action = DesktopLoadGameAction {
            slot: slot.index(),
            file: slot.file.display().to_string(),
            map_name: slot.meta.as_ref().and_then(|meta| meta.map_name.clone()),
            timestamp: slot.timestamp(),
            status: "selected-for-load".into(),
        };
        self.last_load_game_action = Some(action.clone());
        Some(action)
    }

    fn active_menu_route_shell_panel_for_viewport(viewport: RenderViewport) -> RenderRect {
        let panel_width = (viewport.width * 0.46).clamp(280.0, 520.0);
        let panel_height = 220.0;
        RenderRect::new(
            viewport.x + viewport.width - panel_width - 48.0,
            viewport.y + (viewport.height - panel_height) * 0.5,
            panel_width,
            panel_height,
        )
    }

    fn active_menu_route_shell_panel_for_route(
        viewport: RenderViewport,
        route: DesktopMenuRoute,
    ) -> RenderRect {
        if route == DesktopMenuRoute::About {
            let panel_width = (viewport.width * 0.72).clamp(360.0, 720.0);
            let panel_height = (viewport.height - 120.0).clamp(360.0, 700.0);
            return RenderRect::new(
                viewport.x + viewport.width - panel_width - 48.0,
                viewport.y + (viewport.height - panel_height) * 0.5,
                panel_width,
                panel_height,
            );
        }
        if route == DesktopMenuRoute::Settings {
            let panel_width = (viewport.width * 0.62).clamp(340.0, 680.0);
            let panel_height = (viewport.height - 150.0).clamp(300.0, 560.0);
            return RenderRect::new(
                viewport.x + viewport.width - panel_width - 48.0,
                viewport.y + (viewport.height - panel_height) * 0.5,
                panel_width,
                panel_height,
            );
        }
        if route == DesktopMenuRoute::Database {
            let panel_width = (viewport.width * 0.68).clamp(380.0, 760.0);
            let panel_height = (viewport.height - 130.0).clamp(330.0, 620.0);
            return RenderRect::new(
                viewport.x + viewport.width - panel_width - 48.0,
                viewport.y + (viewport.height - panel_height) * 0.5,
                panel_width,
                panel_height,
            );
        }
        if matches!(
            route,
            DesktopMenuRoute::CustomGame | DesktopMenuRoute::Editor
        ) {
            let panel_width = (viewport.width * 0.66).clamp(380.0, 740.0);
            let panel_height = (viewport.height - 130.0).clamp(330.0, 600.0);
            return RenderRect::new(
                viewport.x + viewport.width - panel_width - 48.0,
                viewport.y + (viewport.height - panel_height) * 0.5,
                panel_width,
                panel_height,
            );
        }
        if route == DesktopMenuRoute::Schematics {
            let panel_width = (viewport.width * 0.66).clamp(380.0, 740.0);
            let panel_height = (viewport.height - 80.0).clamp(430.0, 700.0);
            return RenderRect::new(
                viewport.x + viewport.width - panel_width - 48.0,
                viewport.y + (viewport.height - panel_height) * 0.5,
                panel_width,
                panel_height,
            );
        }
        if route == DesktopMenuRoute::Mods {
            let panel_width = (viewport.width * 0.68).clamp(380.0, 760.0);
            let panel_height = (viewport.height - 120.0).clamp(360.0, 640.0);
            return RenderRect::new(
                viewport.x + viewport.width - panel_width - 48.0,
                viewport.y + (viewport.height - panel_height) * 0.5,
                panel_width,
                panel_height,
            );
        }
        Self::active_menu_route_shell_panel_for_viewport(viewport)
    }

    fn about_link_card_rect_for_panel(panel: RenderRect, index: usize) -> RenderRect {
        let columns = if panel.width >= 340.0 { 2usize } else { 1usize };
        let gap = 8.0;
        let outer_pad = 22.0;
        let card_height = 54.0;
        let usable_width = panel.width - outer_pad * 2.0 - gap * (columns.saturating_sub(1)) as f32;
        let card_width = usable_width / columns as f32;
        let col = index % columns;
        let row = index / columns;
        let top = panel.y + panel.height - 134.0;
        RenderRect::new(
            panel.x + outer_pad + col as f32 * (card_width + gap),
            top - card_height - row as f32 * (card_height + gap),
            card_width,
            card_height,
        )
    }

