    fn schematic_modal_action_at_point(
        &self,
        panel: RenderRect,
        point: RenderPoint,
    ) -> Option<DesktopMenuRouteShellAction> {
        let modal = self.schematic_modal?;
        let dialog = Self::schematic_info_dialog_rect_for_panel(panel);
        match modal {
            DesktopSchematicModal::Info { .. } => self.schematic_info_action_at_point(panel, point),
            DesktopSchematicModal::Import => {
                for (index, button) in [
                    DesktopSchematicModalButton::ImportClipboard,
                    DesktopSchematicModalButton::ImportFile,
                    DesktopSchematicModalButton::BrowseWorkshop,
                ]
                .into_iter()
                .enumerate()
                {
                    if Self::schematic_modal_option_button_rect(dialog, index).contains_point(point)
                    {
                        return Some(DesktopMenuRouteShellAction::SchematicModalButton(button));
                    }
                }
                if Self::schematic_info_button_rect(dialog, 0).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                        DesktopSchematicModalButton::Back,
                    ));
                }
                None
            }
            DesktopSchematicModal::Tags => {
                let tags = self.schematics_tag_names();
                for (index, _) in tags.iter().enumerate() {
                    let row = Self::schematic_tag_editor_row_rect(dialog, index);
                    if Self::schematic_tag_editor_move_up_rect(row).contains_point(point) {
                        return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                            DesktopSchematicModalButton::TagMoveUp(index),
                        ));
                    }
                    if Self::schematic_tag_editor_move_down_rect(row).contains_point(point) {
                        return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                            DesktopSchematicModalButton::TagMoveDown(index),
                        ));
                    }
                    if Self::schematic_tag_editor_select_rect(row).contains_point(point) {
                        return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                            DesktopSchematicModalButton::TagSelect(index),
                        ));
                    }
                    if Self::schematic_tag_editor_rename_rect(row).contains_point(point) {
                        return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                            DesktopSchematicModalButton::TagRename(index),
                        ));
                    }
                    if Self::schematic_tag_editor_delete_rect(row).contains_point(point) {
                        return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                            DesktopSchematicModalButton::TagDelete(index),
                        ));
                    }
                }
                if Self::schematic_tag_editor_new_text_rect(dialog).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                        DesktopSchematicModalButton::TagNewText,
                    ));
                }
                if Self::schematic_tag_editor_new_icon_rect(dialog).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                        DesktopSchematicModalButton::TagNewIcon,
                    ));
                }
                if Self::schematic_info_button_rect(dialog, 0).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                        DesktopSchematicModalButton::Back,
                    ));
                }
                None
            }
            DesktopSchematicModal::Export { index } => {
                let mut buttons = Vec::new();
                if self
                    .schematic_cards
                    .get(index)
                    .map(|entry| !entry.has_steam_id)
                    .unwrap_or(false)
                {
                    buttons.push(DesktopSchematicModalButton::ShareWorkshop);
                }
                buttons.extend([
                    DesktopSchematicModalButton::Copy,
                    DesktopSchematicModalButton::ExportFile,
                ]);
                for (button_index, button) in buttons.into_iter().enumerate() {
                    if Self::schematic_modal_option_button_rect(dialog, button_index)
                        .contains_point(point)
                    {
                        return Some(DesktopMenuRouteShellAction::SchematicModalButton(button));
                    }
                }
                if Self::schematic_info_button_rect(dialog, 0).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                        DesktopSchematicModalButton::Back,
                    ));
                }
                None
            }
            DesktopSchematicModal::Edit { index } => {
                if let Some(entry) = self.schematic_cards.get(index) {
                    for (tag_index, _) in entry.labels.iter().take(4).enumerate() {
                        let chip = Self::schematic_edit_owned_tag_chip_rect(dialog, tag_index);
                        if Self::schematic_edit_tag_remove_rect(chip).contains_point(point) {
                            return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                                DesktopSchematicModalButton::CardTagRemove {
                                    card_index: index,
                                    tag_index,
                                },
                            ));
                        }
                    }
                    let available = self
                        .schematics_tag_names()
                        .into_iter()
                        .filter(|tag| !entry.labels.iter().any(|label| label == tag))
                        .collect::<Vec<_>>();
                    for (tag_index, _) in available.iter().take(4).enumerate() {
                        if Self::schematic_edit_available_tag_chip_rect(dialog, tag_index)
                            .contains_point(point)
                        {
                            return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                                DesktopSchematicModalButton::CardTagAdd {
                                    card_index: index,
                                    tag_index,
                                },
                            ));
                        }
                    }
                    if Self::schematic_label_add_button_rect(dialog).contains_point(point) {
                        return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                            DesktopSchematicModalButton::CardTagNewText { card_index: index },
                        ));
                    }
                    if Self::schematic_label_add_icon_button_rect(dialog).contains_point(point) {
                        return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                            DesktopSchematicModalButton::CardTagNewIcon { card_index: index },
                        ));
                    }
                }
                if Self::schematic_info_button_rect(dialog, 1).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                        DesktopSchematicModalButton::EditOk,
                    ));
                }
                if Self::schematic_info_button_rect(dialog, 2).contains_point(point)
                    || Self::schematic_info_button_rect(dialog, 0).contains_point(point)
                {
                    return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                        DesktopSchematicModalButton::EditCancel,
                    ));
                }
                None
            }
            DesktopSchematicModal::IconTag { card_index } => {
                let candidates = self.schematic_icon_tag_candidates();
                for (icon_index, icon) in candidates.iter().take(24).enumerate() {
                    if Self::schematic_icon_tag_button_rect(dialog, icon_index)
                        .contains_point(point)
                    {
                        return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                            DesktopSchematicModalButton::CardTagAddIcon {
                                card_index,
                                icon_index,
                            },
                        ));
                    }
                    let _ = icon;
                }
                if Self::schematic_info_button_rect(dialog, 0).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                        DesktopSchematicModalButton::Back,
                    ));
                }
                None
            }
        }
    }

    fn schematics_card_action_at_point(
        &self,
        panel: RenderRect,
        point: RenderPoint,
    ) -> Option<DesktopSchematicCardAction> {
        let grid = Self::schematics_grid_rect_for_panel(panel);
        for (visible_index, card_index) in self
            .filtered_schematic_card_indices()
            .into_iter()
            .enumerate()
        {
            let entry = &self.schematic_cards[card_index];
            let card = Self::schematics_card_rect_for_grid(grid, visible_index);
            if !Self::schematics_card_visible_in_grid(grid, card) || !card.contains_point(point) {
                continue;
            }
            for action_index in 0..4 {
                if Self::schematics_card_action_button_rect(card, action_index)
                    .contains_point(point)
                {
                    return Self::schematics_card_action_for_index(entry, card_index, action_index);
                }
            }
            return Some(DesktopSchematicCardAction::new(
                card_index,
                DesktopSchematicCardActionKind::Info,
            ));
        }
        None
    }

    fn join_route_shell_action_at_surface_point(
        &self,
        viewport: RenderViewport,
        x: f32,
        y: f32,
    ) -> Option<DesktopMenuRouteShellAction> {
        let panel = Self::active_menu_route_shell_panel_for_route(viewport, DesktopMenuRoute::Join);
        let point = RenderPoint::new(x, y);
        if Self::join_route_add_button_rect_for_panel(panel).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::OpenJoinAddServer);
        }
        if Self::join_route_refresh_button_rect_for_panel(panel).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::RefreshJoinServers);
        }
        if self
            .join_route_server_card_index_at_point(panel, point)
            .is_some()
        {
            return Some(DesktopMenuRouteShellAction::ConnectJoin);
        }
        None
    }

    fn map_list_route_shell_action_at_surface_point(
        &self,
        viewport: RenderViewport,
        route: DesktopMenuRoute,
        x: f32,
        y: f32,
    ) -> Option<DesktopMenuRouteShellAction> {
        if !matches!(
            route,
            DesktopMenuRoute::CustomGame | DesktopMenuRoute::Editor
        ) {
            return None;
        }
        let panel = Self::active_menu_route_shell_panel_for_route(viewport, route);
        let point = RenderPoint::new(x, y);
        if Self::route_back_button_rect_for_panel(panel).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::CloseRoute);
        }
        if Self::map_list_filter_button_rect_for_panel(panel, route).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::OpenMapListFilters);
        }
        if route == DesktopMenuRoute::Editor {
            if Self::map_list_action_button_rect_for_panel(panel, 0).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::NewEditorMap);
            }
            if Self::map_list_action_button_rect_for_panel(panel, 1).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::ImportEditorMap);
            }
        }
        None
    }

    fn schematics_route_shell_action_at_surface_point(
        &self,
        viewport: RenderViewport,
        x: f32,
        y: f32,
    ) -> Option<DesktopMenuRouteShellAction> {
        let panel =
            Self::active_menu_route_shell_panel_for_route(viewport, DesktopMenuRoute::Schematics);
        let point = RenderPoint::new(x, y);
        if self.schematic_modal.is_some() {
            return self.schematic_modal_action_at_point(panel, point);
        }
        if Self::route_back_button_rect_for_panel(panel).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::CloseRoute);
        }
        if Self::schematics_search_rect_for_panel(panel).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::FocusSchematicSearch);
        }
        if Self::schematics_import_button_rect_for_panel(panel).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::OpenSchematicImport);
        }
        if Self::schematics_tag_edit_button_rect_for_panel(panel).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::OpenSchematicTags);
        }
        if let Some(tag_index) = self.schematics_tag_chip_index_at_point(panel, point) {
            return Some(DesktopMenuRouteShellAction::ToggleSchematicTag(tag_index));
        }
        if let Some(action) = self.schematics_card_action_at_point(panel, point) {
            return Some(DesktopMenuRouteShellAction::SchematicCard(action));
        }
        None
    }

    fn database_search_rect_for_panel(panel: RenderRect) -> RenderRect {
        RenderRect::new(
            panel.x + 28.0,
            panel.y + panel.height - 128.0,
            panel.width - 56.0,
            DATABASE_SEARCH_BAR_HEIGHT,
        )
    }

    fn database_tab_rect_for_panel(panel: RenderRect, index: usize) -> RenderRect {
        let search = Self::database_search_rect_for_panel(panel);
        RenderRect::new(
            panel.x + 28.0 + index as f32 * (DATABASE_TAB_SIZE + 6.0),
            search.y - DATABASE_TAB_SIZE - 10.0,
            DATABASE_TAB_SIZE,
            DATABASE_TAB_SIZE,
        )
    }

    fn database_category_header_rect_for_panel(panel: RenderRect, index: usize) -> RenderRect {
        let first_y = Self::database_tab_rect_for_panel(panel, 0).y - 38.0;
        let row_height = DATABASE_CONTENT_CELL_SIZE + DATABASE_CONTENT_CELL_GAP + 46.0;
        RenderRect::new(
            panel.x + 28.0,
            first_y - index as f32 * row_height,
            panel.width - 56.0,
            22.0,
        )
    }

    fn database_content_cell_rect_for_panel(
        panel: RenderRect,
        category_index: usize,
        item_index: usize,
    ) -> RenderRect {
        let header = Self::database_category_header_rect_for_panel(panel, category_index);
        RenderRect::new(
            header.x + item_index as f32 * (DATABASE_CONTENT_CELL_SIZE + DATABASE_CONTENT_CELL_GAP),
            header.y - DATABASE_CONTENT_CELL_SIZE - 9.0,
            DATABASE_CONTENT_CELL_SIZE,
            DATABASE_CONTENT_CELL_SIZE,
        )
    }

    fn active_menu_route_shell_action_at_surface_point(
        &self,
        surface_size: DesktopSurfaceSize,
        x: f32,
        y: f32,
    ) -> Option<DesktopMenuRouteShellAction> {
        let route = self.active_menu_route?;
        let viewport = self.default_render_viewport_for_surface(surface_size);
        if route == DesktopMenuRoute::Settings {
            if let Some(action) =
                self.settings_route_shell_action_at_surface_point(surface_size, x, y)
            {
                return Some(action);
            }
        }
        if route == DesktopMenuRoute::Mods {
            let panel = Self::active_menu_route_shell_panel_for_route(viewport, route);
            let point = RenderPoint::new(x, y);
            if self.mods_import_dialog_open {
                return self.mods_import_action_at_point(panel, point);
            }
            if let Some(action) = self.mods_route_detail_action_at_point(panel, point) {
                return Some(action);
            }
            if Self::route_back_button_rect_for_panel(panel).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::CloseRoute);
            }
            if Self::mods_route_action_button_rect_for_panel(panel, 1).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::OpenModsImport);
            }
            if self.mods_selected_mod_index.is_none() {
                if let Some(index) = self.mods_route_mod_card_index_at_point(panel, point) {
                    return Some(DesktopMenuRouteShellAction::OpenModsDetail(index));
                }
            }
        }
        if route == DesktopMenuRoute::Join {
            if let Some(action) = self.join_route_shell_action_at_surface_point(viewport, x, y) {
                return Some(action);
            }
        }
        if matches!(
            route,
            DesktopMenuRoute::CustomGame | DesktopMenuRoute::Editor
        ) {
            if let Some(action) =
                self.map_list_route_shell_action_at_surface_point(viewport, route, x, y)
            {
                return Some(action);
            }
        }
        if route == DesktopMenuRoute::Schematics {
            if let Some(action) =
                self.schematics_route_shell_action_at_surface_point(viewport, x, y)
            {
                return Some(action);
            }
        }
        if let Some(rect) = Self::discord_route_shell_copy_rect_for_viewport(viewport, route) {
            if rect.contains_point(RenderPoint::new(x, y)) {
                return Some(DesktopMenuRouteShellAction::CopyDiscordLink);
            }
        }
        let rect = Self::active_menu_route_shell_primary_rect_for_viewport(viewport, route)?;
        rect.contains_point(RenderPoint::new(x, y))
            .then_some(match route {
                DesktopMenuRoute::Campaign => DesktopMenuRouteShellAction::LaunchCampaign,
                DesktopMenuRoute::Join => DesktopMenuRouteShellAction::ConnectJoin,
                DesktopMenuRoute::About => match self.about_route_page {
                    DesktopAboutRoutePage::Links => DesktopMenuRouteShellAction::ShowAboutCredits,
                    DesktopAboutRoutePage::Credits => DesktopMenuRouteShellAction::ShowAboutLinks,
                },
                DesktopMenuRoute::Discord => DesktopMenuRouteShellAction::OpenDiscordLink,
                _ => return None,
            })
    }

    fn about_link_name_at_surface_point(
        &self,
        surface_size: DesktopSurfaceSize,
        x: f32,
        y: f32,
    ) -> Option<&'static str> {
        if self.active_menu_route != Some(DesktopMenuRoute::About)
            || self.about_route_page != DesktopAboutRoutePage::Links
        {
            return None;
        }
        let viewport = self.default_render_viewport_for_surface(surface_size);
        let panel =
            Self::active_menu_route_shell_panel_for_route(viewport, DesktopMenuRoute::About);
        let point = RenderPoint::new(x, y);
        for (index, link) in self.visible_about_links().into_iter().enumerate() {
            let rect = Self::about_link_card_rect_for_panel(panel, index);
            if rect.contains_point(point) {
                return Some(link.name);
            }
        }
        None
    }

    fn launch_campaign_smoke_world_from_menu(&mut self) -> GameRuntimePlayableSmokeReport {
        let selected_sector = self.campaign_selected_sector_from_dialog();
        let report = self.runtime.seed_playable_smoke_world(&self.content_loader);
        if let Some(sector) = selected_sector {
            self.runtime.state.set_sector(Some(sector));
        }
        self.runtime
            .set_network_context(GameRuntimeNetworkContext::offline());
        self.game_state = self.runtime.state.clone();
        self.player.team = TeamId(self.game_state.rules.default_team as u8);
        self.active_menu_route = None;
        self.campaign_planet_dialog = None;
        self.last_campaign_launch_report = Some(report);
        report
    }

    fn dispatch_settings_action(&mut self, action: DesktopSettingsAction) {
        match action {
            DesktopSettingsAction::OpenPage(page) => {
                self.settings_dialog_state.page = page;
                self.last_settings_hovered_control = None;
                self.last_settings_pressed_control = None;
                self.settings_scroll_drag_state = None;
            }
            DesktopSettingsAction::BackToMain => {
                self.settings_child_dialog = None;
                if self.settings_dialog_state.page == DesktopSettingsPage::Main {
                    self.active_menu_route = None;
                } else {
                    self.settings_dialog_state.page = DesktopSettingsPage::Main;
                }
                self.last_settings_hovered_control = None;
                self.last_settings_pressed_control = None;
                self.settings_scroll_drag_state = None;
            }
            DesktopSettingsAction::ResetCurrentPage => {
                self.reset_current_settings_page_overrides();
            }
            DesktopSettingsAction::ToggleSetting(table, key) => {
                if let Some(spec) = settings_pref_spec(table, key) {
                    if spec.kind == DesktopSettingsPrefKind::Check {
                        let checked = self.setting_bool_effective_value(spec);
                        self.set_setting_override(table, key, (!checked).to_string());
                    }
                }
            }
            DesktopSettingsAction::SetSliderValue(table, key, value) => {
                if let Some(spec) = settings_pref_spec(table, key) {
                    if spec.kind == DesktopSettingsPrefKind::Slider {
                        let value = spec
                            .range_step
                            .map(|range| value.clamp(range.min, range.max))
                            .unwrap_or(value);
                        self.set_setting_override(table, key, value.to_string());
                    }
                }
            }
            DesktopSettingsAction::OpenLanguageDialog => {
                self.settings_child_dialog = Some(DesktopSettingsChildDialog::Language);
            }
            DesktopSettingsAction::OpenControlsDialog => {
                self.settings_child_dialog = Some(DesktopSettingsChildDialog::Controls);
            }
            DesktopSettingsAction::CloseChildDialog => {
                self.settings_child_dialog = None;
            }
            DesktopSettingsAction::ClearAllData
            | DesktopSettingsAction::ClearPlanetData
            | DesktopSettingsAction::ClearSaves
            | DesktopSettingsAction::ClearResearch
            | DesktopSettingsAction::ClearCampaignSaves
            | DesktopSettingsAction::ExportData
            | DesktopSettingsAction::ImportData
            | DesktopSettingsAction::OpenDataFolder
            | DesktopSettingsAction::ExportCrashLogs => {}
        }
        self.last_settings_action = Some(action);
    }

    fn open_schematic_modal(&mut self, modal: DesktopSchematicModal) {
        self.schematic_label_add_text.clear();
        if matches!(modal, DesktopSchematicModal::Tags) {
            self.sync_schematic_tag_order();
            self.schematic_tag_editor_text.clear();
        }
        self.schematic_modal = Some(modal);
        self.schematic_info_dialog = match modal {
            DesktopSchematicModal::Info { index } => Some(index),
            _ => None,
        };
        if let DesktopSchematicModal::Edit { index } = modal {
            if let Some(entry) = self.schematic_cards.get(index) {
                self.schematic_edit_name = entry.name.clone();
                self.schematic_edit_description = entry.description.clone();
            }
        }
    }

    fn close_schematic_modal(&mut self) {
        self.schematic_modal = None;
        self.schematic_info_dialog = None;
    }

    fn mods_folder_uri_for_path(path: &str) -> String {
        let normalized = path.replace('\\', "/");
        let mut escaped = String::with_capacity(normalized.len());
        for ch in normalized.chars() {
            match ch {
                ' ' => escaped.push_str("%20"),
                '#' => escaped.push_str("%23"),
                '?' => escaped.push_str("%3F"),
                '%' => escaped.push_str("%25"),
                _ => escaped.push(ch),
            }
        }
        if escaped.starts_with("//") {
            format!("file:{escaped}")
        } else if escaped.starts_with('/') {
            format!("file://{escaped}")
        } else {
            format!("file:///{escaped}")
        }
    }

    fn dispatch_mods_folder_action_with_platform<P: Platform>(
        &mut self,
        index: usize,
        platform: &mut P,
    ) -> Option<DesktopModsFolderAction> {
        let path = self.mods_route_mod_root_at_index(index)?.to_string();
        let uri = Self::mods_folder_uri_for_path(&path);
        let opened = platform.open_uri(&uri);
        let action = DesktopModsFolderAction {
            index,
            path,
            uri,
            opened,
        };
        self.last_mods_folder_action = Some(action.clone());
        Some(action)
    }

    fn dispatch_mods_import_file_with_platform<P: Platform>(
        &mut self,
        platform: &mut P,
    ) -> MultiFileChooserRequest {
        let request = platform.show_multi_file_chooser(&["zip", "jar"]);
        self.last_mods_import_action = Some(DesktopModsImportAction::File);
        self.last_mods_import_file_request = Some(request.clone());
        self.mods_import_dialog_open = false;
        request
    }

    fn dispatch_menu_route_shell_action(&mut self, action: DesktopMenuRouteShellAction) {
        self.last_menu_route_shell_action = Some(action);
        match action {
            DesktopMenuRouteShellAction::CloseRoute => {
                self.active_menu_route = None;
                self.mods_selected_mod_index = None;
                self.mods_import_dialog_open = false;
                self.settings_child_dialog = None;
            }
            DesktopMenuRouteShellAction::LaunchCampaign => {
                if self.block_menu_action_for_content_errors(MenuButtonRole::Campaign) {
                    self.last_menu_route_shell_action = None;
                    return;
                }
                self.launch_campaign_smoke_world_from_menu();
            }
            DesktopMenuRouteShellAction::ConnectJoin => {
                let Some(target) = self.connect_target.clone() else {
                    self.connect_error = Some("missing connect target".into());
                    return;
                };
                let _ = self.connect_to_target(target);
            }
            DesktopMenuRouteShellAction::OpenJoinAddServer => {
                self.join_add_dialog_open = true;
            }
            DesktopMenuRouteShellAction::RefreshJoinServers => {
                self.join_refresh_requests = self.join_refresh_requests.saturating_add(1);
            }
            DesktopMenuRouteShellAction::OpenMapListFilters => {
                self.map_list_filter_dialog_open = true;
            }
            DesktopMenuRouteShellAction::NewEditorMap => {
                self.editor_new_map_dialog_open = true;
            }
            DesktopMenuRouteShellAction::ImportEditorMap => {
                self.editor_import_map_dialog_open = true;
            }
            DesktopMenuRouteShellAction::OpenModsImport => {
                self.mods_import_dialog_open = true;
                self.mods_selected_mod_index = None;
                self.last_mods_import_action = Some(DesktopModsImportAction::Open);
                self.last_mods_import_file_request = None;
            }
            DesktopMenuRouteShellAction::CloseModsImport => {
                self.mods_import_dialog_open = false;
                self.last_mods_import_action = Some(DesktopModsImportAction::Close);
            }
            DesktopMenuRouteShellAction::ModsImportFile => {
                let mut platform = DefaultPlatform;
                let _ = self.dispatch_mods_import_file_with_platform(&mut platform);
            }
            DesktopMenuRouteShellAction::ModsImportGithub => {
                self.mods_import_dialog_open = false;
                self.last_mods_import_action = Some(DesktopModsImportAction::Github);
            }
            DesktopMenuRouteShellAction::OpenModsDetail(index) => {
                if self.last_mods_directory_mod_names.get(index).is_some() {
                    self.mods_selected_mod_index = Some(index);
                }
            }
            DesktopMenuRouteShellAction::OpenModsFolder(index) => {
                let mut platform = DefaultPlatform;
                let _ = self.dispatch_mods_folder_action_with_platform(index, &mut platform);
            }
            DesktopMenuRouteShellAction::CloseModsDetail => {
                self.mods_selected_mod_index = None;
            }
            DesktopMenuRouteShellAction::FocusSchematicSearch => {
                self.schematic_search_focused = true;
            }
            DesktopMenuRouteShellAction::ClearSchematicSearch => {
                self.schematic_search.clear();
                self.schematic_search_focused = true;
            }
            DesktopMenuRouteShellAction::ToggleSchematicTag(tag_index) => {
                if let Some(tag) = self.schematics_tag_names().get(tag_index).cloned() {
                    if let Some(selected_index) = self
                        .schematic_selected_tags
                        .iter()
                        .position(|selected| selected == &tag)
                    {
                        self.schematic_selected_tags.remove(selected_index);
                    } else {
                        self.schematic_selected_tags.push(tag.clone());
                    }
                    self.last_schematic_tag_toggled = Some(tag);
                }
            }
            DesktopMenuRouteShellAction::OpenSchematicImport => {
                self.schematic_import_dialog_open = true;
                self.open_schematic_modal(DesktopSchematicModal::Import);
            }
            DesktopMenuRouteShellAction::OpenSchematicTags => {
                self.schematic_tags_dialog_open = true;
                self.open_schematic_modal(DesktopSchematicModal::Tags);
            }
            DesktopMenuRouteShellAction::CloseSchematicInfo => {
                self.close_schematic_modal();
            }
            DesktopMenuRouteShellAction::SchematicInfoExport => {
                if let Some(index) = self.schematic_info_dialog {
                    self.open_schematic_modal(DesktopSchematicModal::Export { index });
                    self.last_schematic_card_action = Some(DesktopSchematicCardAction::new(
                        index,
                        DesktopSchematicCardActionKind::Export,
                    ));
                }
            }
            DesktopMenuRouteShellAction::SchematicInfoEdit => {
                if let Some(index) = self.schematic_info_dialog {
                    self.open_schematic_modal(DesktopSchematicModal::Edit { index });
                    self.last_schematic_card_action = Some(DesktopSchematicCardAction::new(
                        index,
                        DesktopSchematicCardActionKind::Edit,
                    ));
                }
            }
            DesktopMenuRouteShellAction::CloseSchematicModal => {
                self.close_schematic_modal();
            }
            DesktopMenuRouteShellAction::SchematicModalButton(button) => {
                self.last_schematic_modal_button = Some(button);
                match button {
                    DesktopSchematicModalButton::Back | DesktopSchematicModalButton::EditCancel => {
                        self.close_schematic_modal();
                    }
                    DesktopSchematicModalButton::EditOk => {
                        if let Some(DesktopSchematicModal::Edit { index }) = self.schematic_modal {
                            let name = self.schematic_edit_name.trim().to_string();
                            if !name.is_empty() {
                                if let Some(entry) = self.schematic_cards.get_mut(index) {
                                    entry.name = name;
                                    entry.description = self.schematic_edit_description.clone();
                                }
                                self.close_schematic_modal();
                            }
                        }
                    }
                    DesktopSchematicModalButton::TagMoveUp(index) => {
                        self.sync_schematic_tag_order();
                        if index > 0 && index < self.schematic_tag_order.len() {
                            self.schematic_tag_order.swap(index, index - 1);
                            self.persist_schematic_tags();
                        }
                    }
                    DesktopSchematicModalButton::TagMoveDown(index) => {
                        self.sync_schematic_tag_order();
                        if index + 1 < self.schematic_tag_order.len() {
                            self.schematic_tag_order.swap(index, index + 1);
                            self.persist_schematic_tags();
                        }
                    }
                    DesktopSchematicModalButton::TagSelect(index) => {
                        self.sync_schematic_tag_order();
                        if let Some(tag) = self.schematic_tag_order.get(index).cloned() {
                            self.schematic_selected_tags.clear();
                            self.schematic_selected_tags.push(tag.clone());
                            self.last_schematic_tag_toggled = Some(tag);
                            self.close_schematic_modal();
                        }
                    }
                    DesktopSchematicModalButton::TagRename(index) => {
                        self.sync_schematic_tag_order();
                        let name = self.schematic_tag_editor_text.trim().to_string();
                        if !name.is_empty()
                            && !self.schematic_tag_order.iter().any(|tag| tag == &name)
                        {
                            if let Some(old) = self.schematic_tag_order.get(index).cloned() {
                                self.schematic_tag_order[index] = name.clone();
                                for entry in &mut self.schematic_cards {
                                    for label in &mut entry.labels {
                                        if label == &old {
                                            *label = name.clone();
                                        }
                                    }
                                }
                                for selected in &mut self.schematic_selected_tags {
                                    if selected == &old {
                                        *selected = name.clone();
                                    }
                                }
                                self.schematic_tag_editor_text.clear();
                                self.persist_schematic_tags();
                            }
                        }
                    }
                    DesktopSchematicModalButton::TagDelete(index) => {
                        self.sync_schematic_tag_order();
                        if index < self.schematic_tag_order.len() {
                            let removed = self.schematic_tag_order.remove(index);
                            self.schematic_selected_tags
                                .retain(|selected| selected != &removed);
                            for entry in &mut self.schematic_cards {
                                entry.labels.retain(|label| label != &removed);
                            }
                            self.persist_schematic_tags();
                        }
                    }
                    DesktopSchematicModalButton::TagNewText => {
                        self.sync_schematic_tag_order();
                        let name = self.schematic_tag_editor_text.trim().to_string();
                        if !name.is_empty()
                            && !self.schematic_tag_order.iter().any(|tag| tag == &name)
                        {
                            self.schematic_tag_order.push(name);
                            self.schematic_tag_editor_text.clear();
                            self.persist_schematic_tags();
                        }
                    }
                    DesktopSchematicModalButton::TagNewIcon => {
                        self.sync_schematic_tag_order();
                        let mut icon = "★".to_string();
                        if self.schematic_tag_order.iter().any(|tag| tag == &icon) {
                            icon = format!("★{}", self.schematic_tag_order.len() + 1);
                        }
                        self.schematic_tag_order.push(icon);
                        self.persist_schematic_tags();
                    }
                    DesktopSchematicModalButton::CardTagRemove {
                        card_index,
                        tag_index,
                    } => {
                        if let Some(entry) = self.schematic_cards.get_mut(card_index) {
                            if tag_index < entry.labels.len() {
                                entry.labels.remove(tag_index);
                                self.persist_schematic_tags();
                            }
                        }
                    }
                    DesktopSchematicModalButton::CardTagAdd {
                        card_index,
                        tag_index,
                    } => {
                        let available = self
                            .schematics_tag_names()
                            .into_iter()
                            .filter(|tag| {
                                self.schematic_cards
                                    .get(card_index)
                                    .map(|entry| !entry.labels.iter().any(|label| label == tag))
                                    .unwrap_or(false)
                            })
                            .collect::<Vec<_>>();
                        if let (Some(entry), Some(tag)) = (
                            self.schematic_cards.get_mut(card_index),
                            available.get(tag_index).cloned(),
                        ) {
                            if !entry.labels.iter().any(|label| label == &tag) {
                                entry.labels.push(tag);
                                self.persist_schematic_tags();
                            }
                        }
                    }
                    DesktopSchematicModalButton::CardTagNewText { card_index } => {
                        let tag = self.schematic_label_add_text.trim().to_string();
                        if !tag.is_empty() {
                            self.sync_schematic_tag_order();
                            let known = self.schematic_tag_order.iter().any(|known| known == &tag);
                            let mut added = false;
                            if !known {
                                self.schematic_tag_order.push(tag.clone());
                            }
                            if let Some(entry) = self.schematic_cards.get_mut(card_index) {
                                if !entry.labels.iter().any(|label| label == &tag) {
                                    entry.labels.push(tag);
                                    added = true;
                                }
                            }
                            self.persist_schematic_tags();
                            if added {
                                self.schematic_label_add_text.clear();
                                self.close_schematic_modal();
                            }
                        }
                    }
                    DesktopSchematicModalButton::CardTagNewIcon { card_index } => {
                        self.open_schematic_modal(DesktopSchematicModal::IconTag { card_index });
                    }
                    DesktopSchematicModalButton::CardTagAddIcon {
                        card_index,
                        icon_index,
                    } => {
                        let candidates = self.schematic_icon_tag_candidates();
                        if let Some(icon) = candidates.get(icon_index).copied() {
                            let tag = icon
                                .glyph_string()
                                .unwrap_or_else(|| icon.java_name.to_string());
                            self.sync_schematic_tag_order();
                            if !self.schematic_tag_order.iter().any(|known| known == &tag) {
                                self.schematic_tag_order.push(tag.clone());
                            }
                            if let Some(entry) = self.schematic_cards.get_mut(card_index) {
                                if !entry.labels.iter().any(|label| label == &tag) {
                                    entry.labels.push(tag);
                                }
                            }
                            self.persist_schematic_tags();
                            self.close_schematic_modal();
                        }
                    }
                    DesktopSchematicModalButton::ImportClipboard
                    | DesktopSchematicModalButton::ImportFile
                    | DesktopSchematicModalButton::BrowseWorkshop
                    | DesktopSchematicModalButton::ShareWorkshop
                    | DesktopSchematicModalButton::Copy
                    | DesktopSchematicModalButton::ExportFile => {}
                }
            }
            DesktopMenuRouteShellAction::SchematicCard(action) => {
                match action.kind {
                    DesktopSchematicCardActionKind::Info => {
                        self.open_schematic_modal(DesktopSchematicModal::Info {
                            index: action.index,
                        });
                    }
                    DesktopSchematicCardActionKind::Export => {
                        self.open_schematic_modal(DesktopSchematicModal::Export {
                            index: action.index,
                        });
                    }
                    DesktopSchematicCardActionKind::Edit => {
                        self.open_schematic_modal(DesktopSchematicModal::Edit {
                            index: action.index,
                        });
                    }
                    DesktopSchematicCardActionKind::Delete
                    | DesktopSchematicCardActionKind::ViewWorkshop => {}
                }
                self.last_schematic_card_action = Some(action);
            }
            DesktopMenuRouteShellAction::ShowAboutCredits => {
                self.about_route_page = DesktopAboutRoutePage::Credits;
            }
            DesktopMenuRouteShellAction::ShowAboutLinks => {
                self.about_route_page = DesktopAboutRoutePage::Links;
            }
            DesktopMenuRouteShellAction::OpenDiscordLink => {
                self.dispatch_about_link_action("discord");
            }
            DesktopMenuRouteShellAction::CopyDiscordLink => {
                self.copy_discord_link();
            }
            DesktopMenuRouteShellAction::Settings(action) => {
                self.dispatch_settings_action(action);
            }
        }
    }

    fn campaign_sector_preset_by_id(
        &self,
        planet_name: &str,
        sector_id: i32,
    ) -> Option<&SectorPreset> {
        self.content_loader.sectors().iter().find(|sector| {
            sector.planet_name.as_deref() == Some(planet_name)
                && sector.sector_id == Some(sector_id)
        })
    }

    fn campaign_selected_sector_from_dialog(&self) -> Option<Sector> {
        let dialog = self.campaign_planet_dialog.as_ref()?;
        let selected = dialog.selected_sector_id?;
        let preset = self.campaign_sector_preset_by_id(&dialog.planet_name, selected)?;
        let mut sector = Sector::new(selected);
        sector.preset = Some(preset.clone());
        sector.save_exists = true;
        sector.info.has_core = true;
        Some(sector)
    }

    fn visible_about_links(&self) -> Vec<&'static AboutLinkEntry> {
        ABOUT_LINKS
            .iter()
            .filter(|link| {
                !self.about_filter_banned_links || !ABOUT_BANNED_LINK_NAMES.contains(&link.name)
            })
            .collect()
    }

    fn about_link_by_name(&self, name: &str) -> Option<&'static AboutLinkEntry> {
        self.visible_about_links()
            .into_iter()
            .find(|link| link.name == name)
    }

    pub fn dispatch_about_link_action_with_platform<P: Platform>(
        &mut self,
        name: &str,
        platform: &mut P,
    ) -> Option<DesktopAboutLinkAction> {
        let link = self.about_link_by_name(name)?;
        let wiki_event_fired = link.name == "wiki";
        let opened = platform.open_uri(link.url);
        let (clipboard_text, error_message) = if opened {
            (None, None)
        } else {
            platform.set_clipboard_text(link.url);
            (Some(link.url.to_string()), Some("@linkfail".to_string()))
        };
        let action = DesktopAboutLinkAction {
            name: link.name.to_string(),
            url: link.url.to_string(),
            opened,
            wiki_event_fired,
            clipboard_text,
            error_message,
        };
        self.last_about_linkfail_message = action.error_message.clone();
        self.last_about_link_action = Some(action.clone());
        Some(action)
    }

    pub fn dispatch_about_link_action(&mut self, name: &str) -> Option<DesktopAboutLinkAction> {
        let mut platform = DefaultPlatform;
        self.dispatch_about_link_action_with_platform(name, &mut platform)
    }

    pub fn copy_discord_link_with_platform<P: Platform>(&mut self, platform: &mut P) -> String {
        platform.set_clipboard_text(DISCORD_URL);
        self.last_discord_clipboard_text = Some(DISCORD_URL.to_string());
        DISCORD_URL.to_string()
    }

    pub fn copy_discord_link(&mut self) -> String {
        let mut platform = DefaultPlatform;
        self.copy_discord_link_with_platform(&mut platform)
    }

    fn push_database_route_page(&self, pass: &mut RenderPass, panel: RenderRect) {
        let search = Self::database_search_rect_for_panel(panel);
        pass.push(RenderCommand::draw_sprite(
            Self::settings_text_button_symbol("grayt", false, false),
            search,
            [1.0, 1.0, 1.0, 0.92],
            0.0,
            Layer::END_PIXELED + 0.025,
        ));
        pass.push(RenderCommand::draw_text_styled(
            desktop_ui_icon_glyph_or_label("zoom", "zoom"),
            RenderPoint::new(search.x + 22.0, search.center().y),
            [0.72, 0.82, 0.9, 1.0],
            14.0,
            0.0,
            RenderTextStyle::new(RenderTextAlign::Center)
                .with_vertical_align(RenderTextVerticalAlign::Center)
                .with_integer_position(true)
                .with_outline(true),
            Layer::END_PIXELED + 0.03,
        ));
        pass.push(RenderCommand::draw_text_styled(
            "@players.search",
            RenderPoint::new(search.x + 44.0, search.center().y),
            [0.60, 0.70, 0.78, 1.0],
            12.0,
            0.0,
            RenderTextStyle::new(RenderTextAlign::Start)
                .with_vertical_align(RenderTextVerticalAlign::Center)
                .with_integer_position(true),
            Layer::END_PIXELED + 0.03,
        ));

        let all_tab = Self::database_tab_rect_for_panel(panel, 0);
        pass.push(RenderCommand::draw_sprite(
            Self::settings_text_button_symbol("flatTogglet", false, true),
            all_tab,
            [1.0, 1.0, 1.0, 0.95],
            0.0,
            Layer::END_PIXELED + 0.031,
        ));
        pass.push(RenderCommand::draw_text_styled(
            "@all",
            all_tab.center(),
            [Pal::ACCENT.r, Pal::ACCENT.g, Pal::ACCENT.b, 1.0],
            10.0,
            0.0,
            RenderTextStyle::new(RenderTextAlign::Center)
                .with_vertical_align(RenderTextVerticalAlign::Center)
                .with_integer_position(true)
                .with_outline(true),
            Layer::END_PIXELED + 0.033,
        ));

        for (index, planet) in self
            .content_loader
            .get_by(ContentType::Planet)
            .iter()
            .filter_map(|record| record.name())
            .take(4)
            .enumerate()
        {
            let tab = Self::database_tab_rect_for_panel(panel, index + 1);
            pass.push(RenderCommand::draw_sprite(
                Self::settings_text_button_symbol("flatTogglet", false, false),
                tab,
                [1.0, 1.0, 1.0, 0.82],
                0.0,
                Layer::END_PIXELED + 0.031 + index as f32 * 0.0001,
            ));
            pass.push(RenderCommand::draw_text_styled(
                planet,
                tab.center(),
                [0.76, 0.86, 0.94, 1.0],
                8.0,
                0.0,
                RenderTextStyle::new(RenderTextAlign::Center)
                    .with_vertical_align(RenderTextVerticalAlign::Center)
                    .with_integer_position(true),
                Layer::END_PIXELED + 0.033 + index as f32 * 0.0001,
            ));
        }

        let categories = self.database_route_content_types();
        if categories.is_empty() {
            pass.push(RenderCommand::draw_text_styled(
                "@none.found",
                RenderPoint::new(panel.x + panel.width * 0.5, all_tab.y - 50.0),
                [0.70, 0.78, 0.84, 1.0],
                13.0,
                0.0,
                RenderTextStyle::new(RenderTextAlign::Center)
                    .with_vertical_align(RenderTextVerticalAlign::Center)
                    .with_integer_position(true),
                Layer::END_PIXELED + 0.034,
            ));
            return;
        }

        let visible_columns = ((panel.width - 56.0 + DATABASE_CONTENT_CELL_GAP)
            / (DATABASE_CONTENT_CELL_SIZE + DATABASE_CONTENT_CELL_GAP))
            .floor()
            .clamp(1.0, DATABASE_VISIBLE_ITEMS_PER_CATEGORY as f32)
            as usize;
        for (category_index, content_type) in categories
            .iter()
            .take(DATABASE_VISIBLE_CATEGORIES)
            .copied()
            .enumerate()
        {
            let header = Self::database_category_header_rect_for_panel(panel, category_index);
            if header.y < panel.y + 42.0 {
                break;
            }
            let records = self
                .content_loader
                .get_by(content_type)
                .iter()
                .filter_map(|record| record.name())
                .take(visible_columns)
                .collect::<Vec<_>>();
            let label = Self::database_category_label(content_type);
            pass.push(RenderCommand::draw_text_styled(
                format!(
                    "{} | {}",
                    label,
                    self.content_loader.get_by(content_type).len()
                ),
                RenderPoint::new(header.x, header.center().y),
                [Pal::ACCENT.r, Pal::ACCENT.g, Pal::ACCENT.b, 1.0],
                12.0,
                0.0,
                RenderTextStyle::new(RenderTextAlign::Start)
                    .with_vertical_align(RenderTextVerticalAlign::Center)
                    .with_integer_position(true)
                    .with_outline(true),
                Layer::END_PIXELED + 0.034 + category_index as f32 * 0.001,
            ));
            pass.push(RenderCommand::fill_rect(
                RenderRect::new(header.x, header.y - 4.0, header.width, 3.0),
                [Pal::ACCENT.r, Pal::ACCENT.g, Pal::ACCENT.b, 0.92],
                Layer::END_PIXELED + 0.0345 + category_index as f32 * 0.001,
            ));
            for (item_index, name) in records.iter().enumerate() {
                let cell =
                    Self::database_content_cell_rect_for_panel(panel, category_index, item_index);
                pass.push(RenderCommand::draw_sprite(
                    "whiteui",
                    cell,
                    [0.12, 0.16, 0.20, 0.96],
                    0.0,
                    Layer::END_PIXELED + 0.035 + category_index as f32 * 0.001,
                ));
                pass.push(RenderCommand::stroke_rect(
                    cell,
                    [0.34, 0.48, 0.58, 0.82],
                    1.0,
                    Layer::END_PIXELED + 0.036 + category_index as f32 * 0.001,
                ));
                pass.push(RenderCommand::draw_text_styled(
                    *name,
                    RenderPoint::new(cell.center().x, cell.y - 7.0),
                    [0.66, 0.76, 0.84, 1.0],
                    7.0,
                    0.0,
                    RenderTextStyle::new(RenderTextAlign::Center)
                        .with_vertical_align(RenderTextVerticalAlign::Center)
                        .with_integer_position(true),
                    Layer::END_PIXELED + 0.037 + category_index as f32 * 0.001,
                ));
            }
        }
    }

