    fn push_schematic_label_add_controls(
        &self,
        pass: &mut RenderPass,
        dialog: RenderRect,
        layer_offset: f32,
    ) {
        let add_field = Self::schematic_label_add_text_field_rect(dialog);
        pass.push(RenderCommand::draw_sprite(
            Self::settings_text_button_symbol("grayt", false, false),
            add_field,
            [1.0, 1.0, 1.0, 0.86],
            0.0,
            Layer::END_PIXELED + layer_offset,
        ));
        pass.push(RenderCommand::draw_text_styled(
            if self.schematic_label_add_text.is_empty() {
                "@schematic.addtag".to_string()
            } else {
                self.schematic_label_add_text.clone()
            },
            RenderPoint::new(add_field.x + 8.0, add_field.center().y),
            if self.schematic_label_add_text.is_empty() {
                [0.58, 0.68, 0.76, 1.0]
            } else {
                [0.88, 0.94, 1.0, 1.0]
            },
            9.0,
            0.0,
            RenderTextStyle::new(RenderTextAlign::Start)
                .with_vertical_align(RenderTextVerticalAlign::Center)
                .with_integer_position(true),
            Layer::END_PIXELED + layer_offset + 0.001,
        ));
        self.push_settings_text_button(
            pass,
            Self::schematic_label_add_button_rect(dialog),
            "@schematic.texttag",
            Some("add"),
            Layer::END_PIXELED + layer_offset + 0.002,
        );
        self.push_settings_text_button(
            pass,
            Self::schematic_label_add_icon_button_rect(dialog),
            "@schematic.icontag",
            Some("add"),
            Layer::END_PIXELED + layer_offset + 0.003,
        );
    }

    fn push_schematic_info_dialog(&self, pass: &mut RenderPass, panel: RenderRect) {
        let Some(index) = self.schematic_info_dialog else {
            return;
        };
        let Some(entry) = self.schematic_cards.get(index) else {
            return;
        };
        let dialog = Self::schematic_info_dialog_rect_for_panel(panel);
        pass.push(RenderCommand::fill_rect(
            panel,
            [0.0, 0.0, 0.0, 0.42],
            Layer::END_PIXELED + 0.070,
        ));
        pass.push(RenderCommand::draw_sprite(
            Self::settings_drawable_symbol("pane"),
            dialog,
            [1.0, 1.0, 1.0, 0.98],
            0.0,
            Layer::END_PIXELED + 0.071,
        ));
        pass.push(RenderCommand::stroke_rect(
            dialog,
            [0.52, 0.68, 0.82, 0.95],
            2.0,
            Layer::END_PIXELED + 0.072,
        ));
        pass.push(RenderCommand::draw_text_styled(
            format!("[schematic] {}", entry.name),
            RenderPoint::new(dialog.center().x, dialog.y + dialog.height - 28.0),
            [0.94, 0.98, 1.0, 1.0],
            15.0,
            0.0,
            RenderTextStyle::new(RenderTextAlign::Center)
                .with_vertical_align(RenderTextVerticalAlign::Center)
                .with_integer_position(true)
                .with_outline(true),
            Layer::END_PIXELED + 0.076,
        ));
        pass.push(RenderCommand::draw_text_styled(
            format!(
                "schematic.info: {}x{} | {} blocks",
                entry.width, entry.height, entry.tile_count
            ),
            RenderPoint::new(dialog.center().x, dialog.y + dialog.height - 54.0),
            [0.72, 0.80, 0.86, 1.0],
            12.0,
            0.0,
            RenderTextStyle::new(RenderTextAlign::Center)
                .with_vertical_align(RenderTextVerticalAlign::Center)
                .with_integer_position(true),
            Layer::END_PIXELED + 0.076,
        ));
        pass.push(RenderCommand::draw_text_styled(
            "@schematic.tags",
            RenderPoint::new(dialog.x + 42.0, dialog.y + dialog.height - 92.0),
            [0.72, 0.82, 0.9, 1.0],
            11.0,
            0.0,
            RenderTextStyle::new(RenderTextAlign::Start)
                .with_vertical_align(RenderTextVerticalAlign::Center)
                .with_integer_position(true)
                .with_outline(true),
            Layer::END_PIXELED + 0.077,
        ));
        for (tag_index, tag) in entry.labels.iter().take(4).enumerate() {
            let chip = Self::schematic_edit_owned_tag_chip_rect(dialog, tag_index);
            pass.push(RenderCommand::draw_sprite(
                Self::settings_drawable_symbol("button"),
                chip,
                [1.0, 1.0, 1.0, 0.82],
                0.0,
                Layer::END_PIXELED + 0.078 + tag_index as f32 * 0.001,
            ));
            pass.push(RenderCommand::draw_text_styled(
                tag.clone(),
                RenderPoint::new(chip.x + 8.0, chip.center().y),
                [0.78, 0.86, 0.92, 1.0],
                9.0,
                0.0,
                RenderTextStyle::new(RenderTextAlign::Start)
                    .with_vertical_align(RenderTextVerticalAlign::Center)
                    .with_integer_position(true),
                Layer::END_PIXELED + 0.081 + tag_index as f32 * 0.001,
            ));
            pass.push(RenderCommand::draw_text_styled(
                desktop_ui_icon_glyph_or_label("cancelSmall", "x"),
                Self::schematic_edit_tag_remove_rect(chip).center(),
                [1.0, 0.56, 0.54, 1.0],
                10.0,
                0.0,
                RenderTextStyle::new(RenderTextAlign::Center)
                    .with_vertical_align(RenderTextVerticalAlign::Center)
                    .with_integer_position(true),
                Layer::END_PIXELED + 0.082 + tag_index as f32 * 0.001,
            ));
        }
        let available = self
            .schematics_tag_names()
            .into_iter()
            .filter(|tag| !entry.labels.iter().any(|label| label == tag))
            .collect::<Vec<_>>();
        for (tag_index, tag) in available.iter().take(4).enumerate() {
            let chip = Self::schematic_edit_available_tag_chip_rect(dialog, tag_index);
            pass.push(RenderCommand::draw_sprite(
                Self::settings_text_button_symbol("flatTogglet", false, false),
                chip,
                [1.0, 1.0, 1.0, 0.62],
                0.0,
                Layer::END_PIXELED + 0.077 + tag_index as f32 * 0.001,
            ));
            pass.push(RenderCommand::draw_text_styled(
                format!("+{tag}"),
                chip.center(),
                [0.62, 0.74, 0.82, 1.0],
                8.0,
                0.0,
                RenderTextStyle::new(RenderTextAlign::Center)
                    .with_vertical_align(RenderTextVerticalAlign::Center)
                    .with_integer_position(true),
                Layer::END_PIXELED + 0.080 + tag_index as f32 * 0.001,
            ));
        }
        self.push_schematic_label_add_controls(pass, dialog, 0.083);

        let preview = Self::schematic_info_preview_rect(dialog);
        pass.push(RenderCommand::draw_sprite(
            "schematic-background",
            preview,
            [0.76, 0.84, 0.90, 0.82],
            0.0,
            Layer::END_PIXELED + 0.073,
        ));
        pass.push(RenderCommand::stroke_rect(
            preview,
            [0.22, 0.30, 0.36, 0.95],
            1.0,
            Layer::END_PIXELED + 0.074,
        ));
        pass.push(RenderCommand::draw_text_styled(
            "SchematicImage preview",
            preview.center(),
            [0.70, 0.80, 0.88, 1.0],
            12.0,
            0.0,
            RenderTextStyle::new(RenderTextAlign::Center)
                .with_vertical_align(RenderTextVerticalAlign::Center)
                .with_integer_position(true),
            Layer::END_PIXELED + 0.077,
        ));
        if !entry.description.is_empty() {
            pass.push(RenderCommand::draw_text_styled(
                format!("description: {}", entry.description),
                RenderPoint::new(dialog.center().x, dialog.y + 82.0),
                [0.70, 0.76, 0.82, 1.0],
                11.0,
                0.0,
                RenderTextStyle::new(RenderTextAlign::Center)
                    .with_vertical_align(RenderTextVerticalAlign::Center)
                    .with_integer_position(true),
                Layer::END_PIXELED + 0.077,
            ));
        }
        pass.push(RenderCommand::draw_text_styled(
            "requirements: pending real Schematic.requirements()",
            RenderPoint::new(dialog.center().x, dialog.y + 104.0),
            [0.58, 0.66, 0.74, 1.0],
            10.0,
            0.0,
            RenderTextStyle::new(RenderTextAlign::Center)
                .with_vertical_align(RenderTextVerticalAlign::Center)
                .with_integer_position(true),
            Layer::END_PIXELED + 0.077,
        ));

        for (button_index, (label, icon)) in [
            ("@back", "left"),
            ("@editor.export", "upload"),
            ("@edit", "pencil"),
        ]
        .into_iter()
        .enumerate()
        {
            self.push_settings_text_button(
                pass,
                Self::schematic_info_button_rect(dialog, button_index),
                label,
                Some(icon),
                Layer::END_PIXELED + 0.078 + button_index as f32 * 0.001,
            );
        }
    }

    fn push_schematic_modal_dialog(&self, pass: &mut RenderPass, panel: RenderRect) {
        let Some(modal) = self.schematic_modal else {
            return;
        };
        match modal {
            DesktopSchematicModal::Info { .. } => {
                self.push_schematic_info_dialog(pass, panel);
            }
            DesktopSchematicModal::Import => {
                let dialog = self.push_schematic_modal_base(pass, panel, "@editor.import");
                self.push_schematic_modal_option_button(
                    pass,
                    dialog,
                    0,
                    "@schematic.copy.import",
                    "copy",
                );
                self.push_schematic_modal_option_button(
                    pass,
                    dialog,
                    1,
                    "@schematic.importfile",
                    "download",
                );
                self.push_schematic_modal_option_button(
                    pass,
                    dialog,
                    2,
                    "@schematic.browseworkshop",
                    "book",
                );
                self.push_settings_text_button(
                    pass,
                    Self::schematic_info_button_rect(dialog, 0),
                    "@back",
                    Some("left"),
                    Layer::END_PIXELED + 0.083,
                );
            }
            DesktopSchematicModal::Tags => {
                let dialog = self.push_schematic_modal_base(pass, panel, "@schematic.edittags");
                let tags = self.schematics_tag_names();
                for (index, tag) in tags.iter().take(6).enumerate() {
                    let row = Self::schematic_tag_editor_row_rect(dialog, index);
                    pass.push(RenderCommand::draw_sprite(
                        Self::settings_drawable_symbol("button"),
                        row,
                        [1.0, 1.0, 1.0, 0.82],
                        0.0,
                        Layer::END_PIXELED + 0.076 + index as f32 * 0.001,
                    ));
                    pass.push(RenderCommand::draw_text_styled(
                        desktop_ui_icon_glyph_or_label("upOpen", "up"),
                        Self::schematic_tag_editor_move_up_rect(row).center(),
                        [0.78, 0.88, 0.96, 1.0],
                        12.0,
                        0.0,
                        RenderTextStyle::new(RenderTextAlign::Center)
                            .with_vertical_align(RenderTextVerticalAlign::Center)
                            .with_integer_position(true),
                        Layer::END_PIXELED + 0.079 + index as f32 * 0.001,
                    ));
                    pass.push(RenderCommand::draw_text_styled(
                        desktop_ui_icon_glyph_or_label("downOpen", "down"),
                        Self::schematic_tag_editor_move_down_rect(row).center(),
                        [0.78, 0.88, 0.96, 1.0],
                        12.0,
                        0.0,
                        RenderTextStyle::new(RenderTextAlign::Center)
                            .with_vertical_align(RenderTextVerticalAlign::Center)
                            .with_integer_position(true),
                        Layer::END_PIXELED + 0.079 + index as f32 * 0.001,
                    ));
                    pass.push(RenderCommand::draw_text_styled(
                        format!(
                            "{} | {}",
                            tag,
                            self.schematic_cards
                                .iter()
                                .filter(|entry| entry.labels.iter().any(|label| label == tag))
                                .count()
                        ),
                        Self::schematic_tag_editor_select_rect(row).center(),
                        if self
                            .schematic_selected_tags
                            .iter()
                            .any(|selected| selected == tag)
                        {
                            [Pal::ACCENT.r, Pal::ACCENT.g, Pal::ACCENT.b, 1.0]
                        } else {
                            [0.78, 0.86, 0.92, 1.0]
                        },
                        11.0,
                        0.0,
                        RenderTextStyle::new(RenderTextAlign::Center)
                            .with_vertical_align(RenderTextVerticalAlign::Center)
                            .with_integer_position(true)
                            .with_outline(true),
                        Layer::END_PIXELED + 0.080 + index as f32 * 0.001,
                    ));
                    pass.push(RenderCommand::draw_text_styled(
                        desktop_ui_icon_glyph_or_label("pencil", "edit"),
                        Self::schematic_tag_editor_rename_rect(row).center(),
                        [0.82, 0.92, 1.0, 1.0],
                        12.0,
                        0.0,
                        RenderTextStyle::new(RenderTextAlign::Center)
                            .with_vertical_align(RenderTextVerticalAlign::Center)
                            .with_integer_position(true),
                        Layer::END_PIXELED + 0.081 + index as f32 * 0.001,
                    ));
                    pass.push(RenderCommand::draw_text_styled(
                        desktop_ui_icon_glyph_or_label("trash", "trash"),
                        Self::schematic_tag_editor_delete_rect(row).center(),
                        [1.0, 0.56, 0.54, 1.0],
                        12.0,
                        0.0,
                        RenderTextStyle::new(RenderTextAlign::Center)
                            .with_vertical_align(RenderTextVerticalAlign::Center)
                            .with_integer_position(true),
                        Layer::END_PIXELED + 0.081 + index as f32 * 0.001,
                    ));
                }
                let field = Self::schematic_tag_editor_text_field_rect(dialog);
                pass.push(RenderCommand::draw_sprite(
                    Self::settings_text_button_symbol("grayt", false, false),
                    field,
                    [1.0, 1.0, 1.0, 0.90],
                    0.0,
                    Layer::END_PIXELED + 0.083,
                ));
                pass.push(RenderCommand::draw_text_styled(
                    if self.schematic_tag_editor_text.is_empty() {
                        "@schematic.addtag".to_string()
                    } else {
                        self.schematic_tag_editor_text.clone()
                    },
                    RenderPoint::new(field.x + 12.0, field.center().y),
                    if self.schematic_tag_editor_text.is_empty() {
                        [0.60, 0.70, 0.78, 1.0]
                    } else {
                        [0.88, 0.94, 1.0, 1.0]
                    },
                    11.0,
                    0.0,
                    RenderTextStyle::new(RenderTextAlign::Start)
                        .with_vertical_align(RenderTextVerticalAlign::Center)
                        .with_integer_position(true),
                    Layer::END_PIXELED + 0.084,
                ));
                self.push_settings_text_button(
                    pass,
                    Self::schematic_tag_editor_new_text_rect(dialog),
                    "@schematic.texttag",
                    Some("add"),
                    Layer::END_PIXELED + 0.085,
                );
                self.push_settings_text_button(
                    pass,
                    Self::schematic_tag_editor_new_icon_rect(dialog),
                    "@schematic.icontag",
                    Some("add"),
                    Layer::END_PIXELED + 0.086,
                );
                self.push_settings_text_button(
                    pass,
                    Self::schematic_info_button_rect(dialog, 0),
                    "@back",
                    Some("left"),
                    Layer::END_PIXELED + 0.083,
                );
            }
            DesktopSchematicModal::Export { index } => {
                let title = self
                    .schematic_cards
                    .get(index)
                    .map(|entry| format!("@editor.export: {}", entry.name))
                    .unwrap_or_else(|| "@editor.export".to_string());
                let dialog = self.push_schematic_modal_base(pass, panel, title);
                let mut button_index = 0;
                if self
                    .schematic_cards
                    .get(index)
                    .map(|entry| !entry.has_steam_id)
                    .unwrap_or(false)
                {
                    self.push_schematic_modal_option_button(
                        pass,
                        dialog,
                        button_index,
                        "@schematic.shareworkshop",
                        "book",
                    );
                    button_index += 1;
                }
                self.push_schematic_modal_option_button(
                    pass,
                    dialog,
                    button_index,
                    "@schematic.copy",
                    "copy",
                );
                self.push_schematic_modal_option_button(
                    pass,
                    dialog,
                    button_index + 1,
                    "@schematic.exportfile",
                    "upload",
                );
                self.push_settings_text_button(
                    pass,
                    Self::schematic_info_button_rect(dialog, 0),
                    "@back",
                    Some("left"),
                    Layer::END_PIXELED + 0.083,
                );
            }
            DesktopSchematicModal::Edit { index } => {
                let title = self
                    .schematic_cards
                    .get(index)
                    .map(|entry| format!("@schematic.edit: {}", entry.name))
                    .unwrap_or_else(|| "@schematic.edit".to_string());
                let dialog = self.push_schematic_modal_base(pass, panel, title);
                pass.push(RenderCommand::draw_text_styled(
                    "@schematic.tags",
                    RenderPoint::new(dialog.x + 42.0, dialog.y + dialog.height - 92.0),
                    [0.72, 0.82, 0.9, 1.0],
                    11.0,
                    0.0,
                    RenderTextStyle::new(RenderTextAlign::Start)
                        .with_vertical_align(RenderTextVerticalAlign::Center)
                        .with_integer_position(true)
                        .with_outline(true),
                    Layer::END_PIXELED + 0.077,
                ));
                if let Some(entry) = self.schematic_cards.get(index) {
                    for (tag_index, tag) in entry.labels.iter().take(4).enumerate() {
                        let chip = Self::schematic_edit_owned_tag_chip_rect(dialog, tag_index);
                        pass.push(RenderCommand::draw_sprite(
                            Self::settings_drawable_symbol("button"),
                            chip,
                            [1.0, 1.0, 1.0, 0.82],
                            0.0,
                            Layer::END_PIXELED + 0.078 + tag_index as f32 * 0.001,
                        ));
                        pass.push(RenderCommand::draw_text_styled(
                            tag.clone(),
                            RenderPoint::new(chip.x + 8.0, chip.center().y),
                            [0.78, 0.86, 0.92, 1.0],
                            9.0,
                            0.0,
                            RenderTextStyle::new(RenderTextAlign::Start)
                                .with_vertical_align(RenderTextVerticalAlign::Center)
                                .with_integer_position(true),
                            Layer::END_PIXELED + 0.081 + tag_index as f32 * 0.001,
                        ));
                        pass.push(RenderCommand::draw_text_styled(
                            desktop_ui_icon_glyph_or_label("cancelSmall", "x"),
                            Self::schematic_edit_tag_remove_rect(chip).center(),
                            [1.0, 0.56, 0.54, 1.0],
                            10.0,
                            0.0,
                            RenderTextStyle::new(RenderTextAlign::Center)
                                .with_vertical_align(RenderTextVerticalAlign::Center)
                                .with_integer_position(true),
                            Layer::END_PIXELED + 0.082 + tag_index as f32 * 0.001,
                        ));
                    }
                    let available = self
                        .schematics_tag_names()
                        .into_iter()
                        .filter(|tag| !entry.labels.iter().any(|label| label == tag))
                        .collect::<Vec<_>>();
                    for (tag_index, tag) in available.iter().take(4).enumerate() {
                        let chip = Self::schematic_edit_available_tag_chip_rect(dialog, tag_index);
                        pass.push(RenderCommand::draw_sprite(
                            Self::settings_text_button_symbol("flatTogglet", false, false),
                            chip,
                            [1.0, 1.0, 1.0, 0.62],
                            0.0,
                            Layer::END_PIXELED + 0.077 + tag_index as f32 * 0.001,
                        ));
                        pass.push(RenderCommand::draw_text_styled(
                            format!("+{tag}"),
                            chip.center(),
                            [0.62, 0.74, 0.82, 1.0],
                            8.0,
                            0.0,
                            RenderTextStyle::new(RenderTextAlign::Center)
                                .with_vertical_align(RenderTextVerticalAlign::Center)
                                .with_integer_position(true),
                            Layer::END_PIXELED + 0.080 + tag_index as f32 * 0.001,
                        ));
                    }
                }
                self.push_schematic_label_add_controls(pass, dialog, 0.083);
                for (row, (label, value, height)) in [
                    ("@name", self.schematic_edit_name.as_str(), 42.0),
                    (
                        "@editor.description",
                        self.schematic_edit_description.as_str(),
                        86.0,
                    ),
                ]
                .into_iter()
                .enumerate()
                {
                    let y = dialog.y + dialog.height - 234.0 - row as f32 * 92.0;
                    pass.push(RenderCommand::draw_text_styled(
                        label,
                        RenderPoint::new(dialog.x + 42.0, y + height * 0.5),
                        [0.72, 0.82, 0.9, 1.0],
                        11.0,
                        0.0,
                        RenderTextStyle::new(RenderTextAlign::Start)
                            .with_vertical_align(RenderTextVerticalAlign::Center)
                            .with_integer_position(true)
                            .with_outline(true),
                        Layer::END_PIXELED + 0.077,
                    ));
                    let field = RenderRect::new(dialog.x + 170.0, y, dialog.width - 220.0, height);
                    pass.push(RenderCommand::draw_sprite(
                        Self::settings_text_button_symbol("grayt", false, false),
                        field,
                        [1.0, 1.0, 1.0, 0.90],
                        0.0,
                        Layer::END_PIXELED + 0.076 + row as f32 * 0.001,
                    ));
                    pass.push(RenderCommand::draw_text_styled(
                        value.to_string(),
                        RenderPoint::new(field.x + 12.0, field.center().y),
                        [0.88, 0.94, 1.0, 1.0],
                        11.0,
                        0.0,
                        RenderTextStyle::new(RenderTextAlign::Start)
                            .with_vertical_align(RenderTextVerticalAlign::Center)
                            .with_integer_position(true),
                        Layer::END_PIXELED + 0.079 + row as f32 * 0.001,
                    ));
                }
                self.push_settings_text_button(
                    pass,
                    Self::schematic_info_button_rect(dialog, 1),
                    "@ok",
                    Some("ok"),
                    Layer::END_PIXELED + 0.083,
                );
                self.push_settings_text_button(
                    pass,
                    Self::schematic_info_button_rect(dialog, 2),
                    "@cancel",
                    Some("cancel"),
                    Layer::END_PIXELED + 0.084,
                );
            }
            DesktopSchematicModal::IconTag { card_index } => {
                let title = self
                    .schematic_cards
                    .get(card_index)
                    .map(|entry| format!("@schematic.icontag: {}", entry.name))
                    .unwrap_or_else(|| "@schematic.icontag".to_string());
                let dialog = self.push_schematic_modal_base(pass, panel, title);
                let candidates = self.schematic_icon_tag_candidates();
                for (index, icon) in candidates.iter().take(24).enumerate() {
                    let rect = Self::schematic_icon_tag_button_rect(dialog, index);
                    pass.push(RenderCommand::draw_sprite(
                        Self::settings_text_button_symbol("grayt", false, false),
                        rect,
                        [1.0, 1.0, 1.0, 0.86],
                        0.0,
                        Layer::END_PIXELED + 0.076 + index as f32 * 0.001,
                    ));
                    pass.push(RenderCommand::draw_text_styled(
                        desktop_ui_icon_glyph_or_label(icon.java_name, icon.java_name),
                        rect.center(),
                        [0.92, 0.97, 1.0, 1.0],
                        14.0,
                        0.0,
                        RenderTextStyle::new(RenderTextAlign::Center)
                            .with_vertical_align(RenderTextVerticalAlign::Center)
                            .with_integer_position(true),
                        Layer::END_PIXELED + 0.079 + index as f32 * 0.001,
                    ));
                }
                self.push_settings_text_button(
                    pass,
                    Self::schematic_info_button_rect(dialog, 0),
                    "@back",
                    Some("left"),
                    Layer::END_PIXELED + 0.083,
                );
            }
        }
    }

