    fn push_active_menu_route_shell(&self, pass: &mut RenderPass, viewport: RenderViewport) {
        let Some(route) = self.active_menu_route else {
            return;
        };

        let panel = Self::active_menu_route_shell_panel_for_route(viewport, route);
        let dialog = BaseDialog::new(route.title());
        let stage_rect = RenderRect::new(viewport.x, viewport.y, viewport.width, viewport.height);
        for command in
            dialog.shell_render_commands(DialogShellLayout::from_stage_and_panel(stage_rect, panel))
        {
            pass.push(command);
        }
        pass.push(RenderCommand::stroke_rect(
            panel,
            [0.32, 0.42, 0.5, 0.95],
            2.0,
            Layer::END_PIXELED + 0.01,
        ));
        pass.push(RenderCommand::draw_text_styled(
            format!("upstream: {}", route.upstream_dialog()),
            RenderPoint::new(panel.x + panel.width * 0.5, panel.y + panel.height - 84.0),
            [0.72, 0.82, 0.9, 1.0],
            14.0,
            0.0,
            RenderTextStyle::new(RenderTextAlign::Center)
                .with_vertical_align(RenderTextVerticalAlign::Center)
                .with_integer_position(true),
            Layer::END_PIXELED + 0.02,
        ));
        if route == DesktopMenuRoute::About {
            self.push_about_route_page(pass, panel);
        } else if route == DesktopMenuRoute::Join {
            self.push_join_route_page(pass, panel);
        } else if route == DesktopMenuRoute::LoadGame {
            self.push_load_game_route_page(pass, panel);
        } else if route == DesktopMenuRoute::Database {
            self.push_database_route_page(pass, panel);
        } else if matches!(
            route,
            DesktopMenuRoute::CustomGame | DesktopMenuRoute::Editor
        ) {
            self.push_map_list_route_page(pass, panel, route);
        } else if route == DesktopMenuRoute::Schematics {
            self.push_schematics_route_page(pass, panel);
        } else if route == DesktopMenuRoute::Mods {
            self.push_mods_route_page(pass, panel);
        } else if route == DesktopMenuRoute::Settings
            && self.settings_dialog_state.page == DesktopSettingsPage::Main
        {
            self.push_settings_main_menu_buttons(pass, panel);
        } else {
            for (index, line) in self.active_menu_route_shell_lines(route).iter().enumerate() {
                if route == DesktopMenuRoute::Settings && line.starts_with("button:") {
                    continue;
                }
                pass.push(RenderCommand::draw_text_styled(
                    line.clone(),
                    RenderPoint::new(
                        panel.x + panel.width * 0.5,
                        panel.y + panel.height - 118.0 - index as f32 * 20.0,
                    ),
                    [0.56, 0.64, 0.72, 1.0],
                    12.0,
                    0.0,
                    RenderTextStyle::new(RenderTextAlign::Center)
                        .with_vertical_align(RenderTextVerticalAlign::Center)
                        .with_integer_position(true),
                    Layer::END_PIXELED + 0.02,
                ));
            }
            if route == DesktopMenuRoute::Settings {
                self.push_settings_route_controls(pass, panel);
                self.push_settings_route_buttons(pass, panel);
            }
        }
        if route == DesktopMenuRoute::Settings {
            self.push_settings_child_dialog(pass, panel);
        }
        if let Some(primary_rect) =
            Self::active_menu_route_shell_primary_rect_for_viewport(viewport, route)
        {
            let label = self
                .active_menu_route_shell_primary_label(route)
                .unwrap_or("OPEN");
            pass.push(RenderCommand::fill_rect(
                primary_rect,
                [0.18, 0.35, 0.58, 0.92],
                Layer::END_PIXELED + 0.03,
            ));
            pass.push(RenderCommand::draw_sprite(
                "button.9",
                primary_rect,
                [1.0, 1.0, 1.0, 1.0],
                0.0,
                Layer::END_PIXELED + 0.035,
            ));
            pass.push(RenderCommand::stroke_rect(
                primary_rect,
                [0.58, 0.75, 0.92, 1.0],
                1.0,
                Layer::END_PIXELED + 0.04,
            ));
            pass.push(RenderCommand::draw_text_styled(
                label,
                primary_rect.center(),
                [0.95, 0.98, 1.0, 1.0],
                16.0,
                0.0,
                RenderTextStyle::new(RenderTextAlign::Center)
                    .with_vertical_align(RenderTextVerticalAlign::Center)
                    .with_integer_position(true)
                    .with_outline(true),
                Layer::END_PIXELED + 0.05,
            ));
        }
        if let Some(copy_rect) = Self::discord_route_shell_copy_rect_for_viewport(viewport, route) {
            pass.push(RenderCommand::fill_rect(
                copy_rect,
                [0.16, 0.24, 0.32, 0.9],
                Layer::END_PIXELED + 0.03,
            ));
            pass.push(RenderCommand::draw_sprite(
                "button.9",
                copy_rect,
                [1.0, 1.0, 1.0, 1.0],
                0.0,
                Layer::END_PIXELED + 0.035,
            ));
            pass.push(RenderCommand::stroke_rect(
                copy_rect,
                [0.48, 0.68, 0.82, 1.0],
                1.0,
                Layer::END_PIXELED + 0.04,
            ));
            pass.push(RenderCommand::draw_text_styled(
                "COPYLINK",
                copy_rect.center(),
                [0.9, 0.96, 1.0, 1.0],
                15.0,
                0.0,
                RenderTextStyle::new(RenderTextAlign::Center)
                    .with_vertical_align(RenderTextVerticalAlign::Center)
                    .with_integer_position(true)
                    .with_outline(true),
                Layer::END_PIXELED + 0.05,
            ));
        }
    }

