    #[test]
    fn desktop_launcher_emits_unit_engine_circles_for_elevated_snapshot() {
        let mut launcher = DesktopLauncher::new(Vec::new());
        let dagger = launcher
            .content_loader
            .unit_by_name("dagger")
            .expect("base content should include dagger")
            .clone();

        let mut unit = UnitComp::new(7401, dagger, TeamId(1));
        unit.add();
        unit.set_pos(80.0, 96.0);
        unit.set_rotation(90.0);
        unit.elevation = 1.0;
        launcher
            .runtime
            .client_unit_snapshot_entities
            .insert(7401, unit);

        let viewport = RenderViewport::new(0.0, 0.0, 160.0, 160.0);
        let camera = RenderCamera::new(RenderPoint::new(80.0, 80.0), viewport);
        let minimap_camera = MinimapCamera::new(80.0, 80.0, 160.0, 160.0);
        let frame = launcher.graphics_frame_for_render(
            22,
            camera,
            viewport,
            minimap_camera,
            sample_minimap_overlay_input(false),
        );
        let render_frame = frame.bundle.render_frame.as_ref().unwrap();
        let overlay = render_frame
            .passes
            .iter()
            .find(|pass| {
                pass.kind == RenderPassKind::Overlay
                    && pass.commands.iter().any(|command| {
                        matches!(command, RenderCommand::DrawSprite { symbol, .. } if symbol == "dagger")
                    })
            })
            .expect("unit snapshot should emit overlay pass");

        let engine_circles = overlay
            .commands
            .iter()
            .filter_map(|command| match command {
                RenderCommand::DrawCircle {
                    center,
                    radius,
                    color,
                    filled,
                    layer,
                    ..
                } => Some((*center, *radius, *color, *filled, *layer)),
                _ => None,
            })
            .collect::<Vec<_>>();

        assert_eq!(engine_circles.len(), 2);
        assert_eq!(engine_circles[0].0, RenderPoint::new(80.0, 91.0));
        assert!((engine_circles[0].1 - 2.5).abs() < 0.0001);
        assert_eq!(
            engine_circles[0].2,
            super::rgba8888_to_render_color(0xffd37fff, 1.0)
        );
        assert!(engine_circles[0].3);
        assert_eq!(engine_circles[0].4, Layer::FLYING_UNIT);

        assert!((engine_circles[1].0.x - 80.0).abs() < 0.0001);
        assert!((engine_circles[1].0.y - 91.625).abs() < 0.0001);
        assert!((engine_circles[1].1 - 1.25).abs() < 0.0001);
        assert_eq!(
            engine_circles[1].2,
            super::rgba8888_to_render_color(0xffffffff, 1.0)
        );
        assert!(engine_circles[1].3);
        assert_eq!(engine_circles[1].4, Layer::FLYING_UNIT);

        launcher.render_time = std::f32::consts::PI;
        let pulsed_frame = launcher.graphics_frame_for_render(
            23,
            camera,
            viewport,
            minimap_camera,
            sample_minimap_overlay_input(false),
        );
        let pulsed_render_frame = pulsed_frame.bundle.render_frame.as_ref().unwrap();
        let pulsed_overlay = pulsed_render_frame
            .passes
            .iter()
            .find(|pass| {
                pass.kind == RenderPassKind::Overlay
                    && pass.commands.iter().any(|command| {
                        matches!(command, RenderCommand::DrawSprite { symbol, .. } if symbol == "dagger")
                    })
            })
            .expect("pulsed unit snapshot should emit overlay pass");
        let pulsed_engine_radius = pulsed_overlay
            .commands
            .iter()
            .filter_map(|command| match command {
                RenderCommand::DrawCircle { radius, .. } => Some(*radius),
                _ => None,
            })
            .next()
            .expect("pulsed unit engine should still emit outer circle");
        assert!((pulsed_engine_radius - 3.125).abs() < 0.0001);
    }

    #[test]
    fn desktop_launcher_emits_unit_trail_lines_before_engine_circles() {
        let mut launcher = DesktopLauncher::new(Vec::new());
        let mut unit_type = UnitType::new(9901, "trail-test");
        unit_type.trail_length = 4;
        unit_type.trail_color_rgba = Some(0x6bb6ffff);
        unit_type.engine_size = 2.0;
        unit_type.engine_offset = 4.0;
        unit_type.use_engine_elevation = true;

        let mut unit = UnitComp::new(7501, unit_type, TeamId(1));
        unit.add();
        unit.set_pos(32.0, 32.0);
        unit.set_rotation(90.0);
        unit.elevation = 1.0;

        let mut trail = UnitTrailState::new(4, 1.0);
        trail.update(20.0, 20.0, 1.0, 1.0);
        trail.update(28.0, 20.0, 3.0, 1.0);
        unit.trail = Some(trail);

        launcher
            .runtime
            .client_unit_snapshot_entities
            .insert(7501, unit);

        let viewport = RenderViewport::new(0.0, 0.0, 96.0, 96.0);
        let camera = RenderCamera::new(RenderPoint::new(48.0, 48.0), viewport);
        let minimap_camera = MinimapCamera::new(48.0, 48.0, 96.0, 96.0);
        let frame = launcher.graphics_frame_for_render(
            24,
            camera,
            viewport,
            minimap_camera,
            sample_minimap_overlay_input(false),
        );
        let render_frame = frame.bundle.render_frame.as_ref().unwrap();
        let overlay = render_frame
            .passes
            .iter()
            .find(|pass| {
                pass.kind == RenderPassKind::Overlay
                    && pass.commands.iter().any(|command| {
                        matches!(command, RenderCommand::DrawLine { from, to, .. }
                            if *from == RenderPoint::new(20.0, 20.0)
                                && *to == RenderPoint::new(28.0, 20.0))
                    })
            })
            .expect("unit snapshot should emit a trail line in the overlay pass");

        let trail_line_index = overlay
            .commands
            .iter()
            .position(|command| {
                matches!(command, RenderCommand::DrawLine { from, to, .. }
                    if *from == RenderPoint::new(20.0, 20.0)
                        && *to == RenderPoint::new(28.0, 20.0))
            })
            .expect("unit trail should emit a visible trail line");
        let engine_circle_index = overlay
            .commands
            .iter()
            .position(|command| {
                matches!(command, RenderCommand::DrawCircle { center, .. }
                    if *center == RenderPoint::new(32.0, 28.0))
            })
            .expect("unit engine should still emit engine circles");
        assert!(
            trail_line_index < engine_circle_index,
            "unit trail should render before engine glow like Java UnitType.drawTrail()/drawEngine order"
        );

        match &overlay.commands[trail_line_index] {
            RenderCommand::DrawLine {
                from,
                to,
                stroke,
                color,
                layer,
            } => {
                assert_eq!(*from, RenderPoint::new(20.0, 20.0));
                assert_eq!(*to, RenderPoint::new(28.0, 20.0));
                assert!((*stroke - 2.0).abs() < 0.0001);
                let expected = super::rgba8888_to_render_color(0x6bb6ffff, 1.0);
                assert!((color[0] - expected[0]).abs() < 0.0001);
                assert!((color[1] - expected[1]).abs() < 0.0001);
                assert!((color[2] - expected[2]).abs() < 0.0001);
                assert!((color[3] - expected[3] * 0.5).abs() < 0.0001);
                assert_eq!(*layer, Layer::FLYING_UNIT);
            }
            other => panic!("expected unit trail DrawLine, got {other:?}"),
        }
    }

    #[test]
    fn desktop_launcher_update_ticks_client_unit_snapshot_trails() {
        let mut launcher = DesktopLauncher::new(Vec::new());
        let mut unit_type = UnitType::new(9905, "desktop-trail-test");
        unit_type.trail_length = 4;
        unit_type.engine_offset = 4.0;
        unit_type.engine_size = 2.0;
        unit_type.use_engine_elevation = true;

        let mut unit = UnitComp::new(7505, unit_type, TeamId(1));
        unit.add();
        unit.set_pos(32.0, 32.0);
        unit.set_rotation(0.0);
        unit.elevation = 1.0;
        launcher
            .runtime
            .client_unit_snapshot_entities
            .insert(7505, unit);

        launcher.update();
        {
            let unit = launcher
                .runtime
                .client_unit_snapshot_entities
                .get_mut(&7505)
                .unwrap();
            unit.set_pos(40.0, 32.0);
        }
        launcher.update();

        let unit = launcher
            .runtime
            .client_unit_snapshot_entities
            .get(&7505)
            .unwrap();
        let segments = unit
            .trail
            .as_ref()
            .expect("desktop update should tick unit trail")
            .segment_plans();
        assert_eq!(segments.len(), 2);
        assert!((segments[0].start.x - 28.0).abs() < 0.0001);
        assert!((segments[0].start.y - 32.0).abs() < 0.0001);
        assert!((segments[0].end.x - 36.0).abs() < 0.0001);
        assert!((segments[0].end.y - 32.0).abs() < 0.0001);
    }

    #[test]
    fn desktop_launcher_routes_minimap_overlay_plan_into_minimap_render_pass() {
        let mut launcher = DesktopLauncher::new(Vec::new());
        launcher.game_state.world.resize(16, 16);
        launcher.texture_atlas = TextureAtlasPlan::from_virtual_source_paths([
            "sprites/dagger.png",
            "sprites/units.png",
        ]);

        let mut minimap_input = sample_minimap_overlay_input(true);
        minimap_input.net_active = true;
        minimap_input.show_pings = true;
        minimap_input.show_spawns = true;
        minimap_input.has_spawns = true;
        minimap_input.waves = true;
        minimap_input.wave_team_color = 0xff00ffff;
        minimap_input.drop_zone_radius = 20.0;
        minimap_input.time = 180.0;
        minimap_input.global_time = 15.0;
        minimap_input.units.push(MinimapEntitySnapshot {
            entity_id: 42,
            x: 64.0,
            y: 64.0,
            rotation: 180.0,
            team_color: 0x33cc66ff,
            region: "dagger".into(),
            draw_minimap: true,
            hidden_by_fog: false,
        });
        minimap_input.players.push(MinimapPlayerSnapshot {
            player_id: 7,
            x: 72.0,
            y: 80.0,
            name: "pilot".into(),
            color: 0xffffffff,
            dead: false,
            ping_time: 1.0,
            ping_x: 80.0,
            ping_y: 88.0,
            ping_text: Some("go".into()),
        });
        minimap_input.markers.push(MinimapMarkerSnapshot {
            id: 3,
            x: 96.0,
            y: 48.0,
            label: "A".into(),
            minimap: true,
        });
        minimap_input.indicators.push(MinimapIndicatorSnapshot {
            tile: MinimapTilePos::new(2, 3),
            time: 35.0,
            block_offset_tiles: 1.0,
        });
        minimap_input
            .spawns
            .push(MinimapSpawnSnapshot { x: 32.0, y: 40.0 });

        let viewport = RenderViewport::new(0.0, 0.0, 128.0, 128.0);
        let camera = RenderCamera::new(RenderPoint::new(64.0, 64.0), viewport);
        let minimap_camera = MinimapCamera::new(64.0, 64.0, 128.0, 128.0);
        let frame =
            launcher.graphics_frame_for_render(16, camera, viewport, minimap_camera, minimap_input);

        let minimap_sidecar = frame
            .bundle
            .minimap_overlay
            .as_ref()
            .expect("graphics bridge should still carry minimap overlay sidecar state");
        assert!(
            !minimap_sidecar.commands.is_empty(),
            "minimap overlay sidecar should remain observable while commands are lowered"
        );

        let render_frame = frame.bundle.render_frame.as_ref().unwrap();
        let minimap_pass = render_frame
            .passes
            .iter()
            .find(|pass| pass.kind == RenderPassKind::Minimap)
            .expect("minimap overlay commands should be lowered into a Minimap render pass");
        assert_eq!(minimap_pass.target, RenderTarget::Screen);
        assert_eq!(minimap_pass.order, RenderPassKind::Minimap.default_order());

        let expected_tint = super::rgba8888_to_render_color(0x33cc66ff, 1.0);
        assert!(minimap_pass.commands.iter().any(|command| {
            matches!(
                command,
                RenderCommand::DrawSprite {
                    symbol,
                    tint,
                    rotation,
                    ..
                } if symbol == "dagger"
                    && *tint == expected_tint
                    && (*rotation - 90.0).abs() < f32::EPSILON
            )
        }));
        assert!(minimap_pass.commands.iter().any(
            |command| matches!(command, RenderCommand::DrawText { text, .. } if text == "pilot")
        ));
        assert!(minimap_pass.commands.iter().any(
            |command| matches!(command, RenderCommand::DrawText { text, .. } if text == "go")
        ));
        assert!(minimap_pass
            .commands
            .iter()
            .any(|command| matches!(command, RenderCommand::DrawText { text, .. } if text == "A")));
        assert!(minimap_pass.commands.iter().any(|command| {
            matches!(
                command,
                RenderCommand::DrawPolygon {
                    center,
                    radius,
                    sides: 4,
                    filled: false,
                    ..
                } if *center == RenderPoint::new(80.0, 88.0)
                    && (*radius - 12.0).abs() < f32::EPSILON
            )
        }));
        assert!(minimap_pass.commands.iter().any(|command| {
            matches!(
                command,
                RenderCommand::DrawPolygon {
                    center,
                    radius,
                    sides: 3,
                    rotation,
                    filled: true,
                    ..
                } if *center == RenderPoint::new(80.0, 118.0)
                    && (*radius - 10.0).abs() < f32::EPSILON
                    && (*rotation + 90.0).abs() < f32::EPSILON
            )
        }));
        let expected_ping_color = super::rgba8888_to_render_color(0xffffffff, 1.0);
        assert!(minimap_pass.commands.iter().any(|command| {
            matches!(
                command,
                RenderCommand::DrawText {
                    text,
                    position,
                    size,
                    color,
                    ..
                } if text == "pilot"
                    && *position == RenderPoint::new(80.0, 153.0)
                    && (*size - 7.0).abs() < f32::EPSILON
                    && *color == expected_ping_color
            )
        }));
        let expected_indicator_color =
            super::minimap_overlay_lerp_color(0xffa500ff, 0xff2400ff, 0.5);
        assert!(minimap_pass.commands.iter().any(|command| {
            matches!(
                command,
                RenderCommand::DrawCircle {
                    center,
                    color,
                    filled: false,
                    ..
                } if *center == RenderPoint::new(28.0, 36.0)
                    && *color == expected_indicator_color
            )
        }));
        assert!(minimap_pass.commands.iter().any(|command| {
            matches!(
                command,
                RenderCommand::DrawSprite {
                    symbol,
                    rect,
                    tint,
                    ..
                } if symbol == "units"
                    && *rect == RenderRect::from_center(RenderPoint::new(32.0, 40.0), 10.0, 10.0)
                    && *tint == super::rgba8888_to_render_color(0xff00ffff, 1.0)
            )
        }));
        assert!(minimap_pass.commands.iter().any(|command| {
            matches!(
                command,
                RenderCommand::DrawCircle {
                    center,
                    radius,
                    color,
                    filled: false,
                    ..
                } if *center == RenderPoint::new(32.0, 40.0)
                    && (*radius - 20.0).abs() < f32::EPSILON
                    && *color == super::rgba8888_to_render_color(0xff00ffff, 1.0)
            )
        }));
        assert!(minimap_pass.commands.iter().any(|command| {
            matches!(
                command,
                RenderCommand::DrawCircle {
                    center,
                    radius,
                    filled: false,
                    ..
                } if *center == RenderPoint::new(32.0, 40.0)
                    && (*radius - 17.5).abs() < 0.001
            )
        }));

        let mut renderer = HeadlessDesktopGraphicsRenderer::default();
        renderer.render_graphics_frame(&frame);
        assert!(renderer
            .last_opengl_backend_executor_state
            .sprite_texture_bindings
            .iter()
            .any(|binding| binding.symbol == "dagger"));
        assert!(renderer
            .last_opengl_backend_executor_state
            .sprite_texture_bindings
            .iter()
            .any(|binding| binding.symbol == "units"));
        assert!(
            renderer
                .last_opengl_backend_executor_state
                .draw_text_commands
                >= 4
        );
    }

    #[test]
    fn desktop_launcher_block_render_plan_uses_world_tile_and_runtime_building_snapshots() {
        let mut launcher = DesktopLauncher::new(Vec::new());
        let wall_large = launcher
            .content_loader
            .block_by_name("copper-wall-large")
            .unwrap()
            .base()
            .clone();

        let tile_pos = {
            let world = &mut launcher.game_state.world;
            world.resize(3, 3);
            let tile = world.tile_mut(1, 1).unwrap();
            tile.block = wall_large.id;
            let tile_pos = tile.pos();
            tile.build = Some(mindustry_core::mindustry::world::BuildingRef {
                tile_pos,
                block: wall_large.id,
                team: 7,
                rotation: 2,
            });
            tile_pos
        };

        let mut building = BuildingComp::new(tile_pos, wall_large.clone(), TeamId(7));
        building.rotation = 2;
        building.health = building.max_health * 0.5;
        building.was_visible = true;
        building.was_damaged = true;
        building.visible_flags = 1;
        launcher.runtime.buildings.push(building);

        let viewport = RenderViewport::new(8.0, 8.0, 8.0, 8.0);
        let camera = RenderCamera::new(RenderPoint::new(12.0, 12.0), viewport);
        let plan = launcher.block_render_plan(camera, viewport).unwrap();

        assert_eq!(plan.tile_passes.len(), 1);
        assert_eq!(plan.tile_passes[0].stage, BlockDrawStage::TileBase);
        assert_eq!(plan.tile_passes[0].tiles.len(), 1);

        let tile = &plan.tile_passes[0].tiles[0];
        assert_eq!(tile.coord, TileCoord::new(1, 1));
        assert_eq!(tile.block, "copper-wall-large");
        assert_eq!(tile.cache_layer, CacheLayer::Normal);
        assert!(!tile.draw_custom_shadow);
        assert!(!tile.emits_light);
        assert!(tile.obstructs_light);

        assert_eq!(plan.building_passes[0].stage, BlockDrawStage::BuildingBase);
        let building = &plan.building_passes[0].buildings[0];
        assert_eq!(building.block, "copper-wall-large");
        assert_eq!(building.cache_layer, CacheLayer::Normal);
        assert_eq!(building.size, 2);
        assert_eq!(building.rotation, 2);
        assert_eq!(building.team, 7);
        assert!(building.visible);
        assert!(building.was_visible);
        assert!(building.damaged);
        assert!((building.health_fraction - 0.5).abs() < f32::EPSILON);
        assert_eq!(plan.cracks.len(), 1);
        assert_eq!(plan.cracks[0].region_symbol(), "cracks-2-4");
        assert!(plan
            .building_passes
            .iter()
            .any(|pass| pass.stage == BlockDrawStage::BuildingCracks));
    }

    #[test]
    fn desktop_launcher_block_render_plan_carries_runtime_visual_snapshot_into_building_pass() {
        let mut launcher = DesktopLauncher::new(Vec::new());
        let smelter = launcher
            .content_loader
            .block_by_name("silicon-smelter")
            .unwrap()
            .base()
            .clone();

        let tile_pos = {
            let world = &mut launcher.game_state.world;
            world.resize(4, 4);
            let tile = world.tile_mut(1, 1).unwrap();
            tile.block = smelter.id;
            let tile_pos = tile.pos();
            tile.build = Some(mindustry_core::mindustry::world::BuildingRef {
                tile_pos,
                block: smelter.id,
                team: 3,
                rotation: 1,
            });
            tile_pos
        };

        let mut building = BuildingComp::new(tile_pos, smelter, TeamId(3));
        building.rotation = 1;
        launcher.runtime.add_building(building);
        launcher.runtime.crafting_runtime_states.insert(
            tile_pos,
            mindustry_core::mindustry::core::game_runtime::GameRuntimeCraftingBlockState::GenericCrafter(
                mindustry_core::mindustry::world::blocks::production::GenericCrafterState {
                    progress: 0.25,
                    total_progress: 13.0,
                    warmup: 0.5,
                },
            ),
        );
        let viewport = RenderViewport::new(8.0, 8.0, 8.0, 8.0);
        let camera = RenderCamera::new(RenderPoint::new(12.0, 12.0), viewport);
        let plan = launcher.block_render_plan(camera, viewport).unwrap();
        let building = plan
            .building_passes
            .iter()
            .flat_map(|pass| pass.buildings.iter())
            .find(|building| building.coord == TileCoord::new(1, 1))
            .expect("runtime building should enter block renderer plan");
        let visual_runtime = building
            .visual_runtime
            .as_ref()
            .expect("runtime visual snapshot should be attached to building plan");

        assert_eq!(visual_runtime.progress, Some(0.25));
        assert_eq!(visual_runtime.total_progress, Some(13.0));
        assert_eq!(visual_runtime.warmup, Some(0.5));
        assert!(visual_runtime.liquid.is_none());
        let power = visual_runtime
            .power
            .as_ref()
            .expect("smelter power module status should be mirrored into visual runtime");
        assert_eq!(power.status, Some(0.0));
        assert_eq!(power.production_efficiency, None);
        assert!(visual_runtime.turret.is_none());

        assert_eq!(plan.block_builds.len(), 1);
        let block_build = &plan.block_builds[0];
        assert_eq!(block_build.coord, TileCoord::new(1, 1));
        assert_eq!(block_build.block, "silicon-smelter");
        assert_eq!(block_build.region, "silicon-smelter");
        assert_eq!(
            block_build.regions,
            vec![
                String::from("silicon-smelter"),
                String::from("silicon-smelter-top")
            ]
        );
        assert_eq!(block_build.progress, 0.25);
        assert_eq!(block_build.time, 13.0);
        assert_eq!(block_build.alpha, 0.5);
    }

