    #[test]
    fn desktop_graphics_opengl_shader_lifecycle_reload_resolving_replaces_cached_program_handle() {
        let load_plan = ShaderCatalog::init_plan();
        let lifecycle_plan =
            super::DesktopGraphicsOpenGlBackendShaderLifecycleCommandPlan::from_load_plan(
                &load_plan,
            );
        let mut executor =
            super::DesktopGraphicsResolvingOpenGlBackendShaderLifecycleExecutor::default();
        lifecycle_plan.drive_shader_lifecycle_command_sink(&mut executor);
        let old_mesh_program = *executor.cache.programs.get("shader:Mesh").unwrap();
        let before_reload = executor.commands.len();

        let reload_lifecycle_plan =
            super::DesktopGraphicsOpenGlBackendShaderLifecycleCommandPlan::from_reload_plan(
                &ShaderCatalog::reload_plan(),
            );
        reload_lifecycle_plan.drive_shader_lifecycle_command_sink(&mut executor);
        assert_eq!(
            executor.commands[before_reload],
            super::DesktopGraphicsOpenGlBackendResolvedShaderLifecycleCommand::DeleteProgram {
                shader: ShaderId::Mesh,
                program_key: "shader:Mesh".into(),
                program_handle: Some(old_mesh_program),
            }
        );

        let new_mesh_program = *executor.cache.programs.get("shader:Mesh").unwrap();
        assert_ne!(old_mesh_program, new_mesh_program);
        assert_eq!(
            executor.commands[before_reload + 7],
            super::DesktopGraphicsOpenGlBackendResolvedShaderLifecycleCommand::CreateProgram {
                shader: ShaderId::Mesh,
                program_key: "shader:Mesh".into(),
                program_handle: new_mesh_program,
                previous_program_handle: None,
            }
        );
        assert_eq!(executor.cache.shaders.len(), 0);
        assert_eq!(executor.cache.programs.len(), ShaderId::INIT_ORDER.len());
    }

    fn desktop_shader_test_asset_root(label: &str) -> std::path::PathBuf {
        let root = std::env::temp_dir().join(format!(
            "mindustry-shader-source-{label}-{}-{}",
            std::process::id(),
            std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .unwrap()
                .as_nanos()
        ));
        std::fs::create_dir_all(root.join("shaders")).unwrap();
        root
    }

    fn write_shader_source(root: &std::path::Path, source_path: &str, text: &str) {
        let path = root.join(source_path);
        if let Some(parent) = path.parent() {
            std::fs::create_dir_all(parent).unwrap();
        }
        std::fs::write(path, text).unwrap();
    }

    fn desktop_mesh_shader_task() -> mindustry_core::mindustry::graphics::ShaderLoadTask {
        ShaderCatalog::init_plan()
            .tasks
            .into_iter()
            .find(|task| task.shader == ShaderId::Mesh)
            .unwrap()
    }

    fn desktop_shader_source_file(
        stage: super::DesktopGraphicsOpenGlBackendShaderStage,
        source_path: &str,
        source_text: &str,
    ) -> super::DesktopGraphicsOpenGlBackendShaderSourceFile {
        super::DesktopGraphicsOpenGlBackendShaderSourceFile {
            shader: ShaderId::Mesh,
            stage,
            source_path: source_path.into(),
            file_path: std::path::PathBuf::from(source_path),
            source_text: source_text.into(),
        }
    }

    #[test]
    fn desktop_graphics_opengl_shader_source_loader_reads_vertex_and_fragment_sources() {
        let root = desktop_shader_test_asset_root("success");
        write_shader_source(
            &root,
            "shaders/mesh.vert",
            "attribute vec3 a_position;\r\nvoid main(){}\r\n",
        );
        write_shader_source(
            &root,
            "shaders/planet.frag",
            "void main(){ gl_FragColor = vec4(1.0); }\r\n",
        );
        let task = ShaderCatalog::init_plan()
            .tasks
            .into_iter()
            .find(|task| task.shader == ShaderId::Mesh)
            .unwrap();
        let loader = super::DesktopGraphicsOpenGlBackendShaderSourceLoader::new(&root);
        let sources = loader.load_program_sources(&task).unwrap();

        assert_eq!(sources.shader, ShaderId::Mesh);
        assert_eq!(sources.program_key, "shader:Mesh");
        assert_eq!(sources.vertex.source_path, task.source.vertex_path());
        assert_eq!(sources.fragment.source_path, task.source.fragment_path());
        assert_eq!(sources.vertex.file_path, root.join("shaders/mesh.vert"));
        assert_eq!(sources.fragment.file_path, root.join("shaders/planet.frag"));
        assert_eq!(
            sources.vertex.source_text,
            "attribute vec3 a_position;\nvoid main(){}\n"
        );
        assert!(sources.fragment.source_text.contains("gl_FragColor"));
    }

    #[test]
    fn desktop_graphics_opengl_shader_source_loader_reports_missing_empty_and_empty_path() {
        let root = desktop_shader_test_asset_root("errors");
        write_shader_source(&root, "shaders/mesh.vert", "void main(){}\n");
        let task = ShaderCatalog::init_plan()
            .tasks
            .into_iter()
            .find(|task| task.shader == ShaderId::Mesh)
            .unwrap();
        let loader = super::DesktopGraphicsOpenGlBackendShaderSourceLoader::new(&root);

        assert!(matches!(
            loader.load_program_sources(&task),
            Err(super::DesktopGraphicsOpenGlBackendShaderSourceLoadError::ReadSource {
                shader: ShaderId::Mesh,
                stage: super::DesktopGraphicsOpenGlBackendShaderStage::Fragment,
                ref source_path,
                ..
            }) if source_path == "shaders/planet.frag"
        ));

        write_shader_source(&root, "shaders/planet.frag", "\r\n");
        assert!(matches!(
            loader.load_program_sources(&task),
            Err(super::DesktopGraphicsOpenGlBackendShaderSourceLoadError::EmptySource {
                shader: ShaderId::Mesh,
                stage: super::DesktopGraphicsOpenGlBackendShaderStage::Fragment,
                ref source_path,
                ..
            }) if source_path == "shaders/planet.frag"
        ));

        assert!(matches!(
            loader.load_stage_source(
                ShaderId::Mesh,
                super::DesktopGraphicsOpenGlBackendShaderStage::Vertex,
                ""
            ),
            Err(
                super::DesktopGraphicsOpenGlBackendShaderSourceLoadError::EmptySourcePath {
                    shader: ShaderId::Mesh,
                    stage: super::DesktopGraphicsOpenGlBackendShaderStage::Vertex,
                }
            )
        ));
    }

    #[test]
    fn desktop_graphics_opengl_shader_preprocess_applies_prepend_precision_and_gl30_rewrites() {
        let options = super::DesktopGraphicsOpenGlBackendShaderPreprocessOptions {
            prepend_vertex_code: "// vertex-prepend\n".into(),
            prepend_fragment_code: "// fragment-prepend\n".into(),
            gl30: true,
            ..Default::default()
        };

        let vertex = desktop_shader_source_file(
            super::DesktopGraphicsOpenGlBackendShaderStage::Vertex,
            "shaders/mesh.vert",
            "attribute vec3 a_position;\nvarying vec2 v_texCoords;\nvoid main(){}\n",
        );
        let vertex = vertex.preprocess(&options).unwrap();
        assert!(vertex.source_text.starts_with("#version 150\n"));
        assert!(vertex.source_text.contains("// vertex-prepend"));
        assert!(vertex.source_text.contains("in vec3 a_position;"));
        assert!(vertex.source_text.contains("out vec2 v_texCoords;"));

        let fragment = desktop_shader_source_file(
            super::DesktopGraphicsOpenGlBackendShaderStage::Fragment,
            "shaders/planet.frag",
            "#define HIGHP\nvarying vec2 v_texCoords;\nvoid main(){ gl_FragColor = texture2D(u_texture, v_texCoords); }\n",
        );
        let fragment = fragment.preprocess(&options).unwrap();
        assert!(fragment
            .source_text
            .starts_with("#version 150\nout vec4 fragColor;\n"));
        assert!(fragment.source_text.contains("precision highp float;"));
        assert!(fragment.source_text.contains("// fragment-prepend"));
        assert!(fragment.source_text.contains("in vec2 v_texCoords;"));
        assert!(fragment
            .source_text
            .contains("fragColor = texture(u_texture, v_texCoords);"));
    }

    #[test]
    fn desktop_graphics_opengl_shader_preprocess_rejects_explicit_version_and_gles_blocks() {
        let versioned = desktop_shader_source_file(
            super::DesktopGraphicsOpenGlBackendShaderStage::Vertex,
            "shaders/mesh.vert",
            "#version 120\nvoid main(){}\n",
        );
        assert!(matches!(
            versioned.preprocess(
                &super::DesktopGraphicsOpenGlBackendShaderPreprocessOptions::default()
            ),
            Err(super::DesktopGraphicsOpenGlBackendShaderPreprocessError::ExplicitVersion {
                shader: ShaderId::Mesh,
                stage: super::DesktopGraphicsOpenGlBackendShaderStage::Vertex,
                ref source_path,
            }) if source_path == "shaders/mesh.vert"
        ));

        let gles = desktop_shader_source_file(
            super::DesktopGraphicsOpenGlBackendShaderStage::Fragment,
            "shaders/planet.frag",
            "#ifdef GL_ES\nprecision mediump float;\n#endif\nvoid main(){}\n",
        );
        assert!(matches!(
            gles.preprocess(
                &super::DesktopGraphicsOpenGlBackendShaderPreprocessOptions::default()
            ),
            Err(super::DesktopGraphicsOpenGlBackendShaderPreprocessError::ExplicitGlesBlock {
                shader: ShaderId::Mesh,
                stage: super::DesktopGraphicsOpenGlBackendShaderStage::Fragment,
                ref source_path,
            }) if source_path == "shaders/planet.frag"
        ));

        let options = super::DesktopGraphicsOpenGlBackendShaderPreprocessOptions {
            prepend_vertex_code: "#version 100\n".into(),
            ..Default::default()
        };
        let plain = desktop_shader_source_file(
            super::DesktopGraphicsOpenGlBackendShaderStage::Vertex,
            "shaders/mesh.vert",
            "void main(){}\n",
        );
        assert!(matches!(
            plain.preprocess(&options),
            Err(super::DesktopGraphicsOpenGlBackendShaderPreprocessError::ExplicitVersion {
                shader: ShaderId::Mesh,
                stage: super::DesktopGraphicsOpenGlBackendShaderStage::Vertex,
                ref source_path,
            }) if source_path == "shaders/mesh.vert"
        ));
    }

    #[test]
    fn desktop_graphics_opengl_shader_build_executor_loads_preprocesses_and_resolves_handles() {
        let root = desktop_shader_test_asset_root("build-success");
        write_shader_source(
            &root,
            "shaders/mesh.vert",
            "attribute vec3 a_position;\nvoid main(){}\n",
        );
        write_shader_source(
            &root,
            "shaders/planet.frag",
            "void main(){ gl_FragColor = vec4(1.0); }\n",
        );
        let mut executor = super::DesktopGraphicsOpenGlBackendShaderBuildExecutor::new(
            super::DesktopGraphicsOpenGlBackendShaderSourceLoader::new(&root),
        )
        .with_preprocess_options(
            super::DesktopGraphicsOpenGlBackendShaderPreprocessOptions {
                gl30: true,
                ..Default::default()
            },
        );
        let report = executor.build_task(&desktop_mesh_shader_task()).unwrap();

        assert_eq!(report.shader, ShaderId::Mesh);
        assert_eq!(report.program_key, "shader:Mesh");
        assert_eq!(report.resolved_commands.len(), 12);
        assert_eq!(report.compile_reports.len(), 2);
        assert_eq!(report.link_reports.len(), 1);
        assert!(!report.has_errors());
        assert_eq!(
            report.compile_reports[0],
            super::DesktopGraphicsOpenGlBackendShaderCompileReport {
                shader: ShaderId::Mesh,
                stage: super::DesktopGraphicsOpenGlBackendShaderStage::Vertex,
                shader_key: "shader:Mesh:vertex".into(),
                shader_handle: 1,
                source_path: "shaders/mesh.vert".into(),
                success: None,
                log: None,
            }
        );
        assert_eq!(report.compile_reports[1].source_path, "shaders/planet.frag");
        assert_eq!(report.link_reports[0].program_handle, 3);
        assert!(report
            .preprocessed_sources
            .vertex
            .source_text
            .contains("#version 150\n"));
        assert!(report
            .preprocessed_sources
            .fragment
            .source_text
            .contains("out vec4 fragColor;"));
    }

