    #[test]
    fn desktop_graphics_opengl_shader_build_executor_carries_compile_and_link_logs() {
        let root = desktop_shader_test_asset_root("build-logs");
        write_shader_source(&root, "shaders/mesh.vert", "void main(){}\n");
        write_shader_source(&root, "shaders/planet.frag", "void main(){}\n");
        let mut executor = super::DesktopGraphicsOpenGlBackendShaderBuildExecutor::new(
            super::DesktopGraphicsOpenGlBackendShaderSourceLoader::new(&root),
        );
        executor.push_compile_log_override(
            super::DesktopGraphicsOpenGlBackendShaderCompileLogOverride {
                shader: ShaderId::Mesh,
                stage: super::DesktopGraphicsOpenGlBackendShaderStage::Fragment,
                success: false,
                log: "fragment syntax error".into(),
            },
        );
        executor.push_link_log_override(super::DesktopGraphicsOpenGlBackendShaderLinkLogOverride {
            shader: ShaderId::Mesh,
            success: false,
            log: "link failed".into(),
        });
        let report = executor.build_task(&desktop_mesh_shader_task()).unwrap();

        assert!(report.has_errors());
        assert_eq!(report.compile_reports[0].success, None);
        assert_eq!(report.compile_reports[1].success, Some(false));
        assert_eq!(
            report.compile_reports[1].log.as_deref(),
            Some("fragment syntax error")
        );
        assert_eq!(report.link_reports[0].success, Some(false));
        assert_eq!(report.link_reports[0].log.as_deref(), Some("link failed"));
    }

    #[test]
    fn desktop_graphics_opengl_backend_adapter_preserves_draw_command_payloads() {
        let viewport = RenderViewport::new(0.0, 0.0, 64.0, 64.0);
        let camera = RenderCamera::new(RenderPoint::new(32.0, 32.0), viewport);
        let mut render_frame =
            RenderFramePlan::new(45, RenderSize::new(64.0, 64.0), camera, viewport);
        let mut pass = RenderPass::new(RenderPassKind::Overlay)
            .with_order(RenderPassKind::Overlay.default_order());
        pass.extend([
            RenderCommand::FillRect {
                rect: RenderRect::new(0.0, 0.0, 8.0, 8.0),
                color: [0.1, 0.2, 0.3, 1.0],
                layer: Layer::OVERLAY_UI,
            },
            RenderCommand::StrokeRect {
                rect: RenderRect::new(8.0, 0.0, 8.0, 8.0),
                color: [0.3, 0.2, 0.1, 1.0],
                thickness: 2.0,
                layer: Layer::OVERLAY_UI,
            },
            RenderCommand::DrawLine {
                from: RenderPoint::new(0.0, 0.0),
                to: RenderPoint::new(8.0, 8.0),
                stroke: 1.0,
                color: [1.0, 1.0, 1.0, 1.0],
                layer: Layer::OVERLAY_UI,
            },
            RenderCommand::DrawPolygon {
                center: RenderPoint::new(12.0, 12.0),
                radius: 4.0,
                sides: 6,
                rotation: 0.0,
                color: [0.8, 0.8, 1.0, 1.0],
                filled: false,
                layer: Layer::OVERLAY_UI,
            },
            RenderCommand::DrawPixel {
                x: 3,
                y: 4,
                color: [1.0, 0.0, 0.0, 1.0],
                layer: Layer::OVERLAY_UI,
            },
            RenderCommand::draw_sprite(
                "router",
                RenderRect::new(16.0, 16.0, 8.0, 8.0),
                [1.0, 1.0, 1.0, 1.0],
                0.0,
                Layer::OVERLAY_UI,
            ),
        ]);
        render_frame.push_pass(pass);

        let mut bridge = RenderBridge::new();
        bridge.set_render_frame(render_frame);
        let frame = DesktopGraphicsFrame {
            bundle: bridge.finish(),
            floor_chunk_batches: Vec::new(),
            minimap_texture_frame: None,
            font_glyph_upload_plan: None,
            texture_atlas: TextureAtlasPlan::from_virtual_source_paths(["sprites/router.png"]),
        };

        let plan = DesktopGraphicsOpenGlBackendFramePlan::from_frame(&frame);
        let mut executor = DesktopGraphicsOpenGlBackendExecutor::default();
        plan.drive_step_sink(&mut executor);
        let mut adapter = super::DesktopGraphicsRecordingOpenGlBackendAdapter::default();
        executor.drive_adapter(&mut adapter);

        let command_kinds = adapter
            .events
            .iter()
            .filter_map(|event| match event {
                super::DesktopGraphicsOpenGlBackendEvent::Command { kind, .. } => Some(*kind),
                _ => None,
            })
            .collect::<Vec<_>>();
        assert_eq!(
            command_kinds,
            vec![
                "FillRect",
                "StrokeRect",
                "DrawLine",
                "DrawPolygon",
                "DrawPixel",
                "DrawSprite"
            ]
        );
        assert_eq!(executor.state.draw_sprite_commands, 1);
        assert_eq!(executor.state.commands, 6);
        assert_eq!(executor.state.action_count, 6);
        assert_eq!(executor.state.actions.len(), 6);
        assert!(matches!(
            executor.state.actions[0],
            super::DesktopGraphicsOpenGlBackendAdapterAction::FillRect {
                rect: RenderRect {
                    x: 0.0,
                    y: 0.0,
                    width: 8.0,
                    height: 8.0
                },
                color: [0.1, 0.2, 0.3, 1.0],
                layer
            } if (layer - Layer::OVERLAY_UI).abs() < 0.0001
        ));
        assert!(matches!(
            executor.state.actions[1],
            super::DesktopGraphicsOpenGlBackendAdapterAction::StrokeRect {
                rect: RenderRect {
                    x: 8.0,
                    y: 0.0,
                    width: 8.0,
                    height: 8.0
                },
                color: [0.3, 0.2, 0.1, 1.0],
                thickness: 2.0,
                layer
            } if (layer - Layer::OVERLAY_UI).abs() < 0.0001
        ));
        assert!(matches!(
            executor.state.actions[2],
            super::DesktopGraphicsOpenGlBackendAdapterAction::DrawLine {
                from: RenderPoint { x: 0.0, y: 0.0 },
                to: RenderPoint { x: 8.0, y: 8.0 },
                stroke: 1.0,
                color: [1.0, 1.0, 1.0, 1.0],
                layer
            } if (layer - Layer::OVERLAY_UI).abs() < 0.0001
        ));
        assert!(matches!(
            executor.state.actions[3],
            super::DesktopGraphicsOpenGlBackendAdapterAction::DrawPolygon {
                center: RenderPoint { x: 12.0, y: 12.0 },
                radius: 4.0,
                sides: 6,
                rotation: 0.0,
                color: [0.8, 0.8, 1.0, 1.0],
                filled: false,
                layer
            } if (layer - Layer::OVERLAY_UI).abs() < 0.0001
        ));
        assert!(matches!(
            executor.state.actions[4],
            super::DesktopGraphicsOpenGlBackendAdapterAction::DrawPixel {
                x: 3,
                y: 4,
                color: [1.0, 0.0, 0.0, 1.0],
                layer
            } if (layer - Layer::OVERLAY_UI).abs() < 0.0001
        ));
        assert!(matches!(
            &executor.state.actions[5],
            super::DesktopGraphicsOpenGlBackendAdapterAction::DrawSprite { symbol, .. }
                if symbol == "router"
        ));
        let mut classifying_adapter =
            super::DesktopGraphicsClassifyingOpenGlBackendAdapter::default();
        executor.drive_adapter(&mut classifying_adapter);
        assert_eq!(classifying_adapter.state.command_events, 6);
        assert_eq!(classifying_adapter.state.deferred_noop_commands, 0);
        assert_eq!(classifying_adapter.state.draw_sprite_commands, 1);
        assert_eq!(classifying_adapter.state.draw_commands, 6);
        assert_eq!(classifying_adapter.state.pending_gl_draw_commands, 0);
        assert_eq!(classifying_adapter.state.state_commands, 0);
        assert_eq!(classifying_adapter.state.actions.len(), 6);
        assert!(matches!(
            classifying_adapter.state.actions[0],
            super::DesktopGraphicsOpenGlBackendAdapterAction::FillRect {
                rect: RenderRect {
                    x: 0.0,
                    y: 0.0,
                    width: 8.0,
                    height: 8.0
                },
                color: [0.1, 0.2, 0.3, 1.0],
                layer
            } if (layer - Layer::OVERLAY_UI).abs() < 0.0001
        ));
        assert!(matches!(
            classifying_adapter.state.actions[1],
            super::DesktopGraphicsOpenGlBackendAdapterAction::StrokeRect {
                rect: RenderRect {
                    x: 8.0,
                    y: 0.0,
                    width: 8.0,
                    height: 8.0
                },
                color: [0.3, 0.2, 0.1, 1.0],
                thickness: 2.0,
                layer
            } if (layer - Layer::OVERLAY_UI).abs() < 0.0001
        ));
        assert!(matches!(
            classifying_adapter.state.actions[2],
            super::DesktopGraphicsOpenGlBackendAdapterAction::DrawLine {
                from: RenderPoint { x: 0.0, y: 0.0 },
                to: RenderPoint { x: 8.0, y: 8.0 },
                stroke: 1.0,
                color: [1.0, 1.0, 1.0, 1.0],
                layer
            } if (layer - Layer::OVERLAY_UI).abs() < 0.0001
        ));
        assert!(matches!(
            classifying_adapter.state.actions[3],
            super::DesktopGraphicsOpenGlBackendAdapterAction::DrawPolygon {
                center: RenderPoint { x: 12.0, y: 12.0 },
                radius: 4.0,
                sides: 6,
                rotation: 0.0,
                color: [0.8, 0.8, 1.0, 1.0],
                filled: false,
                layer
            } if (layer - Layer::OVERLAY_UI).abs() < 0.0001
        ));
        assert!(matches!(
            classifying_adapter.state.actions[4],
            super::DesktopGraphicsOpenGlBackendAdapterAction::DrawPixel {
                x: 3,
                y: 4,
                color: [1.0, 0.0, 0.0, 1.0],
                layer
            } if (layer - Layer::OVERLAY_UI).abs() < 0.0001
        ));
        assert!(matches!(
            &classifying_adapter.state.actions[5],
            super::DesktopGraphicsOpenGlBackendAdapterAction::DrawSprite { symbol, .. }
                if symbol == "router"
        ));
        assert_eq!(executor.state.actions, classifying_adapter.state.actions);
        let mut action_sink = super::DesktopGraphicsRecordingOpenGlBackendActionSink::default();
        let action_count = executor.drive_action_sink(&mut action_sink);
        assert_eq!(action_count, 6);
        assert_eq!(action_sink.actions, executor.state.actions);
        let command_events = adapter
            .events
            .iter()
            .filter_map(|event| match event {
                super::DesktopGraphicsOpenGlBackendEvent::Command { kind, command, .. } => {
                    Some((*kind, command))
                }
                _ => None,
            })
            .collect::<Vec<_>>();
        assert!(matches!(
            command_events[0],
            (
                "FillRect",
                RenderCommand::FillRect {
                    rect: RenderRect {
                        x: 0.0,
                        y: 0.0,
                        width: 8.0,
                        height: 8.0
                    },
                    color: [0.1, 0.2, 0.3, 1.0],
                    layer
                }
            ) if (*layer - Layer::OVERLAY_UI).abs() < 0.0001
        ));
        assert!(matches!(
            command_events[1],
            (
                "StrokeRect",
                RenderCommand::StrokeRect {
                    rect: RenderRect {
                        x: 8.0,
                        y: 0.0,
                        width: 8.0,
                        height: 8.0
                    },
                    color: [0.3, 0.2, 0.1, 1.0],
                    thickness: 2.0,
                    layer
                }
            ) if (*layer - Layer::OVERLAY_UI).abs() < 0.0001
        ));
        assert!(matches!(
            command_events[2],
            (
                "DrawLine",
                RenderCommand::DrawLine {
                    from: RenderPoint { x: 0.0, y: 0.0 },
                    to: RenderPoint { x: 8.0, y: 8.0 },
                    stroke: 1.0,
                    color: [1.0, 1.0, 1.0, 1.0],
                    layer
                }
            ) if (*layer - Layer::OVERLAY_UI).abs() < 0.0001
        ));
        assert!(matches!(
            command_events[3],
            (
                "DrawPolygon",
                RenderCommand::DrawPolygon {
                    center: RenderPoint { x: 12.0, y: 12.0 },
                    radius: 4.0,
                    sides: 6,
                    rotation: 0.0,
                    color: [0.8, 0.8, 1.0, 1.0],
                    filled: false,
                    layer
                }
            ) if (*layer - Layer::OVERLAY_UI).abs() < 0.0001
        ));
        assert!(matches!(
            command_events[4],
            (
                "DrawPixel",
                RenderCommand::DrawPixel {
                    x: 3,
                    y: 4,
                    color: [1.0, 0.0, 0.0, 1.0],
                    layer
                }
            ) if (*layer - Layer::OVERLAY_UI).abs() < 0.0001
        ));
        assert!(matches!(
            command_events[5],
            (
                "DrawSprite",
                RenderCommand::DrawSprite {
                    symbol,
                    rect: RenderRect {
                        x: 16.0,
                        y: 16.0,
                        width: 8.0,
                        height: 8.0
                    },
                    layer,
                    ..
                }
            ) if symbol == "router" && (*layer - Layer::OVERLAY_UI).abs() < 0.0001
        ));
        assert!(executor.state.errors.is_empty());
    }

    #[test]
    fn desktop_graphics_opengl_backend_executor_rejects_nested_pass_begin() {
        let mut executor = DesktopGraphicsOpenGlBackendExecutor::default();

        executor.consume_opengl_backend_step(opengl_backend_test_step(
            0,
            RenderTarget::Screen,
            DesktopGraphicsOpenGlBackendStepKind::BeginPass,
        ));
        executor.consume_opengl_backend_step(opengl_backend_test_step(
            1,
            RenderTarget::Texture("nested".into()),
            DesktopGraphicsOpenGlBackendStepKind::BeginPass,
        ));

        assert_eq!(executor.state.begin_passes, 2);
        assert!(executor.state.pass_active);
        assert_eq!(
            executor.state.current_target,
            Some(RenderTarget::Texture("nested".into()))
        );
        assert_eq!(
            executor
                .state
                .active_pass
                .as_ref()
                .map(|pass| pass.target.clone()),
            Some(RenderTarget::Texture("nested".into()))
        );
        assert!(executor
            .state
            .errors
            .iter()
            .any(|error| error == "opengl backend began a pass while another pass was active"));
        assert!(executor.state.event_log.iter().any(
            |event| matches!(event, super::DesktopGraphicsOpenGlBackendEvent::Error { message }
                if message == "opengl backend began a pass while another pass was active")
        ));
    }

    #[test]
    fn desktop_graphics_opengl_backend_executor_rejects_end_pass_without_begin() {
        let mut executor = DesktopGraphicsOpenGlBackendExecutor::default();

        executor.consume_opengl_backend_step(opengl_backend_test_step(
            0,
            RenderTarget::Buffer("orphan".into()),
            DesktopGraphicsOpenGlBackendStepKind::EndPass,
        ));

        assert_eq!(executor.state.end_passes, 1);
        assert!(!executor.state.pass_active);
        assert!(executor.state.active_pass.is_none());
        assert_eq!(
            executor.state.current_target,
            Some(RenderTarget::Buffer("orphan".into()))
        );
        assert!(executor
            .state
            .errors
            .iter()
            .any(|error| error == "opengl backend ended a pass while no pass was active"));
    }

    #[test]
    fn desktop_graphics_opengl_backend_executor_rejects_resolve_while_pass_active() {
        let mut executor = DesktopGraphicsOpenGlBackendExecutor::default();

        executor.consume_opengl_backend_step(opengl_backend_test_step(
            0,
            RenderTarget::Buffer("active".into()),
            DesktopGraphicsOpenGlBackendStepKind::BeginPass,
        ));
        executor.consume_opengl_backend_step(opengl_backend_test_step(
            0,
            RenderTarget::Buffer("active".into()),
            DesktopGraphicsOpenGlBackendStepKind::Resolve {
                resolve_target: RenderTarget::Screen,
                resolve_kind: RenderResolveKind::DrawFboSample,
                resolve_sample: None,
            },
        ));

        assert!(executor.state.pass_active);
        assert_eq!(executor.state.resolve_events.len(), 1);
        assert_eq!(
            executor.state.resolve_events[0],
            super::DesktopGraphicsOpenGlBackendResolveEvent {
                source_target: RenderTarget::Buffer("active".into()),
                resolve_target: RenderTarget::Screen,
                resolve_kind: RenderResolveKind::DrawFboSample,
                resolve_sample: None,
            }
        );
        assert!(executor
            .state
            .errors
            .iter()
            .any(|error| error == "opengl backend resolved while a pass was active"));
    }

    #[test]
    fn desktop_graphics_opengl_backend_executor_rejects_target_mismatch_during_active_pass() {
        let mut executor = DesktopGraphicsOpenGlBackendExecutor::default();

        executor.consume_opengl_backend_step(opengl_backend_test_step(
            0,
            RenderTarget::Screen,
            DesktopGraphicsOpenGlBackendStepKind::BeginPass,
        ));
        executor.consume_opengl_backend_step(opengl_backend_test_step(
            0,
            RenderTarget::Buffer("wrong-target".into()),
            DesktopGraphicsOpenGlBackendStepKind::Command {
                kind: "DrawSprite",
                command: RenderCommand::draw_sprite(
                    "router",
                    RenderRect::new(0.0, 0.0, 8.0, 8.0),
                    [1.0, 1.0, 1.0, 1.0],
                    0.0,
                    Layer::BLOCK,
                ),
                resolved_sprite: None,
            },
        ));

        assert_eq!(executor.state.commands, 1);
        assert!(executor
            .state
            .errors
            .iter()
            .any(|error| error.contains("opengl backend step target changed during active pass")));
        assert_eq!(executor.state.draw_sprite_commands, 1);
    }

    #[test]
    fn desktop_graphics_opengl_backend_preserves_begin_end_pass_targets_through_resolve_and_driver()
    {
        let source_target = RenderTarget::Buffer("roundtrip-fbo".into());
        let resolve_target = RenderTarget::Screen;
        let viewport = RenderViewport::new(0.0, 0.0, 32.0, 32.0);
        let camera = RenderCamera::new(RenderPoint::new(16.0, 16.0), viewport);
        let mut render_frame =
            RenderFramePlan::new(42, RenderSize::new(32.0, 32.0), camera, viewport);
        render_frame.push_pass(
            RenderPass::new(RenderPassKind::Lighting)
                .with_order(8)
                .with_target(source_target.clone())
                .with_resolve(resolve_target.clone(), RenderResolveKind::ShaderBlit),
        );

        let mut bridge = RenderBridge::new();
        bridge.set_render_frame(render_frame);
        let frame = DesktopGraphicsFrame {
            bundle: bridge.finish(),
            floor_chunk_batches: Vec::new(),
            minimap_texture_frame: None,
            font_glyph_upload_plan: None,
            texture_atlas: TextureAtlasPlan::from_virtual_source_paths(["sprites/router.png"]),
        };

        let plan = DesktopGraphicsOpenGlBackendFramePlan::from_frame(&frame);
        assert_eq!(plan.steps.len(), 3);
        assert!(matches!(
            plan.steps[0],
            DesktopGraphicsOpenGlBackendStep {
                kind: DesktopGraphicsOpenGlBackendStepKind::BeginPass,
                target: RenderTarget::Buffer(ref target_name),
                ..
            } if target_name == "roundtrip-fbo"
        ));
        assert!(matches!(
            plan.steps[1],
            DesktopGraphicsOpenGlBackendStep {
                kind: DesktopGraphicsOpenGlBackendStepKind::EndPass,
                target: RenderTarget::Buffer(ref target_name),
                ..
            } if target_name == "roundtrip-fbo"
        ));
        assert!(matches!(
            plan.steps[2],
            DesktopGraphicsOpenGlBackendStep {
                kind: DesktopGraphicsOpenGlBackendStepKind::Resolve { .. },
                target: RenderTarget::Buffer(ref target_name),
                ..
            } if target_name == "roundtrip-fbo"
        ));

        let mut executor = DesktopGraphicsOpenGlBackendExecutor::default();
        executor.consume_opengl_backend_step(plan.steps[0].clone());
        assert!(executor.state.pass_active);
        assert_eq!(
            executor
                .state
                .active_pass
                .as_ref()
                .map(|pass| pass.target.clone()),
            Some(source_target.clone())
        );
        assert!(matches!(
            executor.state.event_log.last(),
            Some(super::DesktopGraphicsOpenGlBackendEvent::BeginPass { target, .. })
                if target == &source_target
        ));

        executor.consume_opengl_backend_step(plan.steps[1].clone());
        assert!(!executor.state.pass_active);
        assert!(executor.state.active_pass.is_none());
        assert_eq!(executor.state.current_target, Some(source_target.clone()));
        assert!(matches!(
            executor.state.event_log.last(),
            Some(super::DesktopGraphicsOpenGlBackendEvent::EndPass { target, .. })
                if target == &source_target
        ));

        executor.consume_opengl_backend_step(plan.steps[2].clone());
        assert_eq!(executor.state.resolve_events.len(), 1);
        assert_eq!(executor.state.event_log.len(), 3);
        assert_eq!(
            executor
                .state
                .resource_table
                .get(&source_target)
                .expect("source target should remain addressable")
                .resolve_source_count,
            1
        );
        assert_eq!(
            executor
                .state
                .resource_table
                .get(&resolve_target)
                .expect("resolve target should remain addressable")
                .resolve_target_count,
            1
        );
        assert!(matches!(
            executor.state.event_log.last(),
            Some(super::DesktopGraphicsOpenGlBackendEvent::Resolve {
                source_target: logged_source_target,
                resolve_target: logged_resolve_target,
                resolve_kind: logged_resolve_kind,
                ..
            }) if logged_source_target == &source_target
                && logged_resolve_target == &resolve_target
                && *logged_resolve_kind == RenderResolveKind::ShaderBlit
        ));

        let resolve_event = executor.state.resolve_events[0].clone();
        assert_eq!(resolve_event.source_target, source_target);
        assert_eq!(resolve_event.resolve_target, resolve_target);
        assert_eq!(resolve_event.resolve_kind, RenderResolveKind::ShaderBlit);

        let mut resolving_executor =
            super::DesktopGraphicsResolvingOpenGlBackendCommandExecutor::default();
        resolving_executor.consume_opengl_resolve_event(resolve_event);
        assert_eq!(resolving_executor.resolve_commands.len(), 1);
        assert_eq!(
            resolving_executor.resolve_commands[0].source_target,
            RenderTarget::Buffer("roundtrip-fbo".into())
        );
        assert_eq!(
            resolving_executor.resolve_commands[0].resolve_target,
            RenderTarget::Screen
        );
        assert_eq!(
            resolving_executor.resolve_commands[0].resolve_kind,
            RenderResolveKind::ShaderBlit
        );

        let mut driver = super::DesktopGraphicsRecordingOpenGlBackendDriver::default();
        let driver_state = resolving_executor.drive_driver(&mut driver);
        assert_eq!(driver_state.resolve_commands, 1);
        assert!(matches!(
            driver.commands.last(),
            Some(super::DesktopGraphicsOpenGlBackendDriverCommand::Resolve(command))
                if command.source_target == RenderTarget::Buffer("roundtrip-fbo".into())
                    && command.resolve_target == RenderTarget::Screen
                    && command.resolve_kind == RenderResolveKind::ShaderBlit
        ));
    }

    #[test]
    fn desktop_launcher_graphics_frame_includes_environment_pass_before_lighting() {
        let mut launcher = DesktopLauncher::new(Vec::new());
        launcher.game_state.rules.env = GraphicsEnv::UNDERWATER;
        assert!(launcher.light_renderer_state.add_circle(
            4.0,
            5.0,
            6.0,
            LightPrimitive {
                center: (4.0, 5.0),
                radius: 6.0,
                color: DecalColor::WHITE,
                opacity: 1.0,
            },
        ));

        let viewport = RenderViewport::new(0.0, 0.0, 32.0, 32.0);
        let camera = RenderCamera::new(RenderPoint::new(16.0, 16.0), viewport);
        let frame = launcher.graphics_frame_for_render(
            42,
            camera,
            viewport,
            MinimapCamera::new(16.0, 16.0, 32.0, 32.0),
            sample_minimap_overlay_input(false),
        );

        let render_frame = frame.bundle.render_frame.as_ref().unwrap();
        let environment_index = render_frame
            .passes
            .iter()
            .position(|pass| pass.kind == RenderPassKind::Environment)
            .expect("environment pass should enter render frame");
        let lighting_index = render_frame
            .passes
            .iter()
            .position(|pass| pass.kind == RenderPassKind::Lighting)
            .expect("lighting pass should enter render frame");
        assert!(environment_index < lighting_index);

        let environment_pass = &render_frame.passes[environment_index];
        assert_eq!(
            environment_pass.kind.java_renderer_draw_stage().label(),
            "env"
        );
        assert!(environment_pass.commands.iter().any(|command| matches!(
            command,
            RenderCommand::Custom { name, properties }
                if name == "env-fill_rect"
                    && properties.iter().any(|property| property.key == "bucket" && property.value == "surface")
        )));
    }

