    #[test]
    fn headless_graphics_renderer_records_execution_summary_without_polluting_stats() {
        let viewport = RenderViewport::new(0.0, 0.0, 64.0, 64.0);
        let camera = RenderCamera::new(RenderPoint::new(32.0, 32.0), viewport);
        let mut render_frame =
            RenderFramePlan::new(77, RenderSize::new(64.0, 64.0), camera, viewport);
        let mut block_pass = RenderPass::new(RenderPassKind::Block)
            .with_target(RenderTarget::Buffer("backend-buffer".into()));
        block_pass.push(RenderCommand::draw_sprite(
            "router",
            RenderRect::new(8.0, 8.0, 8.0, 8.0),
            [1.0, 1.0, 1.0, 1.0],
            0.0,
            30.0,
        ));
        block_pass.push(RenderCommand::draw_text(
            "backend-ready",
            RenderPoint::new(9.0, 10.0),
            [1.0, 1.0, 1.0, 1.0],
            12.0,
            0.0,
            RenderTextAlign::Center,
            31.0,
        ));
        block_pass.push(RenderCommand::fill_rect(
            RenderRect::new(0.0, 0.0, 4.0, 4.0),
            [0.0, 0.0, 0.0, 1.0],
            1.0,
        ));
        block_pass.push(RenderCommand::draw_polygon(
            RenderPoint::new(20.0, 21.0),
            5.0,
            6,
            30.0,
            [0.25, 0.5, 0.75, 1.0],
            true,
            32.0,
        ));
        render_frame.push_pass(block_pass);

        let mut ui_pass = RenderPass::new(RenderPassKind::Ui)
            .with_target(RenderTarget::Texture("ui-layer".into()));
        ui_pass.push(RenderCommand::draw_text(
            "status",
            RenderPoint::new(6.0, 7.0),
            [1.0, 1.0, 1.0, 1.0],
            10.0,
            0.0,
            RenderTextAlign::Start,
            60.0,
        ));
        ui_pass.push(RenderCommand::draw_sprite(
            "cursor",
            RenderRect::new(16.0, 16.0, 6.0, 6.0),
            [0.5, 0.5, 1.0, 1.0],
            0.0,
            61.0,
        ));
        render_frame.push_pass(ui_pass);

        let mut lighting_pass = RenderPass::new(RenderPassKind::Lighting);
        lighting_pass.push(RenderCommand::draw_sprite(
            "lighting-glow",
            RenderRect::new(1.0, 1.0, 2.0, 2.0),
            [1.0, 1.0, 0.5, 1.0],
            15.0,
            50.0,
        ));
        render_frame.push_pass(lighting_pass);

        let mut bridge = RenderBridge::new();
        bridge.set_render_frame(render_frame).set_shader_dispatch(
            ShaderDispatchFrame::from_applies([
                ShaderCatalog::apply_plan(ShaderId::Light, &ShaderApplyContext::default()),
                ShaderApplyPlan::new(ShaderId::Shield),
            ]),
        );
        let atlas = TextureAtlasPlan::from_virtual_source_paths([
            "sprites/router.png",
            "sprites/lighting-glow.png",
        ]);
        let frame = DesktopGraphicsFrame {
            bundle: bridge.finish(),
            floor_chunk_batches: Vec::new(),
            minimap_texture_frame: None,
            font_glyph_upload_plan: None,
            texture_atlas: atlas.clone(),
        };

        let summary = DesktopGraphicsExecutionSummary::from_frame(&frame);
        assert_eq!(summary.render_passes_visited, 3);
        assert_eq!(summary.render_commands_visited, 7);
        assert_eq!(summary.draw_sprite_commands, 3);
        assert_eq!(summary.draw_text_commands, 2);
        assert_eq!(summary.draw_polygon_commands, 1);
        assert_eq!(summary.shader_dispatch_applies, 2);
        assert_eq!(summary.shader_dispatch_operations, 1);
        assert_eq!(summary.shader_dispatch_errors, 0);
        assert_eq!(summary.screen_target_passes, 1);
        assert_eq!(summary.texture_target_passes, 1);
        assert_eq!(summary.buffer_target_passes, 1);
        assert_eq!(frame.bundle.stats.render_passes, 3);
        assert_eq!(frame.bundle.stats.render_commands, 7);

        let mut renderer = HeadlessDesktopGraphicsRenderer::default();
        let stats = renderer.render_graphics_frame(&frame);
        assert_eq!(stats.render_passes, 3);
        assert_eq!(renderer.last_execution, summary);
        assert_eq!(renderer.last_stats.render_commands, 7);
        assert_eq!(
            renderer.last_trace,
            DesktopGraphicsExecutionTrace::from_frame(&frame)
        );
        assert_eq!(renderer.last_trace.shader_dispatch.applies.len(), 2);
        assert_eq!(
            renderer.last_trace.shader_dispatch.applies[0],
            DesktopGraphicsShaderApplyExecutionTrace {
                shader: ShaderId::Light,
                operation_count: 1,
                error_count: 0,
            }
        );
        assert_eq!(
            renderer.last_trace.render_passes[0].target,
            RenderTarget::Buffer("backend-buffer".into())
        );
        assert_eq!(
            renderer.last_trace.render_passes[0].draw_sprite_symbols,
            vec!["router".to_string()]
        );
        assert_eq!(
            renderer.last_trace.render_passes[0].resolved_sprites[0],
            DesktopGraphicsResolvedSpriteTrace {
                command_index: Some(0),
                symbol: "router".to_string(),
                page_type: Some(mindustry_core::mindustry::graphics::PageType::Main),
                page_source_path: Some("sprites.png".to_string()),
                page_width: Some(4096),
                page_height: Some(4096),
                linear_filter: true,
                sampler: DesktopGraphicsTextureSamplerTrace::Linear,
                region_source_path: Some("sprites/router.png".to_string()),
                x: Some(0),
                y: Some(0),
                u: Some(0.0),
                v: Some(0.0),
                u2: Some(1.0 / 4096.0),
                v2: Some(1.0 / 4096.0),
                region_width: Some(1),
                region_height: Some(1),
                missing: false,
            }
        );
        assert_eq!(
            renderer.last_trace.render_passes[0].draw_texts,
            vec!["backend-ready".to_string()]
        );
        assert_eq!(
            renderer.last_trace.render_passes[0].draw_polygon_sides,
            vec![6]
        );
        assert_eq!(
            renderer.last_trace.render_passes[1].target,
            RenderTarget::Texture("ui-layer".into())
        );
        assert_eq!(
            renderer.last_trace.render_passes[1].draw_texts,
            vec!["status".to_string()]
        );
        assert_eq!(
            renderer.last_trace.render_passes[2].target,
            RenderTarget::Screen
        );
        assert_eq!(renderer.last_live_backend_state.render_passes_visited, 3);
        assert_eq!(renderer.last_live_backend_state.render_commands_visited, 7);
        assert_eq!(
            renderer
                .last_live_backend_state
                .backend_target_events_emitted,
            6
        );
        assert_eq!(
            renderer
                .last_live_backend_state
                .resolve_target_events_emitted,
            0
        );
        assert_eq!(
            renderer
                .last_live_backend_state
                .buffer_target_events_emitted,
            2
        );
        assert_eq!(
            renderer
                .last_live_backend_state
                .texture_target_events_emitted,
            2
        );
        assert_eq!(
            renderer
                .last_live_backend_state
                .screen_target_events_emitted,
            2
        );
        assert_eq!(
            renderer
                .last_live_backend_state
                .last_backend_target_event
                .as_ref()
                .map(|trace| (trace.target.clone(), trace.event, trace.command_count)),
            Some((
                RenderTarget::Screen,
                DesktopGraphicsLiveBackendRenderTargetEventKind::End,
                1,
            ))
        );
        assert_eq!(
            renderer.last_live_backend_state.draw_sprite_traces_emitted,
            3
        );
        let last_state_sprite = renderer
            .last_live_backend_state
            .last_draw_sprite_trace
            .as_ref()
            .and_then(|trace| trace.resolved_sprite.as_ref())
            .expect("live backend execution state should remember last sprite metadata");
        assert_eq!(last_state_sprite.symbol, "lighting-glow");
        assert_eq!(
            last_state_sprite.page_source_path.as_deref(),
            Some("sprites.png")
        );
        assert_eq!(last_state_sprite.page_width, Some(4096));
        assert_eq!(last_state_sprite.page_height, Some(4096));
        assert_eq!(
            last_state_sprite.sampler,
            DesktopGraphicsTextureSamplerTrace::Linear
        );

        let resolved_trace = DesktopGraphicsExecutionTrace::from_frame_with_atlas(&frame, &atlas);
        assert_eq!(
            resolved_trace,
            DesktopGraphicsExecutionTrace::from_frame(&frame)
        );
        let resolved = &resolved_trace.render_passes[0].resolved_sprites[0];
        assert_eq!(resolved.symbol, "router");
        assert_eq!(
            resolved.page_type,
            Some(mindustry_core::mindustry::graphics::PageType::Main)
        );
        assert_eq!(resolved.x, Some(0));
        assert_eq!(resolved.y, Some(0));
        assert_eq!(resolved.page_source_path.as_deref(), Some("sprites.png"));
        assert_eq!(resolved.page_width, Some(4096));
        assert_eq!(resolved.page_height, Some(4096));
        assert!(resolved.linear_filter);
        assert_eq!(resolved.sampler, DesktopGraphicsTextureSamplerTrace::Linear);
        assert_eq!(
            resolved.region_source_path.as_deref(),
            Some("sprites/router.png")
        );
        assert_eq!(resolved.u, Some(0.0));
        assert_eq!(resolved.v, Some(0.0));
        assert_eq!(resolved.u2, Some(1.0 / 4096.0));
        assert_eq!(resolved.v2, Some(1.0 / 4096.0));
        assert_eq!(resolved.region_width, Some(1));
        assert!(!resolved.missing);

        let missing = &resolved_trace.render_passes[1].resolved_sprites[0];
        assert_eq!(missing.symbol, "cursor");
        assert_eq!(missing.page_type, None);
        assert_eq!(missing.page_source_path, None);
        assert_eq!(missing.page_width, None);
        assert_eq!(missing.page_height, None);
        assert!(missing.linear_filter);
        assert_eq!(missing.sampler, DesktopGraphicsTextureSamplerTrace::Linear);
        assert_eq!(missing.region_source_path, None);
        assert_eq!(missing.x, None);
        assert_eq!(missing.y, None);
        assert_eq!(missing.u, None);
        assert_eq!(missing.v, None);
        assert_eq!(missing.u2, None);
        assert_eq!(missing.v2, None);
        assert!(missing.missing);

        let lighting = &resolved_trace.render_passes[2].resolved_sprites[0];
        assert_eq!(lighting.symbol, "lighting-glow");
        assert_eq!(lighting.page_source_path.as_deref(), Some("sprites.png"));
        assert_eq!(lighting.page_width, Some(4096));
        assert_eq!(lighting.page_height, Some(4096));
        assert!(lighting.linear_filter);
        assert_eq!(lighting.sampler, DesktopGraphicsTextureSamplerTrace::Linear);
        assert_eq!(
            lighting.region_source_path.as_deref(),
            Some("sprites/lighting-glow.png")
        );
        assert_eq!(lighting.x, Some(0));
        assert_eq!(lighting.y, Some(0));
        assert_eq!(lighting.u, Some(0.0));
        assert_eq!(lighting.v, Some(0.0));
        assert_eq!(lighting.u2, Some(1.0 / 4096.0));
        assert_eq!(lighting.v2, Some(1.0 / 4096.0));
        assert_eq!(lighting.region_width, Some(1));
        assert_eq!(lighting.region_height, Some(1));
        assert!(!lighting.missing);

        let resolved_summary = DesktopGraphicsExecutionSummary::from_trace(&frame, &resolved_trace);
        assert_eq!(resolved_summary.atlas_resolved_sprites, 2);
        assert_eq!(resolved_summary.atlas_missing_sprites, 1);
    }

    #[test]
    fn headless_graphics_renderer_resolves_draw_sprite_trace_coordinates_from_manual_atlas() {
        let viewport = RenderViewport::new(0.0, 0.0, 64.0, 64.0);
        let camera = RenderCamera::new(RenderPoint::new(32.0, 32.0), viewport);
        let mut render_frame =
            RenderFramePlan::new(88, RenderSize::new(64.0, 64.0), camera, viewport);
        let mut pass = RenderPass::new(RenderPassKind::Ui);
        pass.push(RenderCommand::draw_sprite(
            "router",
            RenderRect::new(8.0, 12.0, 16.0, 20.0),
            [1.0, 1.0, 1.0, 1.0],
            0.0,
            0.0,
        ));
        render_frame.push_pass(pass);

        let mut bridge = RenderBridge::new();
        bridge.set_render_frame(render_frame);

        let mut atlas = TextureAtlasPlan::new();
        let _ = atlas.insert_region(
            mindustry_core::mindustry::graphics::PageType::Main,
            mindustry_core::mindustry::graphics::TextureAtlasRegion::new(
                mindustry_core::mindustry::graphics::PageType::Main,
                "router",
                "sprites/router.png",
                12,
                34,
                8,
                16,
                false,
            ),
        );

        let frame = DesktopGraphicsFrame {
            bundle: bridge.finish(),
            floor_chunk_batches: Vec::new(),
            minimap_texture_frame: None,
            font_glyph_upload_plan: None,
            texture_atlas: atlas,
        };

        let mut renderer = HeadlessDesktopGraphicsRenderer::default();
        renderer.render_graphics_frame(&frame);

        let resolved = &renderer.last_trace.render_passes[0].resolved_sprites[0];
        assert_eq!(resolved.symbol, "router");
        assert_eq!(
            resolved.page_type,
            Some(mindustry_core::mindustry::graphics::PageType::Main)
        );
        assert_eq!(resolved.page_source_path.as_deref(), Some("sprites.png"));
        assert_eq!(resolved.page_width, Some(4096));
        assert_eq!(resolved.page_height, Some(4096));
        assert!(resolved.linear_filter);
        assert_eq!(resolved.sampler, DesktopGraphicsTextureSamplerTrace::Linear);
        assert_eq!(
            resolved.region_source_path.as_deref(),
            Some("sprites/router.png")
        );
        assert_eq!(resolved.x, Some(12));
        assert_eq!(resolved.y, Some(34));
        assert_eq!(resolved.u, Some(12.0 / 4096.0));
        assert_eq!(resolved.v, Some(34.0 / 4096.0));
        assert_eq!(resolved.u2, Some(20.0 / 4096.0));
        assert_eq!(resolved.v2, Some(50.0 / 4096.0));
        assert_eq!(resolved.region_width, Some(8));
        assert_eq!(resolved.region_height, Some(16));
        assert!(!resolved.missing);
    }

    #[test]
    fn headless_graphics_renderer_roundtrips_opengl_state_to_shared_resolver() {
        let viewport = RenderViewport::new(0.0, 0.0, 64.0, 64.0);
        let camera = RenderCamera::new(RenderPoint::new(32.0, 32.0), viewport);
        let mut render_frame =
            RenderFramePlan::new(89, RenderSize::new(64.0, 64.0), camera, viewport);
        let mut pass = RenderPass::new(RenderPassKind::Lighting)
            .with_target(RenderTarget::Buffer("roundtrip-fbo".into()))
            .with_resolve(RenderTarget::Screen, RenderResolveKind::ShaderBlit);
        pass.push(RenderCommand::draw_sprite(
            "router",
            RenderRect::new(8.0, 12.0, 16.0, 20.0),
            [1.0, 1.0, 1.0, 1.0],
            0.0,
            0.0,
        ));
        render_frame.push_pass(pass);

        let mut bridge = RenderBridge::new();
        bridge.set_render_frame(render_frame);
        let frame = DesktopGraphicsFrame {
            bundle: bridge.finish(),
            floor_chunk_batches: Vec::new(),
            minimap_texture_frame: None,
            font_glyph_upload_plan: None,
            texture_atlas: TextureAtlasPlan::from_virtual_source_paths(["sprites/router.png"]),
        };

        let mut renderer = HeadlessDesktopGraphicsRenderer::default();
        renderer.render_graphics_frame_for_surface(
            &frame,
            super::DesktopGraphicsEffectBufferSurface::new(DesktopSurfaceSize::new(800, 600), 7),
        );

        assert_eq!(
            renderer.last_opengl_backend_execution_state.resolve_steps,
            1
        );
        assert_eq!(
            renderer
                .last_live_backend_state
                .resolve_target_events_emitted,
            1
        );
        assert_eq!(
            renderer
                .last_opengl_backend_executor_state
                .resolve_events
                .len(),
            1
        );
        assert!(renderer
            .last_opengl_backend_executor_state
            .resolved_framebuffer_attachments
            .iter()
            .any(|attachment| attachment.color_texture_key
                == "framebuffer-attachment:renderer.effectBuffer:color0"
                && attachment.width == 800
                && attachment.height == 600
                && attachment.generation == 7));
        assert!(renderer
            .last_opengl_backend_executor_state
            .resolved_framebuffer_attachments
            .iter()
            .any(|attachment| attachment.color_texture_key
                == "framebuffer-attachment:buffer:roundtrip-fbo:color0"));

        let mut resolving_executor =
            super::DesktopGraphicsResolvingOpenGlBackendCommandExecutor::default();
        let resolved_state = renderer
            .last_opengl_backend_executor_state
            .drive_resolving_command_executor(&mut resolving_executor);
        assert_eq!(
            resolved_state,
            super::DesktopGraphicsOpenGlBackendResolvedCommandExecutorState {
                framebuffer_attachments_emitted: renderer
                    .last_opengl_backend_executor_state
                    .framebuffer_attachment_plans
                    .len(),
                texture_uploads_emitted: 1,
                sprite_mesh_uploads_emitted: 1,
                shader_commands_emitted: 0,
                sprite_draw_calls_emitted: 1,
                resolve_events_emitted: 1,
            }
        );
        assert_eq!(
            resolving_executor.framebuffer_attachment_plans.len(),
            renderer
                .last_opengl_backend_executor_state
                .framebuffer_attachment_plans
                .len()
        );
        assert_eq!(
            resolving_executor.resolved_framebuffer_attachments.len(),
            resolving_executor.framebuffer_attachment_plans.len()
        );
        assert!(resolving_executor
            .resolved_framebuffer_attachments
            .iter()
            .any(|attachment| attachment.color_texture_key
                == "framebuffer-attachment:renderer.effectBuffer:color0"));
        assert!(resolving_executor
            .resolved_framebuffer_attachments
            .iter()
            .any(|attachment| attachment.color_texture_key
                == "framebuffer-attachment:buffer:roundtrip-fbo:color0"));
        assert_eq!(resolving_executor.resolve_commands.len(), 1);
        assert_eq!(
            resolving_executor.resolve_commands[0].source_target,
            RenderTarget::Buffer("roundtrip-fbo".into())
        );
        assert_eq!(
            resolving_executor.resolve_commands[0].resolve_target,
            RenderTarget::Screen
        );
        assert_eq!(
            resolving_executor.resolve_commands[0].resolve_kind,
            RenderResolveKind::ShaderBlit
        );
        assert_eq!(
            resolving_executor.resolve_commands[0]
                .source_attachment
                .as_ref()
                .map(|attachment| attachment.color_texture_key.as_str()),
            Some("framebuffer-attachment:buffer:roundtrip-fbo:color0")
        );
        let upload_handle = resolving_executor.resolved_texture_uploads[0].texture_handle;
        let draw_texture_handle =
            resolving_executor
                .resolved_draw_actions
                .iter()
                .find_map(|action| match action {
                    super::DesktopGraphicsOpenGlBackendResolvedDrawCallAction::BindTexture {
                        texture_handle,
                        ..
                    } => Some(*texture_handle),
                    _ => None,
                });
        assert_eq!(draw_texture_handle, Some(upload_handle));
        assert_eq!(
            resolving_executor.resolved_sprite_mesh_uploads[0].vertex_array_handle,
            resolving_executor
                .resolved_draw_actions
                .iter()
                .find_map(|action| {
                    match action {
                    super::DesktopGraphicsOpenGlBackendResolvedDrawCallAction::BindVertexArray {
                        vertex_array_handle,
                        ..
                    } => Some(*vertex_array_handle),
                    _ => None,
                }
                })
                .unwrap()
        );

        let mut driver = super::DesktopGraphicsRecordingOpenGlBackendDriver::default();
        let driver_state = resolving_executor.drive_driver(&mut driver);
        assert_eq!(
            driver_state,
            super::DesktopGraphicsOpenGlBackendDriverExecutionState {
                framebuffer_attachment_plans: resolving_executor.framebuffer_attachment_plans.len(),
                texture_upload_commands: resolving_executor.texture_upload_commands.len(),
                sprite_mesh_upload_commands: resolving_executor.sprite_mesh_upload_commands.len(),
                resolve_mesh_upload_commands: resolving_executor.resolve_mesh_upload_commands.len(),
                shader_commands: resolving_executor.resolved_shader_commands.len(),
                draw_commands: resolving_executor.draw_commands.len(),
                resolve_draw_commands: resolving_executor.resolve_draw_commands.len(),
                resolve_commands: resolving_executor.resolve_commands.len(),
            }
        );
        assert_eq!(
            driver.commands.len(),
            driver_state.framebuffer_attachment_plans
                + driver_state.texture_upload_commands
                + driver_state.sprite_mesh_upload_commands
                + driver_state.resolve_mesh_upload_commands
                + driver_state.shader_commands
                + driver_state.draw_commands
                + driver_state.resolve_draw_commands
                + driver_state.resolve_commands
        );
        assert!(matches!(
            driver.commands.first(),
            Some(super::DesktopGraphicsOpenGlBackendDriverCommand::FramebufferAttachment(_))
        ));
        assert!(driver.commands.iter().any(|command| matches!(
            command,
            super::DesktopGraphicsOpenGlBackendDriverCommand::SpriteMeshUpload(_)
        )));
        assert!(driver.commands.iter().any(|command| matches!(
            command,
            super::DesktopGraphicsOpenGlBackendDriverCommand::Draw(
                super::DesktopGraphicsOpenGlBackendDrawCommand::DrawElements { .. }
            )
        )));
        assert!(matches!(
            driver.commands.last(),
            Some(super::DesktopGraphicsOpenGlBackendDriverCommand::Resolve(
                super::DesktopGraphicsOpenGlBackendResolveCommand {
                    resolve_kind: RenderResolveKind::ShaderBlit,
                    ..
                }
            ))
        ));
    }

    #[test]
    fn desktop_graphics_opengl_resolve_shader_blit_translates_to_fullscreen_quad_draw_commands() {
        let command = super::DesktopGraphicsOpenGlBackendResolveCommand {
            source_target: RenderTarget::Buffer("shader-blit-source".into()),
            resolve_target: RenderTarget::Screen,
            resolve_kind: RenderResolveKind::ShaderBlit,
            resolve_sample: None,
            resolve_sample_trace: None,
            resolve_sample_quad: None,
            source_attachment: Some(
                super::DesktopGraphicsOpenGlBackendResolvedFramebufferAttachment {
                    framebuffer_key: "framebuffer:buffer:shader-blit-source".into(),
                    framebuffer_handle: 41,
                    previous_framebuffer_handle: None,
                    framebuffer_was_recreated: true,
                    framebuffer_target: super::DESKTOP_GRAPHICS_OPENGL_FRAMEBUFFER,
                    color_attachment: super::DESKTOP_GRAPHICS_OPENGL_COLOR_ATTACHMENT0,
                    color_texture_key: "framebuffer-attachment:buffer:shader-blit-source:color0"
                        .into(),
                    color_texture_handle: 43,
                    previous_color_texture_handle: None,
                    color_texture_was_recreated: true,
                    width: 800,
                    height: 600,
                    generation: 9,
                },
            ),
        };

        let expected = vec![
            super::DesktopGraphicsOpenGlBackendDrawCommand::BindFramebuffer {
                target: Some(RenderTarget::Screen),
            },
            super::DesktopGraphicsOpenGlBackendDrawCommand::UseProgram { program_handle: 17 },
            super::DesktopGraphicsOpenGlBackendDrawCommand::ActiveTexture {
                texture_unit: super::DESKTOP_GRAPHICS_OPENGL_TEXTURE0,
            },
            super::DesktopGraphicsOpenGlBackendDrawCommand::BindTexture {
                target: super::DESKTOP_GRAPHICS_OPENGL_TEXTURE_2D,
                texture_handle: 43,
            },
            super::DesktopGraphicsOpenGlBackendDrawCommand::BindVertexArray {
                vertex_array_handle: 23,
            },
            super::DesktopGraphicsOpenGlBackendDrawCommand::DrawElements {
                primitive_type:
                    super::DesktopGraphicsOpenGlBackendSpriteDrawCallPlan::TRIANGLES_PRIMITIVE,
                index_count:
                    super::DesktopGraphicsOpenGlBackendResolveCommand::FULLSCREEN_QUAD_INDEX_COUNT,
                index_type: super::DESKTOP_GRAPHICS_OPENGL_UNSIGNED_INT,
                index_offset_bytes:
                    super::DesktopGraphicsOpenGlBackendResolveCommand::FULLSCREEN_QUAD_INDEX_OFFSET_BYTES,
            },
        ];

        assert_eq!(
            command.shader_blit_to_opengl_draw_commands(17, 23),
            expected
        );

        let mut fbo_sample = command.clone();
        fbo_sample.resolve_kind = RenderResolveKind::DrawFboSample;
        assert!(fbo_sample
            .shader_blit_to_opengl_draw_commands(17, 23)
            .is_empty());
        assert_eq!(
            fbo_sample.source_texture_sample_to_opengl_draw_commands(17, 23),
            expected
        );

        let mut rect_sample = fbo_sample.clone();
        rect_sample.resolve_kind = RenderResolveKind::DrawRectSample;
        assert_eq!(
            rect_sample.source_texture_sample_to_opengl_draw_commands(17, 23),
            expected
        );

        let mut blit = rect_sample.clone();
        blit.resolve_kind = RenderResolveKind::Blit;
        assert!(blit
            .source_texture_sample_to_opengl_draw_commands(17, 23)
            .is_empty());

        let mut missing_source = command;
        missing_source.source_attachment = None;
        assert!(missing_source
            .shader_blit_to_opengl_draw_commands(17, 23)
            .is_empty());
        assert!(missing_source
            .source_texture_sample_to_opengl_draw_commands(17, 23)
            .is_empty());
    }

    #[test]
    fn desktop_graphics_opengl_shared_resolver_allocates_shader_blit_quad_resources() {
        let mut executor = super::DesktopGraphicsResolvingOpenGlBackendCommandExecutor::default();
        executor.consume_opengl_framebuffer_attachment(
            super::DesktopGraphicsOpenGlBackendFramebufferAttachmentPlan::from_buffer_name(
                "buffer:shader-blit-source",
            ),
        );
        executor.consume_opengl_resolve_event(super::DesktopGraphicsOpenGlBackendResolveEvent {
            source_target: RenderTarget::Buffer("shader-blit-source".into()),
            resolve_target: RenderTarget::Screen,
            resolve_kind: RenderResolveKind::ShaderBlit,
            resolve_sample: None,
        });

        assert_eq!(
            executor.cache.programs
                [super::DesktopGraphicsResolvingOpenGlBackendCommandExecutor::SHADER_BLIT_PROGRAM_KEY],
            3
        );
        assert_eq!(
            executor.cache.vertex_arrays
                [super::DesktopGraphicsResolvingOpenGlBackendCommandExecutor::FULLSCREEN_QUAD_VERTEX_ARRAY_KEY],
            4
        );
        assert_eq!(
            executor.resolve_draw_commands,
            vec![
                super::DesktopGraphicsOpenGlBackendDrawCommand::BindFramebuffer {
                    target: Some(RenderTarget::Screen),
                },
                super::DesktopGraphicsOpenGlBackendDrawCommand::UseProgram { program_handle: 3 },
                super::DesktopGraphicsOpenGlBackendDrawCommand::ActiveTexture {
                    texture_unit: super::DESKTOP_GRAPHICS_OPENGL_TEXTURE0,
                },
                super::DesktopGraphicsOpenGlBackendDrawCommand::BindTexture {
                    target: super::DESKTOP_GRAPHICS_OPENGL_TEXTURE_2D,
                    texture_handle: 2,
                },
                super::DesktopGraphicsOpenGlBackendDrawCommand::BindVertexArray {
                    vertex_array_handle: 4,
                },
                super::DesktopGraphicsOpenGlBackendDrawCommand::DrawElements {
                    primitive_type:
                        super::DesktopGraphicsOpenGlBackendSpriteDrawCallPlan::TRIANGLES_PRIMITIVE,
                    index_count:
                        super::DesktopGraphicsOpenGlBackendResolveCommand::FULLSCREEN_QUAD_INDEX_COUNT,
                    index_type: super::DESKTOP_GRAPHICS_OPENGL_UNSIGNED_INT,
                    index_offset_bytes:
                        super::DesktopGraphicsOpenGlBackendResolveCommand::FULLSCREEN_QUAD_INDEX_OFFSET_BYTES,
                },
            ]
        );
        assert!(executor.resolve_sample_quads.is_empty());

        let mut sink = super::DesktopGraphicsRecordingOpenGlBackendDrawCommandSink::default();
        assert_eq!(executor.drive_resolve_draw_command_sink(&mut sink), 6);
        assert_eq!(sink.commands, executor.resolve_draw_commands);
    }

    #[test]
    fn desktop_graphics_opengl_shared_resolver_allocates_draw_rect_and_fbo_sample_quad_resources() {
        let mut executor = super::DesktopGraphicsResolvingOpenGlBackendCommandExecutor::default();
        executor.consume_opengl_framebuffer_attachment(
            super::DesktopGraphicsOpenGlBackendFramebufferAttachmentPlan::from_buffer_name(
                "buffer:draw-rect-source",
            ),
        );
        executor.consume_opengl_framebuffer_attachment(
            super::DesktopGraphicsOpenGlBackendFramebufferAttachmentPlan::from_buffer_name(
                "buffer:draw-fbo-source",
            ),
        );

        let rect_sample = RenderTextureSamplePlan::fbo_uv_window(
            RenderCamera::new(
                RenderPoint::new(32.0, 48.0),
                RenderViewport::new(0.0, 0.0, 64.0, 96.0),
            ),
            16,
            24,
            4.0,
            3.0,
            -2.0,
        )
        .unwrap();
        let fbo_sample = RenderTextureSamplePlan::fbo_uv_window(
            RenderCamera::new(
                RenderPoint::new(40.0, 24.0),
                RenderViewport::new(0.0, 0.0, 80.0, 48.0),
            ),
            20,
            12,
            4.0,
            -4.0,
            1.0,
        )
        .unwrap();

        executor.consume_opengl_resolve_event(super::DesktopGraphicsOpenGlBackendResolveEvent {
            source_target: RenderTarget::Buffer("draw-rect-source".into()),
            resolve_target: RenderTarget::Screen,
            resolve_kind: RenderResolveKind::DrawRectSample,
            resolve_sample: Some(rect_sample),
        });
        executor.consume_opengl_resolve_event(super::DesktopGraphicsOpenGlBackendResolveEvent {
            source_target: RenderTarget::Buffer("draw-fbo-source".into()),
            resolve_target: RenderTarget::Screen,
            resolve_kind: RenderResolveKind::DrawFboSample,
            resolve_sample: Some(fbo_sample),
        });

        assert_eq!(executor.resolve_commands.len(), 2);
        assert_eq!(executor.resolve_draw_commands.len(), 12);
        assert_eq!(
            executor.resolve_sample_quads,
            vec![
                super::DesktopGraphicsOpenGlBackendResolveQuad::from(rect_sample),
                super::DesktopGraphicsOpenGlBackendResolveQuad::from(fbo_sample),
            ]
        );
        let rect_program = executor.cache.programs
            [super::DesktopGraphicsResolvingOpenGlBackendCommandExecutor::DRAW_RECT_SAMPLE_PROGRAM_KEY];
        let fbo_program = executor.cache.programs
            [super::DesktopGraphicsResolvingOpenGlBackendCommandExecutor::DRAW_FBO_SAMPLE_PROGRAM_KEY];
        let rect_quad_vertex_array = executor.cache.vertex_arrays
            [&super::DesktopGraphicsResolvingOpenGlBackendCommandExecutor::resolve_sample_quad_vertex_array_key(
                0,
                &executor.resolve_commands[0],
            )];
        let fbo_quad_vertex_array = executor.cache.vertex_arrays
            [&super::DesktopGraphicsResolvingOpenGlBackendCommandExecutor::resolve_sample_quad_vertex_array_key(
                1,
                &executor.resolve_commands[1],
            )];
        assert_ne!(rect_program, fbo_program);
        assert_ne!(rect_quad_vertex_array, fbo_quad_vertex_array);
        assert_eq!(executor.resolved_resolve_mesh_uploads.len(), 2);
        assert_eq!(executor.resolve_mesh_upload_commands.len(), 18);

        let expected_rect_quad = super::DesktopGraphicsOpenGlBackendResolveQuad::from(rect_sample);
        let expected_fbo_quad = super::DesktopGraphicsOpenGlBackendResolveQuad::from(fbo_sample);
        let rect_upload = &executor.resolved_resolve_mesh_uploads[0];
        let fbo_upload = &executor.resolved_resolve_mesh_uploads[1];
        assert_eq!(rect_upload.resolve_index, 0);
        assert_eq!(rect_upload.resolve_kind, RenderResolveKind::DrawRectSample);
        assert_eq!(rect_upload.vertex_array_handle, rect_quad_vertex_array);
        assert_eq!(
            rect_upload.vertex_count,
            super::DesktopGraphicsOpenGlBackendResolveQuad::VERTEX_COUNT
        );
        assert_eq!(
            rect_upload.index_count,
            super::DesktopGraphicsOpenGlBackendResolveQuad::INDEX_COUNT
        );
        assert_eq!(
            rect_upload.vertex_stride_bytes,
            super::DesktopGraphicsOpenGlBackendResolveQuad::VERTEX_STRIDE_BYTES
        );
        assert_eq!(
            rect_upload.vertex_bytes,
            expected_rect_quad.to_vertex_bytes()
        );
        assert_eq!(rect_upload.index_bytes, expected_rect_quad.to_index_bytes());
        assert_eq!(
            rect_upload
                .vertex_attributes
                .iter()
                .map(|attribute| (attribute.name, attribute.components, attribute.offset_bytes))
                .collect::<Vec<_>>(),
            vec![
                (
                    "a_position",
                    2,
                    super::DesktopGraphicsOpenGlBackendResolveQuad::POSITION_OFFSET_BYTES
                ),
                (
                    "a_texCoord0",
                    2,
                    super::DesktopGraphicsOpenGlBackendResolveQuad::TEXCOORD_OFFSET_BYTES
                ),
            ]
        );
        assert_eq!(
            rect_upload
                .vertex_attributes
                .iter()
                .map(|attribute| attribute.attribute_location)
                .collect::<Vec<_>>(),
            vec![Some(0), Some(1)]
        );
        assert_eq!(fbo_upload.resolve_index, 1);
        assert_eq!(fbo_upload.resolve_kind, RenderResolveKind::DrawFboSample);
        assert_eq!(fbo_upload.vertex_array_handle, fbo_quad_vertex_array);
        assert_eq!(fbo_upload.vertex_bytes, expected_fbo_quad.to_vertex_bytes());
        assert_eq!(fbo_upload.index_bytes, expected_fbo_quad.to_index_bytes());

        assert_eq!(
            executor.resolve_mesh_upload_commands[0],
            super::DesktopGraphicsOpenGlBackendResolveMeshUploadCommand::BindVertexArray {
                vertex_array_handle: rect_quad_vertex_array,
            }
        );
        assert_eq!(
            executor.resolve_mesh_upload_commands[2],
            super::DesktopGraphicsOpenGlBackendResolveMeshUploadCommand::BufferData {
                target: super::DESKTOP_GRAPHICS_OPENGL_ARRAY_BUFFER,
                usage: super::DESKTOP_GRAPHICS_OPENGL_DYNAMIC_DRAW,
                bytes: rect_upload.vertex_bytes.clone(),
            }
        );
        assert_eq!(
            executor.resolve_mesh_upload_commands[4],
            super::DesktopGraphicsOpenGlBackendResolveMeshUploadCommand::BufferData {
                target: super::DESKTOP_GRAPHICS_OPENGL_ELEMENT_ARRAY_BUFFER,
                usage: super::DESKTOP_GRAPHICS_OPENGL_DYNAMIC_DRAW,
                bytes: rect_upload.index_bytes.clone(),
            }
        );
        assert_eq!(
            executor.resolve_mesh_upload_commands[9],
            super::DesktopGraphicsOpenGlBackendResolveMeshUploadCommand::BindVertexArray {
                vertex_array_handle: fbo_quad_vertex_array,
            }
        );

        let rect_texture = executor.resolve_commands[0]
            .source_attachment
            .as_ref()
            .expect("draw-rect resolve should retain source attachment")
            .color_texture_handle;
        assert_eq!(
            executor.resolve_commands[0].resolve_sample,
            Some(rect_sample)
        );
        assert_eq!(
            executor.resolve_commands[0].resolve_sample_trace,
            Some(super::DesktopGraphicsOpenGlBackendResolveSampleTrace::from(
                rect_sample
            ))
        );
        assert_eq!(
            executor.resolve_commands[0].resolve_sample_quad,
            Some(super::DesktopGraphicsOpenGlBackendResolveQuad::from(
                rect_sample
            ))
        );
        let fbo_texture = executor.resolve_commands[1]
            .source_attachment
            .as_ref()
            .expect("draw-fbo resolve should retain source attachment")
            .color_texture_handle;
        assert_eq!(
            executor.resolve_commands[1].resolve_sample,
            Some(fbo_sample)
        );
        assert_eq!(
            executor.resolve_commands[1].resolve_sample_trace,
            Some(super::DesktopGraphicsOpenGlBackendResolveSampleTrace::from(
                fbo_sample
            ))
        );
        assert_eq!(
            executor.resolve_commands[1].resolve_sample_quad,
            Some(super::DesktopGraphicsOpenGlBackendResolveQuad::from(
                fbo_sample
            ))
        );

        let rect_commands = &executor.resolve_draw_commands[0..6];
        let fbo_commands = &executor.resolve_draw_commands[6..12];
        assert_eq!(
            rect_commands[0],
            super::DesktopGraphicsOpenGlBackendDrawCommand::BindFramebuffer {
                target: Some(RenderTarget::Screen),
            }
        );
        assert_eq!(
            rect_commands[1],
            super::DesktopGraphicsOpenGlBackendDrawCommand::UseProgram {
                program_handle: rect_program
            }
        );
        assert_eq!(
            rect_commands[3],
            super::DesktopGraphicsOpenGlBackendDrawCommand::BindTexture {
                target: super::DESKTOP_GRAPHICS_OPENGL_TEXTURE_2D,
                texture_handle: rect_texture,
            }
        );
        assert_eq!(
            rect_commands[4],
            super::DesktopGraphicsOpenGlBackendDrawCommand::BindVertexArray {
                vertex_array_handle: rect_quad_vertex_array,
            }
        );
        let rect_quad = executor.resolve_sample_quads[0];
        assert_eq!(
            rect_quad.vertices[0].position,
            [rect_sample.geometry.x, rect_sample.geometry.y]
        );
        assert_eq!(
            rect_quad.vertices[0].uv,
            [rect_sample.uv.u, rect_sample.uv.v]
        );
        assert_eq!(
            rect_quad.vertices[2].position,
            [rect_sample.geometry.right(), rect_sample.geometry.bottom()]
        );
        assert_eq!(
            rect_quad.vertices[2].uv,
            [rect_sample.uv.u2, rect_sample.uv.v2]
        );
        assert_eq!(
            fbo_commands[0],
            super::DesktopGraphicsOpenGlBackendDrawCommand::BindFramebuffer {
                target: Some(RenderTarget::Screen),
            }
        );
        assert_eq!(
            fbo_commands[1],
            super::DesktopGraphicsOpenGlBackendDrawCommand::UseProgram {
                program_handle: fbo_program
            }
        );
        assert_eq!(
            fbo_commands[3],
            super::DesktopGraphicsOpenGlBackendDrawCommand::BindTexture {
                target: super::DESKTOP_GRAPHICS_OPENGL_TEXTURE_2D,
                texture_handle: fbo_texture,
            }
        );
        assert_eq!(
            fbo_commands[4],
            super::DesktopGraphicsOpenGlBackendDrawCommand::BindVertexArray {
                vertex_array_handle: fbo_quad_vertex_array,
            }
        );
        let fbo_quad = executor.resolve_sample_quads[1];
        assert_eq!(
            fbo_quad.vertices[0].position,
            [fbo_sample.geometry.x, fbo_sample.geometry.y]
        );
        assert_eq!(fbo_quad.vertices[0].uv, [fbo_sample.uv.u, fbo_sample.uv.v]);
        assert_eq!(
            fbo_quad.vertices[2].position,
            [fbo_sample.geometry.right(), fbo_sample.geometry.bottom()]
        );
        assert_eq!(
            fbo_quad.vertices[2].uv,
            [fbo_sample.uv.u2, fbo_sample.uv.v2]
        );
        assert_eq!(
            fbo_commands[5],
            super::DesktopGraphicsOpenGlBackendDrawCommand::DrawElements {
                primitive_type:
                    super::DesktopGraphicsOpenGlBackendSpriteDrawCallPlan::TRIANGLES_PRIMITIVE,
                index_count:
                    super::DesktopGraphicsOpenGlBackendResolveCommand::FULLSCREEN_QUAD_INDEX_COUNT,
                index_type: super::DESKTOP_GRAPHICS_OPENGL_UNSIGNED_INT,
                index_offset_bytes:
                    super::DesktopGraphicsOpenGlBackendResolveCommand::FULLSCREEN_QUAD_INDEX_OFFSET_BYTES,
            }
        );

        let mut sink = super::DesktopGraphicsRecordingOpenGlBackendDrawCommandSink::default();
        assert_eq!(executor.drive_resolve_draw_command_sink(&mut sink), 12);
        assert_eq!(sink.commands, executor.resolve_draw_commands);
    }

    #[test]
    fn desktop_graphics_opengl_resolve_mesh_uploads_skip_shader_blit_and_missing_samples() {
        let mut executor = super::DesktopGraphicsResolvingOpenGlBackendCommandExecutor::default();
        for buffer_name in [
            "buffer:shader-blit-source",
            "buffer:draw-rect-missing-sample",
            "buffer:draw-fbo-missing-sample",
        ] {
            executor.consume_opengl_framebuffer_attachment(
                super::DesktopGraphicsOpenGlBackendFramebufferAttachmentPlan::from_buffer_name(
                    buffer_name,
                ),
            );
        }
        let shader_blit_sample = RenderTextureSamplePlan::fbo_uv_window(
            RenderCamera::new(
                RenderPoint::new(16.0, 16.0),
                RenderViewport::new(0.0, 0.0, 32.0, 32.0),
            ),
            8,
            8,
            2.0,
            2.0,
            0.0,
        )
        .unwrap();

        executor.consume_opengl_resolve_event(super::DesktopGraphicsOpenGlBackendResolveEvent {
            source_target: RenderTarget::Buffer("shader-blit-source".into()),
            resolve_target: RenderTarget::Screen,
            resolve_kind: RenderResolveKind::ShaderBlit,
            resolve_sample: Some(shader_blit_sample),
        });
        executor.consume_opengl_resolve_event(super::DesktopGraphicsOpenGlBackendResolveEvent {
            source_target: RenderTarget::Buffer("draw-rect-missing-sample".into()),
            resolve_target: RenderTarget::Screen,
            resolve_kind: RenderResolveKind::DrawRectSample,
            resolve_sample: None,
        });
        executor.consume_opengl_resolve_event(super::DesktopGraphicsOpenGlBackendResolveEvent {
            source_target: RenderTarget::Buffer("draw-fbo-missing-sample".into()),
            resolve_target: RenderTarget::Screen,
            resolve_kind: RenderResolveKind::DrawFboSample,
            resolve_sample: None,
        });

        assert!(executor.resolved_resolve_mesh_uploads.is_empty());
        assert!(executor.resolve_mesh_upload_commands.is_empty());
        assert!(executor.resolve_sample_quads.is_empty());
        assert_eq!(executor.resolve_draw_commands.len(), 18);
        assert_eq!(
            executor.cache.vertex_arrays.len(),
            1,
            "ShaderBlit and missing-sample sample resolves should all reuse fullscreen VAO"
        );
        assert!(executor.cache.vertex_arrays.contains_key(
            super::DesktopGraphicsResolvingOpenGlBackendCommandExecutor::FULLSCREEN_QUAD_VERTEX_ARRAY_KEY
        ));

        let mut upload_sink =
            super::DesktopGraphicsRecordingOpenGlBackendResolveMeshUploadCommandSink::default();
        assert_eq!(
            executor.drive_resolve_mesh_upload_command_sink(&mut upload_sink),
            0
        );
        assert!(upload_sink.commands.is_empty());
    }

    #[cfg(feature = "opengl-backend")]
    #[test]
    fn desktop_graphics_opengl_backend_runtime_feature_records_driver_submission() {
        let mut executor = super::DesktopGraphicsResolvingOpenGlBackendCommandExecutor::default();
        executor.consume_opengl_framebuffer_attachment(
            super::DesktopGraphicsOpenGlBackendFramebufferAttachmentPlan::from_buffer_name(
                "buffer:runtime-feature",
            ),
        );
        executor.consume_opengl_resolve_event(super::DesktopGraphicsOpenGlBackendResolveEvent {
            source_target: RenderTarget::Buffer("runtime-feature".into()),
            resolve_target: RenderTarget::Screen,
            resolve_kind: RenderResolveKind::ShaderBlit,
            resolve_sample: None,
        });

        let mut runtime = super::DesktopGraphicsNullOpenGlBackendRuntime::default();
        super::DesktopGraphicsOpenGlBackendRuntime::resize_surface(
            &mut runtime,
            DesktopSurfaceSize::new(1280, 720),
        );
        let driver_state = super::DesktopGraphicsOpenGlBackendRuntime::submit_resolving_executor(
            &mut runtime,
            &executor,
        );
        super::DesktopGraphicsOpenGlBackendRuntime::present_frame(&mut runtime);

        assert_eq!(driver_state.framebuffer_attachment_plans, 1);
        assert_eq!(driver_state.resolve_draw_commands, 6);
        assert_eq!(driver_state.resolve_commands, 1);
        assert_eq!(
            runtime.state.surface_size,
            Some(DesktopSurfaceSize::new(1280, 720))
        );
        assert_eq!(runtime.state.resize_events, 1);
        assert_eq!(runtime.state.frames_submitted, 1);
        assert_eq!(runtime.state.present_events, 1);
        assert_eq!(runtime.state.last_driver_state, Some(driver_state));
        assert!(matches!(
            runtime.driver.commands.as_slice(),
            [
                super::DesktopGraphicsOpenGlBackendDriverCommand::FramebufferAttachment(_),
                super::DesktopGraphicsOpenGlBackendDriverCommand::Draw(
                    super::DesktopGraphicsOpenGlBackendDrawCommand::BindFramebuffer { .. }
                ),
                super::DesktopGraphicsOpenGlBackendDriverCommand::Draw(
                    super::DesktopGraphicsOpenGlBackendDrawCommand::UseProgram { .. }
                ),
                super::DesktopGraphicsOpenGlBackendDriverCommand::Draw(
                    super::DesktopGraphicsOpenGlBackendDrawCommand::ActiveTexture { .. }
                ),
                super::DesktopGraphicsOpenGlBackendDriverCommand::Draw(
                    super::DesktopGraphicsOpenGlBackendDrawCommand::BindTexture { .. }
                ),
                super::DesktopGraphicsOpenGlBackendDriverCommand::Draw(
                    super::DesktopGraphicsOpenGlBackendDrawCommand::BindVertexArray { .. }
                ),
                super::DesktopGraphicsOpenGlBackendDriverCommand::Draw(
                    super::DesktopGraphicsOpenGlBackendDrawCommand::DrawElements { .. }
                ),
                super::DesktopGraphicsOpenGlBackendDriverCommand::Resolve(_)
            ]
        ));
    }

