    #[test]
    fn desktop_launcher_settings_scroll_wheel_offsets_table_hit_tests() {
        let mut launcher = DesktopLauncher::new(Vec::new());
        launcher.dispatch_menu_action(MenuButtonRole::Settings);
        launcher.settings_dialog_state.page = super::DesktopSettingsPage::Game;

        let surface = DesktopSurfaceSize::new(1280, 720);
        let viewport = launcher.default_render_viewport_for_surface(surface);
        let panel = DesktopLauncher::active_menu_route_shell_panel_for_route(
            viewport,
            super::DesktopMenuRoute::Settings,
        );
        let clip = DesktopLauncher::settings_pref_widget_clip_rect_for_panel(panel);
        let clip_center = clip.center();

        launcher.apply_menu_input_events(
            surface,
            &[DesktopInputTickEvent::CursorMoved {
                x: clip_center.x,
                y: clip_center.y,
            }],
        );
        launcher.apply_menu_input_events(
            surface,
            &[DesktopInputTickEvent::Scroll {
                delta_x: 0.0,
                delta_y: -20.0,
            }],
        );
        let offset = launcher
            .settings_scroll_offsets
            .get("game")
            .copied()
            .expect("scroll wheel over settings table should store a game page offset");
        assert!(offset > 0);

        let specs = DesktopLauncher::settings_pref_widget_specs("game");
        let playerlimit_index = specs
            .iter()
            .position(|spec| spec.key == "playerlimit")
            .expect("game settings should include steam playerlimit");
        let playerlimit_row = DesktopLauncher::settings_pref_widget_row_rect_for_clip_with_scroll(
            clip,
            playerlimit_index,
            offset as f32,
        );
        assert!(
            clip.contains_point(playerlimit_row.center()),
            "scroll offset should bring later settings rows into the clipped table"
        );
        let playerlimit_track =
            DesktopLauncher::settings_pref_widget_slider_track_rect(playerlimit_row);
        let playerlimit_min_point =
            RenderPoint::new(playerlimit_track.x, playerlimit_track.center().y);
        assert_eq!(
            launcher.active_menu_route_shell_action_at_surface_point(
                surface,
                playerlimit_min_point.x,
                playerlimit_min_point.y
            ),
            Some(super::DesktopMenuRouteShellAction::Settings(
                super::DesktopSettingsAction::SetSliderValue("game", "playerlimit", 2)
            ))
        );
    }

    #[test]
    fn desktop_launcher_settings_scrollbar_knob_drag_updates_scroll_offset() {
        let mut launcher = DesktopLauncher::new(Vec::new());
        launcher.dispatch_menu_action(MenuButtonRole::Settings);
        launcher.settings_dialog_state.page = super::DesktopSettingsPage::Game;

        let surface = DesktopSurfaceSize::new(1280, 720);
        let viewport = launcher.default_render_viewport_for_surface(surface);
        let panel = DesktopLauncher::active_menu_route_shell_panel_for_route(
            viewport,
            super::DesktopMenuRoute::Settings,
        );
        let clip = DesktopLauncher::settings_pref_widget_clip_rect_for_panel(panel);
        let specs = DesktopLauncher::settings_pref_widget_specs("game");
        let max = DesktopLauncher::settings_max_scroll_offset_for_clip(clip, specs.len());
        assert!(max > 0);
        let knob = DesktopLauncher::settings_scrollbar_knob_rect_for_clip(clip, specs.len(), 0.0)
            .expect("settings page should expose a scroll knob when rows overflow");
        let knob_center = knob.center();

        launcher.apply_menu_input_events(
            surface,
            &[
                DesktopInputTickEvent::CursorMoved {
                    x: knob_center.x,
                    y: knob_center.y,
                },
                DesktopInputTickEvent::MouseButton {
                    button: "primary".into(),
                    pressed: true,
                },
            ],
        );
        let drag_state = launcher
            .settings_scroll_drag_state
            .expect("pressing the scroll knob should enter drag state");
        assert_eq!(drag_state.table, "game");
        assert!((drag_state.grab_offset_y - knob.height * 0.5).abs() < 0.01);

        launcher.apply_menu_input_events(
            surface,
            &[DesktopInputTickEvent::CursorMoved {
                x: knob_center.x,
                y: clip.y + knob.height * 0.5,
            }],
        );
        assert_eq!(
            launcher.settings_scroll_offsets.get("game").copied(),
            Some(max)
        );

        launcher.apply_menu_input_events(
            surface,
            &[DesktopInputTickEvent::MouseButton {
                button: "primary".into(),
                pressed: false,
            }],
        );
        assert_eq!(launcher.settings_scroll_drag_state, None);
    }

    #[test]
    fn desktop_launcher_settings_pref_specs_cover_group_keys_and_expected_metadata() {
        let mut seen = std::collections::BTreeSet::new();
        for spec in super::SETTINGS_PREF_SPECS {
            assert!(
                seen.insert((spec.table, spec.key)),
                "duplicate settings spec for {}/{}",
                spec.table,
                spec.key
            );
        }

        let expected_count = super::SETTINGS_PREF_GROUPS
            .iter()
            .map(|group| group.entries.len())
            .sum::<usize>();
        assert_eq!(expected_count, 62);
        assert_eq!(super::SETTINGS_PREF_SPECS.len(), expected_count);

        for group in super::SETTINGS_PREF_GROUPS {
            assert_eq!(
                super::settings_pref_count(group.table),
                group.entries.len(),
                "table {} should expose all keys in route metadata",
                group.table
            );
            for key in group.entries {
                let spec = super::settings_pref_spec(group.table, key)
                    .unwrap_or_else(|| panic!("missing settings spec for {}/{}", group.table, key));
                assert_eq!(spec.table, group.table);
                assert_eq!(spec.key, *key);
            }
        }

        let saveinterval = super::settings_pref_spec("game", "saveinterval").unwrap();
        assert_eq!(saveinterval.kind, super::DesktopSettingsPrefKind::Slider);
        assert_eq!(
            saveinterval.default_value,
            super::DesktopSettingsPrefDefaultValue::Int(60)
        );
        assert_eq!(
            saveinterval.range_step,
            Some(super::DesktopSettingsPrefRange::new(10, 600, 10))
        );
        assert_eq!(saveinterval.condition, None);

        let fullscreen = super::settings_pref_spec("graphics", "fullscreen").unwrap();
        assert_eq!(fullscreen.kind, super::DesktopSettingsPrefKind::Check);
        assert_eq!(
            fullscreen.default_value,
            super::DesktopSettingsPrefDefaultValue::Bool(false)
        );
        assert_eq!(fullscreen.range_step, None);
        assert_eq!(fullscreen.condition, Some("!mobile"));

        let max_magnification =
            super::settings_pref_spec("graphics", "maxmagnificationmultiplierpercent").unwrap();
        assert_eq!(
            max_magnification.kind,
            super::DesktopSettingsPrefKind::Slider
        );
        assert_eq!(
            max_magnification.default_value,
            super::DesktopSettingsPrefDefaultValue::Int(100)
        );
        assert_eq!(
            max_magnification.range_step,
            Some(super::DesktopSettingsPrefRange::new(100, 200, 25))
        );

        let minimap = super::settings_pref_spec("graphics", "minimap").unwrap();
        assert_eq!(minimap.kind, super::DesktopSettingsPrefKind::Check);
        assert_eq!(
            minimap.default_value,
            super::DesktopSettingsPrefDefaultValue::Expr("!mobile")
        );
        assert_eq!(minimap.condition, None);

        let linear = super::settings_pref_spec("graphics", "linear").unwrap();
        assert_eq!(linear.kind, super::DesktopSettingsPrefKind::Check);
        assert_eq!(
            linear.default_value,
            super::DesktopSettingsPrefDefaultValue::Expr("!mobile")
        );
        assert_eq!(linear.condition, None);

        let macnotch = super::settings_pref_spec("graphics", "macnotch").unwrap();
        assert_eq!(macnotch.kind, super::DesktopSettingsPrefKind::Check);
        assert_eq!(
            macnotch.default_value,
            super::DesktopSettingsPrefDefaultValue::Bool(false)
        );
        assert_eq!(macnotch.condition, Some("OS.isMac"));

        let musicvol = super::settings_pref_spec("sound", "musicvol").unwrap();
        assert_eq!(musicvol.kind, super::DesktopSettingsPrefKind::Slider);
        assert_eq!(
            musicvol.default_value,
            super::DesktopSettingsPrefDefaultValue::Int(100)
        );
        assert_eq!(
            musicvol.range_step,
            Some(super::DesktopSettingsPrefRange::new(0, 100, 1))
        );
        assert_eq!(musicvol.condition, None);
    }

    #[test]
    fn desktop_launcher_settings_reset_current_page_removes_only_that_table_overrides() {
        let mut launcher = DesktopLauncher::new(Vec::new());
        launcher.dispatch_menu_action(MenuButtonRole::Settings);
        launcher.settings_dialog_state.page = super::DesktopSettingsPage::Game;

        launcher.set_setting_override("game", "saveinterval", "120");
        launcher.set_setting_override("game", "communityservers", "false");
        launcher.set_setting_override("graphics", "fullscreen", "true");
        launcher.set_setting_override("sound", "musicvol", "15");

        assert_eq!(
            launcher
                .setting_effective_value("game", "saveinterval")
                .as_deref(),
            Some("120")
        );
        assert_eq!(
            launcher
                .setting_effective_value("graphics", "fullscreen")
                .as_deref(),
            Some("true")
        );
        assert_eq!(
            launcher
                .setting_effective_value("sound", "musicvol")
                .as_deref(),
            Some("15")
        );

        launcher.dispatch_settings_action(super::DesktopSettingsAction::ResetCurrentPage);

        assert_eq!(
            launcher.last_settings_action,
            Some(super::DesktopSettingsAction::ResetCurrentPage)
        );
        assert_eq!(
            launcher.settings_dialog_state.page,
            super::DesktopSettingsPage::Game
        );
        assert_eq!(
            launcher.setting_override_value("game", "saveinterval"),
            None
        );
        assert_eq!(
            launcher
                .setting_effective_value("game", "saveinterval")
                .as_deref(),
            Some("60")
        );
        assert_eq!(
            launcher.setting_override_value("game", "communityservers"),
            None
        );
        assert_eq!(
            launcher
                .setting_effective_value("game", "communityservers")
                .as_deref(),
            Some("true")
        );
        assert_eq!(
            launcher
                .setting_effective_value("graphics", "fullscreen")
                .as_deref(),
            Some("true")
        );
        assert_eq!(
            launcher
                .setting_effective_value("sound", "musicvol")
                .as_deref(),
            Some("15")
        );
    }

    #[test]
    fn desktop_launcher_menu_back_key_closes_route_shell_then_submenu() {
        let mut launcher = DesktopLauncher::new(Vec::new());
        let surface = DesktopSurfaceSize::new(800, 600);
        let viewport = launcher.default_render_viewport_for_surface(surface);
        let input = DesktopLauncher::default_menu_frame_input_for_viewport(viewport);
        let play_center = launcher
            .menu_renderer_state
            .ui_plan(input)
            .buttons
            .iter()
            .find(|button| button.role == MenuButtonRole::Play)
            .expect("menu ui should include PLAY root")
            .rect
            .center();

        launcher.apply_menu_input_events(
            surface,
            &[
                DesktopInputTickEvent::CursorMoved {
                    x: play_center.x,
                    y: play_center.y,
                },
                DesktopInputTickEvent::MouseButton {
                    button: "primary".into(),
                    pressed: true,
                },
            ],
        );

        let campaign_center = launcher
            .menu_renderer_state
            .ui_plan(input)
            .buttons
            .iter()
            .find(|button| button.role == MenuButtonRole::Campaign)
            .expect("play submenu should include CAMPAIGN")
            .rect
            .center();

        launcher.apply_menu_input_events(
            surface,
            &[
                DesktopInputTickEvent::CursorMoved {
                    x: campaign_center.x,
                    y: campaign_center.y,
                },
                DesktopInputTickEvent::MouseButton {
                    button: "primary".into(),
                    pressed: true,
                },
            ],
        );
        assert_eq!(
            launcher.active_menu_route,
            Some(super::DesktopMenuRoute::Campaign)
        );

        launcher.apply_menu_input_events(
            surface,
            &[DesktopInputTickEvent::Key {
                key_code: "Escape".into(),
                pressed: true,
            }],
        );
        assert_eq!(launcher.active_menu_route, None);
        assert_eq!(launcher.campaign_planet_dialog, None);

        let database_center = launcher
            .menu_renderer_state
            .ui_plan(input)
            .buttons
            .iter()
            .find(|button| button.role == MenuButtonRole::Database)
            .expect("menu ui should include DATABASE root")
            .rect
            .center();
        launcher.apply_menu_input_events(
            surface,
            &[
                DesktopInputTickEvent::CursorMoved {
                    x: database_center.x,
                    y: database_center.y,
                },
                DesktopInputTickEvent::MouseButton {
                    button: "left".into(),
                    pressed: true,
                },
            ],
        );
        assert_eq!(
            launcher.menu_renderer_state.selected_root,
            MenuButtonRole::Database
        );

        launcher.apply_menu_input_events(
            surface,
            &[DesktopInputTickEvent::Key {
                key_code: "Back".into(),
                pressed: true,
            }],
        );
        assert_eq!(
            launcher.menu_renderer_state.selected_root,
            MenuButtonRole::Play
        );
    }

