        assert_eq!(fire.lifetime, 120.0);
        assert_eq!(fire.time, 31.0);
        assert_eq!(fire.x, 16.0);
        assert_eq!(fire.y, 24.0);
        assert_eq!(fire.tile.unwrap().x, 2);
        assert_eq!(fire.tile.unwrap().y, 3);
